function mythicNaturalFeatureAffinity(domain: BeliefDomain, kind: NaturalFeatureKind): number {
    if (domain === "mountains") return kind === "mountain" ? 1 : kind === "cave" ? 0.78 : kind === "spring" ? 0.28 : 0;
    if (domain === "rivers") return kind === "river" ? 1 : kind === "spring" ? 0.84 : kind === "coast" ? 0.46 : 0;
    if (domain === "harvest") return kind === "forest" ? 0.9 : kind === "spring" ? 0.72 : kind === "river" ? 0.42 : 0;
    if (domain === "stars") return kind === "mountain" ? 0.78 : kind === "coast" ? 0.34 : kind === "cave" ? 0.24 : 0;
    if (domain === "storms") return kind === "coast" ? 0.86 : kind === "mountain" ? 0.66 : kind === "river" ? 0.28 : 0;
    if (domain === "forge") return kind === "cave" ? 0.88 : kind === "mountain" ? 0.7 : kind === "river" ? 0.2 : 0;
    if (domain === "trade") return kind === "coast" ? 0.78 : kind === "river" ? 0.72 : kind === "spring" ? 0.24 : 0;
    return kind === "cave" ? 0.72 : kind === "mountain" ? 0.48 : kind === "forest" ? 0.34 : 0;
}

function mythicNaturalFeatureRefs(
    simulation: CivilizationSimulation,
    belief: Belief,
    settlement: Settlement,
    limit = 2,
    maxDistance = 220,
): LegendEntityRef[] {
    return simulation.naturalFeatures
        .map(feature => ({
            feature,
            distance: naturalFeatureDistance(feature, settlement),
            affinity: mythicNaturalFeatureAffinity(belief.domain, feature.kind),
        }))
        .filter(entry => entry.distance <= maxDistance && entry.affinity > 0)
        .sort((a, b) =>
            b.affinity - a.affinity
            || a.distance - b.distance
            || b.feature.prominence - a.feature.prominence
            || a.feature.id - b.feature.id
        )
        .slice(0, limit)
        .map(entry => naturalFeatureRef(simulation, entry.feature.id));
}

