function belongingKindLabel(kind: BelongingKind): string {
    return kind;
}

function belongingKindForAgent(agent: Agent, source?: LegendEvent): BelongingKind {
    if (agent.age < 10) return "toy";
    if (source?.type === "household-founded") return "key";
    if (source?.type === "person-died" || source?.type === "memorial-created") return "keepsake";
    if (source?.type === "journey-made") return agent.profession === "merchant" ? "ledger" : "garment";
    if (agent.profession === "farmer" || agent.profession === "miner" || agent.profession === "artisan") return "tool";
    if (agent.profession === "guard") return "weapon";
    if (agent.profession === "scholar" || agent.profession === "elder") return "book";
    if (agent.profession === "merchant") return "ledger";
    if (agent.profession === "healer") return "charm";
    return "keepsake";
}

function makeBelongingName(seed: number, index: number, kind: BelongingKind, owner: Agent, material: string): string {
    const noun = BELONGING_NOUNS[kind][Math.floor(hashFloat(seed, index, 2441, 1) * BELONGING_NOUNS[kind].length)];
    const style = Math.floor(hashFloat(seed, index, 2441, 2) * 3);
    if (style === 0) return `${owner.name}'s ${material} ${noun}`;
    const prefix = NAME_PREFIXES[Math.floor(hashFloat(seed, index, 2441, 3) * NAME_PREFIXES.length)];
    const suffix = NAME_SUFFIXES[Math.floor(hashFloat(seed, index, 2441, 4) * NAME_SUFFIXES.length)];
    return style === 1 ? `${prefix}${suffix} ${noun}` : `${material} ${noun} of ${owner.name}`;
}

function emptyProfessionCounts(): ProfessionCounts {
    return {
        child: 0,
        farmer: 0,
        miner: 0,
        artisan: 0,
        merchant: 0,
        guard: 0,
        healer: 0,
        scholar: 0,
        elder: 0,
    };
}

function addAgeMilestoneIdToAgent(agent: Agent | undefined, id: number) {
    if (agent && !agent.ageMilestoneIds.includes(id)) agent.ageMilestoneIds.push(id);
}

function ageMilestoneKindForTransition(previousProfession: AgentProfession, newProfession: AgentProfession): AgeMilestoneKind | undefined {
    if (previousProfession === "child" && newProfession !== "child") return "came-of-age";
    if (newProfession === "elder" && previousProfession !== "elder") return "became-elder";
    return undefined;
}

function makeAgeMilestoneName(agent: Agent, kind: AgeMilestoneKind): string {
    if (kind === "came-of-age") return `${agent.name}'s coming of age`;
    return `${agent.name}'s elderhood`;
}

function createAgeMilestoneRecord(
    simulation: CivilizationSimulation,
    agent: Agent,
    previousProfession: AgentProfession,
    career: CareerRecord | undefined,
    sourceEventId: number,
): AgeMilestone | undefined {
    const kind = ageMilestoneKindForTransition(previousProfession, agent.profession);
    if (!kind) return undefined;
    const sourceEvent = simulation.legendEvents[sourceEventId];
    const settlement = simulation.settlements[agent.settlementId];
    const id = simulation.ageMilestones.length;
    const household = agent.householdId === undefined ? undefined : simulation.households[agent.householdId];
    const structure = career?.structureId === undefined ? undefined : simulation.structures[career.structureId];
    const milestone: AgeMilestone = {
        id,
        name: makeAgeMilestoneName(agent, kind),
        kind,
        year: sourceEvent?.year ?? simulation.year,
        age: agent.age,
        personId: agent.id,
        civilizationId: agent.civilizationId,
        settlementId: agent.settlementId,
        householdId: agent.householdId,
        lineageId: agent.lineageId,
        structureId: structure?.id,
        careerId: career?.id,
        previousProfession,
        newProfession: agent.profession,
        sourceEventId,
        subjectRefs: [],
        description: kind === "came-of-age"
            ? `${agent.name} came of age in ${settlement?.name ?? "an unknown settlement"} and entered work as ${agent.profession}.`
            : `${agent.name} entered elderhood in ${settlement?.name ?? "an unknown settlement"} after a life recorded as ${previousProfession}.`,
        eventIds: [sourceEventId],
    };
    simulation.ageMilestones.push(milestone);
    addAgeMilestoneIdToAgent(agent, id);
    milestone.subjectRefs = uniqueLegendRefs([
        ageMilestoneRef(simulation, id),
        personRef(simulation, agent.id),
        eventRef(simulation, sourceEventId),
        ...(career ? [careerRef(simulation, career.id)] : []),
        ...(household ? [householdRef(simulation, household.id)] : []),
        ...(agent.lineageId === undefined ? [] : [lineageRef(simulation, agent.lineageId)]),
        ...(structure ? [structureRef(simulation, structure.id)] : []),
        settlementRef(simulation, agent.settlementId),
        civilizationRef(simulation, agent.civilizationId),
    ], 24);
    if (sourceEvent) {
        sourceEvent.ageMilestoneId = id;
        if (!sourceEvent.entityRefs.some(ref => ref.kind === "age-milestone" && ref.id === id)) {
            sourceEvent.entityRefs.unshift(internLegendRef(simulation, ageMilestoneRef(simulation, id)));
        }
    }
    if (kind === "became-elder") createAppearanceFeatureForAgeMilestone(simulation, milestone, agent);
    return milestone;
}

const APPEARANCE_STATURES = ["short", "compact", "average-height", "tall", "towering"] as const;
const APPEARANCE_BUILDS = ["slender", "lean", "sturdy", "broad-shouldered", "heavyset"] as const;
const APPEARANCE_HAIR = ["black hair", "brown hair", "auburn hair", "fair hair", "silver-streaked hair", "closely shorn hair"] as const;
const APPEARANCE_EYES = ["dark eyes", "amber eyes", "green eyes", "gray eyes", "blue eyes"] as const;

function appearanceTraitPhrase(value: string): string {
    return value.replace(/-/g, " ");
}

function baselineAppearanceTraits(simulation: CivilizationSimulation, agent: Agent): string[] {
    const seed = simulation.options.seed;
    const stature = APPEARANCE_STATURES[Math.floor(hashFloat(seed, agent.id, 1701, 1) * APPEARANCE_STATURES.length)];
    const build = APPEARANCE_BUILDS[Math.floor(hashFloat(seed, agent.id, 1701, 2) * APPEARANCE_BUILDS.length)];
    const hair = APPEARANCE_HAIR[Math.floor(hashFloat(seed, agent.id, 1701, 3) * APPEARANCE_HAIR.length)];
    const eyes = APPEARANCE_EYES[Math.floor(hashFloat(seed, agent.id, 1701, 4) * APPEARANCE_EYES.length)];
    const bearing = agent.traits.includes("brave") ? "bold bearing"
        : agent.traits.includes("patient") ? "calm bearing"
        : agent.traits.includes("restless") ? "restless bearing"
        : agent.traits.includes("melancholy") ? "somber bearing"
        : agent.traits.includes("curious") ? "alert bearing"
        : "steady bearing";
    return [stature, build, hair, eyes, bearing];
}

function makeAppearanceFeatureName(agent: Agent, kind: AppearanceFeatureKind): string {
    if (kind === "birth-description") return `${agent.name}'s appearance`;
    if (kind === "elder-mark") return `${agent.name}'s elder marks`;
    return `${agent.name}'s visible mark`;
}

function addAppearanceFeatureIdToAgent(agent: Agent | undefined, id: number) {
    if (agent && !agent.appearanceFeatureIds.includes(id)) agent.appearanceFeatureIds.push(id);
}

function appearanceFeatureSubjectRefs(simulation: CivilizationSimulation, feature: AppearanceFeature): LegendEntityRef[] {
    return uniqueLegendRefs([
        appearanceFeatureRef(simulation, feature.id),
        personRef(simulation, feature.personId),
        eventRef(simulation, feature.sourceEventId),
        ...(feature.birthId === undefined ? [] : [birthRef(simulation, feature.birthId)]),
        ...(feature.ageMilestoneId === undefined ? [] : [ageMilestoneRef(simulation, feature.ageMilestoneId)]),
        ...(feature.woundLegacyId === undefined ? [] : [woundLegacyRef(simulation, feature.woundLegacyId)]),
        ...(feature.householdId === undefined ? [] : [householdRef(simulation, feature.householdId)]),
        ...(feature.lineageId === undefined ? [] : [lineageRef(simulation, feature.lineageId)]),
        settlementRef(simulation, feature.settlementId),
        civilizationRef(simulation, feature.civilizationId),
    ], 18);
}

function appendAppearanceFeatureRefToEvent(simulation: CivilizationSimulation, feature: AppearanceFeature, eventId: number) {
    const event = simulation.legendEvents[eventId];
    if (!event) return;
    event.appearanceFeatureId = feature.id;
    const ref = appearanceFeatureRef(simulation, feature.id);
    if (!event.entityRefs.some(existing => sameLegendRef(existing, ref))) {
        event.entityRefs.unshift(internLegendRef(simulation, ref));
    }
    if (!feature.eventIds.includes(eventId)) feature.eventIds.push(eventId);
}

function createAppearanceFeature(
    simulation: CivilizationSimulation,
    agent: Agent,
    kind: AppearanceFeatureKind,
    sourceEventId: number,
    traits: string[],
    visibility: number,
    description: string,
    links: {birthId?: number; ageMilestoneId?: number; woundLegacyId?: number} = {},
): AppearanceFeature {
    const id = simulation.appearanceFeatures.length;
    const feature: AppearanceFeature = {
        id,
        name: makeAppearanceFeatureName(agent, kind),
        kind,
        year: simulation.legendEvents[sourceEventId]?.year ?? simulation.year,
        personId: agent.id,
        civilizationId: agent.civilizationId,
        settlementId: agent.settlementId,
        householdId: agent.householdId,
        lineageId: agent.lineageId,
        birthId: links.birthId,
        ageMilestoneId: links.ageMilestoneId,
        woundLegacyId: links.woundLegacyId,
        sourceEventId,
        traits,
        visibility: Math.round(clamp(visibility, 0, 1) * 1000) / 1000,
        subjectRefs: [],
        description,
        eventIds: [sourceEventId],
    };
    simulation.appearanceFeatures.push(feature);
    addAppearanceFeatureIdToAgent(agent, id);
    feature.subjectRefs = appearanceFeatureSubjectRefs(simulation, feature);
    appendAppearanceFeatureRefToEvent(simulation, feature, sourceEventId);
    if (kind !== "birth-description") {
        recordLegendEvent(simulation, {
            year: feature.year,
            type: "appearance-feature-recorded",
            headline: `${feature.name} was recorded.`,
            description: feature.description,
            civilizationId: feature.civilizationId,
            settlementId: feature.settlementId,
            personId: feature.personId,
            appearanceFeatureId: feature.id,
            birthId: feature.birthId,
            ageMilestoneId: feature.ageMilestoneId,
            woundLegacyId: feature.woundLegacyId,
            entityRefs: feature.subjectRefs,
        });
    }
    return feature;
}

function createBaselineAppearanceFeature(simulation: CivilizationSimulation, agent: Agent, birth: BirthRecord) {
    const traits = baselineAppearanceTraits(simulation, agent);
    const visibleTraits = traits.map(appearanceTraitPhrase);
    const description = `${agent.name} was first described as ${visibleTraits.slice(0, -1).join(", ")}, with ${visibleTraits[visibleTraits.length - 1]}.`;
    createAppearanceFeature(simulation, agent, "birth-description", birth.birthEventId, traits, 0.52, description, {birthId: birth.id});
}

function createAppearanceFeatureForAgeMilestone(simulation: CivilizationSimulation, milestone: AgeMilestone, agent: Agent) {
    const traits = [
        "silvered hair",
        agent.traits.includes("patient") ? "measured gait" : agent.traits.includes("restless") ? "weathered restlessness" : "weathered face",
        agent.values.includes("honor") || agent.values.includes("family") ? "honored elder bearing" : "elder bearing",
    ];
    const description = `${agent.name}'s elderhood left visible signs: ${traits.map(appearanceTraitPhrase).join(", ")}.`;
    createAppearanceFeature(simulation, agent, "elder-mark", milestone.sourceEventId, traits, 0.7, description, {ageMilestoneId: milestone.id});
}

function createAppearanceFeatureForWoundLegacy(simulation: CivilizationSimulation, legacy: WoundLegacy, agent: Agent) {
    const kindLabel = woundLegacyKindLabel(legacy.kind);
    const traits = [
        kindLabel,
        legacy.severity === "grave" ? "grave visible mark" : "serious visible mark",
        legacy.kind === "battle-fright" ? "guarded expression" : legacy.kind === "chronic-pain" ? "pained bearing" : "marked body",
    ];
    const description = `${agent.name} became visibly known for ${kindLabel} after ${simulation.injuries[legacy.injuryId]?.name ?? "an injury"}.`;
    createAppearanceFeature(simulation, agent, "wound-mark", legacy.sourceEventId, traits, legacy.severity === "grave" ? 0.86 : 0.68, description, {woundLegacyId: legacy.id});
}

function annualAgentProfessionInput(simulation: CivilizationSimulation, agent: Agent): AnnualAgentProfessionInput {
    const settlement = simulation.settlements[agent.settlementId];
    return {
        agentId: agent.id,
        age: agent.age,
        profession: agent.profession,
        settlementId: settlement.id,
        settlementType: settlement.type,
        suitability: settlement.suitability,
    };
}

function annualAgentProfessionDrafts(
    simulation: CivilizationSimulation,
    workerPool?: CivilizationWorkerPool,
): Map<number, AnnualAgentProfessionDraft> {
    const inputs: AnnualAgentProfessionInput[] = [];
    for (let agentId of simulation.aliveAgentIds) {
        const agent = simulation.agents[agentId];
        if (agent?.alive) inputs.push(annualAgentProfessionInput(simulation, agent));
    }
    if (workerPool && inputs.length > 1) {
        return workerPool.computeAnnualAgentProfessionDrafts(simulation.options.seed, inputs);
    }
    return new Map(inputs.map(input => [
        input.agentId,
        computeAnnualAgentProfessionDraft(simulation.options.seed, input),
    ]));
}

function applyAnnualAgentProfessionDraft(agent: Agent, simulation: CivilizationSimulation, draft: AnnualAgentProfessionDraft) {
    if (!agent.alive) return;
    if (draft.agentId !== agent.id) {
        throw new Error(`Profession draft for agent ${draft.agentId} applied to ${agent.id}`);
    }
    const previousProfession = agent.profession;
    agent.age = draft.age;
    agent.profession = draft.profession;

    if (agent.profession !== previousProfession) {
        for (let specialty of specialtiesForProfession(agent.profession)) {
            if (!agent.specialties.includes(specialty)) agent.specialties.push(specialty);
        }
        agent.specialties = agent.specialties.slice(0, 3);
        const professionEventId = recordLegendEvent(simulation, {
            year: simulation.year,
            type: "profession-changed",
            headline: `${agent.name} became ${indefiniteArticle(agent.profession)} ${agent.profession}.`,
            description: `${agent.name} changed profession from ${previousProfession} to ${agent.profession} in ${simulation.settlements[agent.settlementId]?.name ?? "an unknown settlement"}.`,
            civilizationId: agent.civilizationId,
            settlementId: agent.settlementId,
            personId: agent.id,
            entityRefs: [
                personRef(simulation, agent.id),
                settlementRef(simulation, agent.settlementId),
                civilizationRef(simulation, agent.civilizationId),
            ],
        });
        const career = startCareer(simulation, agent, professionEventId, previousProfession === "child" ? "came-of-age" : agent.profession === "elder" ? "retired" : "profession-changed");
        createAgeMilestoneRecord(simulation, agent, previousProfession, career, professionEventId);
    }
}

function settlementAgents(simulation: CivilizationSimulation, settlementId: number): Agent[] {
    return simulation.aliveAgentIds
        .map(id => simulation.agents[id])
        .filter(agent => agent?.alive && agent.settlementId === settlementId);
}

function updateSettlementPopulation(simulation: CivilizationSimulation, settlementId: number) {
    simulation.settlements[settlementId].population = settlementAgents(simulation, settlementId).length;
}

function updateAllSettlementPopulations(simulation: CivilizationSimulation) {
    for (let settlement of simulation.settlements) {
        settlement.population = 0;
    }
    for (let agentId of simulation.aliveAgentIds) {
        const agent = simulation.agents[agentId];
        if (agent?.alive) simulation.settlements[agent.settlementId].population++;
    }
}

function buildAliveAgentsBySettlement(simulation: CivilizationSimulation): Agent[][] {
    const bySettlement = simulation.settlements.map(() => [] as Agent[]);
    for (let agentId of simulation.aliveAgentIds) {
        const agent = simulation.agents[agentId];
        if (agent?.alive) bySettlement[agent.settlementId].push(agent);
    }
    return bySettlement;
}

function compactAliveAgentIds(simulation: CivilizationSimulation) {
    simulation.aliveAgentIds = simulation.aliveAgentIds.filter(id => simulation.agents[id]?.alive);
}

function applySettlementPopulations(simulation: CivilizationSimulation, aliveAgentsBySettlement: Agent[][]) {
    for (let settlement of simulation.settlements) {
        settlement.population = aliveAgentsBySettlement[settlement.id]?.length ?? 0;
    }
}

function linkParentChild(parent: Agent, child: Agent) {
    if (!parent.childIds.includes(child.id)) parent.childIds.push(child.id);
    if (!child.parentIds.includes(parent.id)) child.parentIds.push(parent.id);
}

function makeUnionName(a: Agent, b: Agent): string {
    return `${a.name} and ${b.name} Union`;
}

function addUnionIdToAgent(agent: Agent | undefined, unionId: number) {
    if (agent && !agent.unionIds.includes(unionId)) agent.unionIds.push(unionId);
}

function sameUnionPartners(union: UnionRecord, aId: number, bId: number): boolean {
    return (union.partnerAgentIds[0] === aId && union.partnerAgentIds[1] === bId)
        || (union.partnerAgentIds[0] === bId && union.partnerAgentIds[1] === aId);
}

function unionForPartners(simulation: CivilizationSimulation, aId: number, bId: number): UnionRecord | undefined {
    const a = simulation.agents[aId];
    const b = simulation.agents[bId];
    const candidateIds = (a?.unionIds.length ?? 0) <= (b?.unionIds.length ?? 0)
        ? a?.unionIds ?? []
        : b?.unionIds ?? [];
    let best: UnionRecord | undefined;
    for (let unionId of candidateIds) {
        const union = simulation.unions[unionId];
        if (!union || !sameUnionPartners(union, aId, bId)) continue;
        if (
            !best
            || (union.status === "active" && best.status !== "active")
            || (union.status === best.status && (union.startedYear > best.startedYear || (union.startedYear === best.startedYear && union.id > best.id)))
        ) {
            best = union;
        }
    }
    return best;
}

function unionSubjectRefs(simulation: CivilizationSimulation, union: UnionRecord): LegendEntityRef[] {
    return uniqueLegendRefs([
        unionRef(simulation, union.id),
        ...union.partnerAgentIds.map(id => personRef(simulation, id)),
        ...union.childAgentIds.slice(0, 12).map(id => personRef(simulation, id)),
        ...(union.householdId === undefined ? [] : [householdRef(simulation, union.householdId)]),
        ...(union.structureId === undefined ? [] : [structureRef(simulation, union.structureId)]),
        ...union.lineageIds.map(id => lineageRef(simulation, id)),
        ...(union.startEventId === undefined ? [] : [eventRef(simulation, union.startEventId)]),
        ...(union.endEventId === undefined ? [] : [eventRef(simulation, union.endEventId)]),
        settlementRef(simulation, union.settlementId),
        civilizationRef(simulation, union.civilizationId),
    ], 28);
}

function refreshUnionSubjectRefs(simulation: CivilizationSimulation, union: UnionRecord) {
    union.subjectRefs = unionSubjectRefs(simulation, union);
}

function createUnionRecord(simulation: CivilizationSimulation, a: Agent, b: Agent, settlement: Settlement, household: Household): UnionRecord {
    const id = simulation.unions.length;
    const union: UnionRecord = {
        id,
        name: makeUnionName(a, b),
        status: "active",
        startedYear: simulation.year,
        partnerAgentIds: [a.id, b.id],
        civilizationId: settlement.civilizationId,
        settlementId: settlement.id,
        householdId: household.id,
        structureId: household.residenceStructureId,
        lineageIds: [...household.lineageIds],
        childAgentIds: [],
        subjectRefs: [],
        description: `${a.name} and ${b.name} formed a family union in ${settlement.name}.`,
        eventIds: [],
    };
    simulation.unions.push(union);
    addUnionIdToAgent(a, id);
    addUnionIdToAgent(b, id);
    refreshUnionSubjectRefs(simulation, union);
    return union;
}

function appendUnionRefToEvent(simulation: CivilizationSimulation, union: UnionRecord, eventId: number) {
    const event = simulation.legendEvents[eventId];
    if (!event) return;
    event.unionId = union.id;
    if (!event.entityRefs.some(ref => ref.kind === "union" && ref.id === union.id)) {
        event.entityRefs.unshift(internLegendRef(simulation, unionRef(simulation, union.id)));
    }
    if (!union.eventIds.includes(eventId)) union.eventIds.push(eventId);
}

function finalizeUnionStart(simulation: CivilizationSimulation, union: UnionRecord, startEventId: number) {
    union.startEventId = startEventId;
    if (!union.eventIds.includes(startEventId)) union.eventIds.push(startEventId);
    refreshUnionSubjectRefs(simulation, union);
}

function registerUnionChildForParents(simulation: CivilizationSimulation, child: Agent, parentIds: number[], birthEventId: number): UnionRecord | undefined {
    if (parentIds.length < 2) return undefined;
    const union = unionForPartners(simulation, parentIds[0], parentIds[1]);
    if (!union) return undefined;
    if (!union.childAgentIds.includes(child.id)) union.childAgentIds.push(child.id);
    appendUnionRefToEvent(simulation, union, birthEventId);
    refreshUnionSubjectRefs(simulation, union);
    return union;
}

function closeActiveUnionsAfterDeath(simulation: CivilizationSimulation, agent: Agent, endEventId: number) {
    for (let unionId of agent.unionIds) {
        const union = simulation.unions[unionId];
        if (!union || union.status !== "active") continue;
        union.status = "ended";
        union.endedYear = simulation.year;
        union.endEventId = endEventId;
        appendUnionRefToEvent(simulation, union, endEventId);
        refreshUnionSubjectRefs(simulation, union);
    }
}

function linkSpouses(simulation: CivilizationSimulation, a: Agent, b: Agent, settlement: Settlement, year: number) {
    if (a.id === b.id || a.spouseId !== undefined || b.spouseId !== undefined) return;
    a.spouseId = b.id;
    b.spouseId = a.id;
    const household = createHousehold(simulation, settlement, [a, b]);
    const union = createUnionRecord(simulation, a, b, settlement, household);
    const marriageEventId = recordLegendEvent(simulation, {
        year,
        type: "person-married",
        headline: `${a.name} and ${b.name} married.`,
        description: `${a.name} and ${b.name} formed a household in ${settlement.name}.`,
        civilizationId: settlement.civilizationId,
        settlementId: settlement.id,
        unionId: union.id,
        householdId: household.id,
        structureId: household.residenceStructureId,
        entityRefs: [
            unionRef(simulation, union.id),
            personRef(simulation, a.id),
            personRef(simulation, b.id),
            householdRef(simulation, household.id),
            ...household.lineageIds.map(lineageId => lineageRef(simulation, lineageId)),
            ...(household.residenceStructureId !== undefined ? [structureRef(simulation, household.residenceStructureId)] : []),
            settlementRef(simulation, settlement.id),
            civilizationRef(simulation, settlement.civilizationId),
        ],
    });
    finalizeUnionStart(simulation, union, marriageEventId);
}

function chooseParentsForBirth(
    simulation: CivilizationSimulation,
    settlement: Settlement,
    agents: Agent[],
    ordinal: number,
): number[] {
    const adults = agents
        .filter(agent =>
            agent.alive
            && agent.civilizationId === settlement.civilizationId
            && agent.settlementId === settlement.id
            && agent.age >= 18
            && agent.age <= 52
        );
    if (adults.length === 0) return [];

    const adultIds = new Set(adults.map(agent => agent.id));
    const pairs = adults
        .filter(agent => agent.spouseId !== undefined && agent.id < agent.spouseId && adultIds.has(agent.spouseId))
        .sort((a, b) =>
            (a.childIds.length + (simulation.agents[a.spouseId!]?.childIds.length ?? 0))
            - (b.childIds.length + (simulation.agents[b.spouseId!]?.childIds.length ?? 0))
            || hashFloat(simulation.options.seed, simulation.year + ordinal * 997, settlement.id, a.id)
            - hashFloat(simulation.options.seed, simulation.year + ordinal * 997, settlement.id, b.id)
        );
    if (pairs.length > 0) {
        const pair = pairs[Math.floor(hashFloat(simulation.options.seed, simulation.year, settlement.id, ordinal + 811) * Math.min(4, pairs.length))];
        return [pair.id, pair.spouseId!];
    }

    const candidates = adults
        .sort((a, b) =>
            a.childIds.length - b.childIds.length
            || hashFloat(simulation.options.seed, simulation.year + ordinal * 997, settlement.id, a.id)
            - hashFloat(simulation.options.seed, simulation.year + ordinal * 997, settlement.id, b.id)
        );
    return candidates.slice(0, Math.min(2, candidates.length)).map(agent => agent.id);
}

function familyRefsForPerson(simulation: CivilizationSimulation, agent: Agent): LegendEntityRef[] {
    const refs: LegendEntityRef[] = [];
    if (agent.lineageId !== undefined) refs.push(lineageRef(simulation, agent.lineageId));
    if (agent.spouseId !== undefined) refs.push(personRef(simulation, agent.spouseId));
    for (let id of agent.parentIds.slice(0, 2)) refs.push(personRef(simulation, id));
    for (let id of agent.childIds.slice(0, 4)) refs.push(personRef(simulation, id));
    return refs;
}

function formHouseholds(
    simulation: CivilizationSimulation,
    settlement: Settlement,
    agents: Agent[],
    maxPairs: number,
    chance: number,
): number {
    if (maxPairs <= 0 || chance <= 0) return 0;
    const candidates = agents
        .filter(agent =>
            agent.alive
            && agent.spouseId === undefined
            && agent.civilizationId === settlement.civilizationId
            && agent.settlementId === settlement.id
            && agent.age >= 18
            && agent.age <= 58
        )
        .sort((a, b) =>
            hashFloat(simulation.options.seed, simulation.year, settlement.id, a.id)
            - hashFloat(simulation.options.seed, simulation.year, settlement.id, b.id)
            || a.id - b.id
        );

    let pairs = 0;
    for (let i = 0; i + 1 < candidates.length && pairs < maxPairs; i += 2) {
        const a = candidates[i];
        const b = candidates[i + 1];
        if (hashFloat(simulation.options.seed, simulation.year + 823, a.id, b.id) > chance) continue;
        linkSpouses(simulation, a, b, settlement, simulation.year);
        pairs++;
    }
    return pairs;
}

function householdPairWorkerAgent(agent: Agent): HouseholdPairWorkerAgent {
    return {
        id: agent.id,
        civilizationId: agent.civilizationId,
        settlementId: agent.settlementId,
        age: agent.age,
        spouseId: agent.spouseId,
        alive: agent.alive,
    };
}

function householdPairWorkerInput(settlement: Settlement, agents: Agent[]): HouseholdPairWorkerInput {
    return {
        settlement: {
            id: settlement.id,
            civilizationId: settlement.civilizationId,
            prosperity: settlement.prosperity,
            unrest: settlement.unrest,
        },
        agents: agents.map(householdPairWorkerAgent),
    };
}

function householdPairDrafts(
    simulation: CivilizationSimulation,
    aliveAgentsBySettlement: Agent[][],
    workerPool?: CivilizationWorkerPool,
): Map<number, HouseholdPairDraft> {
    const inputs = simulation.settlements.map(settlement => householdPairWorkerInput(
        settlement,
        aliveAgentsBySettlement[settlement.id] ?? [],
    ));
    if (workerPool && inputs.length > 1) {
        return workerPool.computeHouseholdPairDrafts(simulation.options.seed, simulation.year, inputs);
    }
    return new Map(inputs.map(input => [
        input.settlement.id,
        computeHouseholdPairDraft(simulation.options.seed, simulation.year, input),
    ]));
}

function applyHouseholdPairDraft(simulation: CivilizationSimulation, settlement: Settlement, draft: HouseholdPairDraft): number {
    if (draft.settlementId !== settlement.id) {
        throw new Error(`Household pair draft for settlement ${draft.settlementId} applied to ${settlement.id}`);
    }
    let pairs = 0;
    for (let [aId, bId] of draft.pairs) {
        const a = simulation.agents[aId];
        const b = simulation.agents[bId];
        if (!a || !b) continue;
        linkSpouses(simulation, a, b, settlement, simulation.year);
        pairs++;
    }
    return pairs;
}

function arrangeInitialHouseholds(simulation: CivilizationSimulation, settlement: Settlement, agents: Agent[]) {
    formHouseholds(simulation, settlement, agents, Math.floor(agents.length * 0.32), 0.72);
}

function maybeFormHouseholds(simulation: CivilizationSimulation, settlement: Settlement, agents: Agent[], draft?: HouseholdPairDraft): number {
    if (draft) return applyHouseholdPairDraft(simulation, settlement, draft);
    if (simulation.year <= 0) return 0;
    const adults = agents.filter(agent => agent.alive && agent.spouseId === undefined && agent.age >= 18 && agent.age <= 42);
    if (adults.length < 2) return 0;
    const chance = clamp(0.02 + settlement.prosperity * 0.05 - settlement.unrest * 0.035, 0.005, 0.08);
    const maxPairs = Math.max(0, Math.floor(adults.length * (0.003 + settlement.prosperity * 0.004)));
    return formHouseholds(simulation, settlement, adults, maxPairs, chance);
}

function inheritedFamilyName(simulation: CivilizationSimulation, parentIds: number[]): string | undefined {
    for (let parentId of parentIds) {
        const parent = simulation.agents[parentId];
        if (parent) return agentFamilyName(parent.name);
    }
    return undefined;
}

function lineageIndexKey(civilizationId: number, familyName: string): string {
    return `${civilizationId}:${familyName}`;
}

function findLineage(simulation: CivilizationSimulation, civilizationId: number, familyName: string): Lineage | undefined {
    const id = simulation.lineageIndex.get(lineageIndexKey(civilizationId, familyName));
    return id === undefined ? undefined : simulation.lineages[id];
}

function assignAgentLineage(simulation: CivilizationSimulation, agent: Agent, settlement: Settlement) {
    const familyName = agentFamilyName(agent.name);
    let lineage = findLineage(simulation, agent.civilizationId, familyName);
    if (!lineage) {
        const id = simulation.lineages.length;
        lineage = {
            id,
            name: `${familyName} Lineage`,
            familyName,
            civilizationId: agent.civilizationId,
            originSettlementId: settlement.id,
            foundedYear: Math.min(simulation.year, agent.bornYear),
            founderAgentId: agent.id,
            memberAgentIds: [],
            householdIds: [],
            eventIds: [],
        };
        simulation.lineages.push(lineage);
        simulation.lineageIndex.set(lineageIndexKey(agent.civilizationId, familyName), id);
        recordLegendEvent(simulation, {
            year: lineage.foundedYear,
            type: "lineage-founded",
            headline: `${lineage.name} entered the record.`,
            description: `${lineage.name} first entered the records of ${simulation.civilizations[agent.civilizationId].name} through ${agent.name} in ${settlement.name}.`,
            civilizationId: agent.civilizationId,
            settlementId: settlement.id,
            personId: agent.id,
            lineageId: id,
            entityRefs: [
                lineageRef(simulation, id),
                personRef(simulation, agent.id),
                settlementRef(simulation, settlement.id),
                civilizationRef(simulation, agent.civilizationId),
            ],
        });
    }
    agent.lineageId = lineage.id;
    if (!lineage.memberAgentIds.includes(agent.id)) lineage.memberAgentIds.push(agent.id);
}

function linkHouseholdLineages(simulation: CivilizationSimulation, household: Household, agents: Agent[]) {
    for (let agent of agents) {
        if (agent.lineageId === undefined || household.lineageIds.includes(agent.lineageId)) continue;
        household.lineageIds.push(agent.lineageId);
        const lineage = simulation.lineages[agent.lineageId];
        if (lineage && !lineage.householdIds.includes(household.id)) lineage.householdIds.push(household.id);
    }
}

function addPreferenceIdToAgent(agent: Agent | undefined, preferenceId: number) {
    if (agent && !agent.preferenceIds.includes(preferenceId)) agent.preferenceIds.push(preferenceId);
}

function preferenceKindLabel(kind: PreferenceKind): string {
    if (kind === "structure-kind") return "place";
    if (kind === "artifact-kind") return "object";
    if (kind === "settlement-quality") return "settlement quality";
    return kind;
}

function preferenceName(agent: Agent, sentiment: PreferenceSentiment, targetName: string): string {
    return `${agent.name} ${sentiment} ${targetName}`;
}

function professionActivityPreference(profession: AgentProfession): LifeActivityKind {
    if (profession === "merchant") return "market-visit";
    if (profession === "guard") return "training";
    if (profession === "scholar") return "study";
    if (profession === "healer") return "healing-care";
    if (profession === "artisan" || profession === "miner") return "craft-practice";
    if (profession === "child") return "child-play";
    if (profession === "elder") return "social-visit";
    return "shared-meal";
}

function valueActivityPreference(value: AgentValue): LifeActivityKind {
    if (value === "faith") return "worship";
    if (value === "knowledge") return "study";
    if (value === "craft") return "craft-practice";
    if (value === "wealth") return "market-visit";
    if (value === "honor") return "training";
    if (value === "comfort") return "rest";
    return "social-visit";
}

function preferenceReasonForAgent(agent: Agent, sentiment: PreferenceSentiment, targetName: string): string {
    const trait = agent.traits[0] ?? "their nature";
    const value = agent.values[0] ?? "their values";
    if (sentiment === "reveres") return `${agent.name} reveres ${targetName} because of ${value}.`;
    if (sentiment === "dislikes") return `${agent.name} dislikes ${targetName} because they are ${trait}.`;
    return `${agent.name} likes ${targetName} because of ${value} and their ${trait} temperament.`;
}

function createPersonalPreference(
    simulation: CivilizationSimulation,
    agent: Agent,
    settlement: Settlement,
    kind: PreferenceKind,
    sentiment: PreferenceSentiment,
    targetKey: string,
    targetName: string,
    strength: number,
) {
    if (agent.preferenceIds.some(id => {
        const existing = simulation.preferences[id];
        return existing?.kind === kind && existing.targetKey === targetKey && existing.sentiment === sentiment;
    })) return;
    const id = simulation.preferences.length;
    const reason = preferenceReasonForAgent(agent, sentiment, targetName);
    const preference: PersonalPreference = {
        id,
        name: preferenceName(agent, sentiment, targetName),
        kind,
        sentiment,
        targetKey,
        targetName,
        reason,
        strength: Math.round(clamp(strength, 0.1, 1) * 1000) / 1000,
        agentId: agent.id,
        civilizationId: agent.civilizationId,
        settlementId: settlement.id,
        recordedYear: agent.bornYear,
        subjectRefs: [],
        description: `${reason} Strength ${Math.round(clamp(strength, 0.1, 1) * 1000) / 1000}.`,
        eventIds: [],
    };
    simulation.preferences.push(preference);
    addPreferenceIdToAgent(agent, id);
    preference.subjectRefs = uniqueLegendRefs([
        preferenceRef(simulation, id),
        personRef(simulation, agent.id),
        settlementRef(simulation, settlement.id),
        civilizationRef(simulation, agent.civilizationId),
    ], 12);
}

function createInitialPreferencesForAgent(simulation: CivilizationSimulation, agent: Agent, settlement: Settlement) {
    const seed = simulation.options.seed;
    const chance = agent.age >= 15 ? 0.22 : 0.08;
    if (hashFloat(seed, agent.id, 2629, 1) > chance) return;
    const mainValue = agent.values[0] ?? "community";
    const activity = agent.values.includes("faith") || agent.values.includes("knowledge") || agent.values.includes("comfort")
        ? valueActivityPreference(mainValue)
        : professionActivityPreference(agent.profession);
    createPersonalPreference(
        simulation,
        agent,
        settlement,
        "activity",
        agent.values.includes("faith") || agent.values.includes("craft") || agent.values.includes("knowledge") ? "reveres" : "likes",
        activity,
        lifeActivityKindLabel(activity),
        0.42 + hashFloat(seed, agent.id, 2633, 1) * 0.38,
    );

    const material = ARTIFACT_MATERIALS[Math.floor(hashFloat(seed, agent.id, 2639, 1) * ARTIFACT_MATERIALS.length)];
    createPersonalPreference(
        simulation,
        agent,
        settlement,
        "material",
        agent.values.includes("wealth") || agent.values.includes("craft") ? "reveres" : "likes",
        material,
        material,
        0.34 + hashFloat(seed, agent.id, 2639, 2) * 0.42,
    );

    if (agent.reputation < 0.45 && hashFloat(seed, agent.id, 2641, 0) > 0.35) return;
    if (agent.traits.includes("restless")) {
        createPersonalPreference(simulation, agent, settlement, "activity", "dislikes", "rest", lifeActivityKindLabel("rest"), 0.42 + hashFloat(seed, agent.id, 2641, 1) * 0.34);
    } else if (agent.traits.includes("melancholy")) {
        createPersonalPreference(simulation, agent, settlement, "settlement-quality", "dislikes", "unrest", "unrest", 0.38 + hashFloat(seed, agent.id, 2641, 2) * 0.36);
    } else if (agent.values.includes("family")) {
        createPersonalPreference(simulation, agent, settlement, "structure-kind", "likes", "residence", "homes", 0.36 + hashFloat(seed, agent.id, 2641, 3) * 0.34);
    } else {
        const artifactKind = ARTIFACT_KINDS[Math.floor(hashFloat(seed, agent.id, 2641, 4) * ARTIFACT_KINDS.length)];
        createPersonalPreference(simulation, agent, settlement, "artifact-kind", "likes", artifactKind, artifactKind, 0.3 + hashFloat(seed, agent.id, 2641, 5) * 0.36);
    }
}

function addTraditionIdToAgent(agent: Agent | undefined, traditionId: number) {
    if (agent && !agent.traditionIds.includes(traditionId)) agent.traditionIds.push(traditionId);
}

function addTraditionIdToSettlement(settlement: Settlement | undefined, traditionId: number) {
    if (settlement && !settlement.traditionIds.includes(traditionId)) settlement.traditionIds.push(traditionId);
}

function addTraditionIdToCivilization(civilization: Civilization | undefined, traditionId: number) {
    if (civilization && !civilization.traditionIds.includes(traditionId)) civilization.traditionIds.push(traditionId);
}

function addAdherentToTradition(tradition: CulturalTradition | undefined, agentId: number) {
    if (tradition && !tradition.adherentAgentIds.includes(agentId)) tradition.adherentAgentIds.push(agentId);
}

function traditionKindLabel(kind: CulturalTraditionKind): string {
    if (kind === "festival-custom") return "festival custom";
    if (kind === "craft-style") return "craft style";
    if (kind === "food-custom") return "food custom";
    if (kind === "funerary-rite") return "funerary rite";
    if (kind === "legal-custom") return "legal custom";
    if (kind === "hospitality-code") return "hospitality code";
    if (kind === "training-drill") return "training drill";
    return "story cycle";
}

function traditionActivityKind(kind: CulturalTraditionKind): LifeActivityKind | undefined {
    if (kind === "craft-style") return "craft-practice";
    if (kind === "food-custom" || kind === "hospitality-code") return "shared-meal";
    if (kind === "training-drill") return "training";
    if (kind === "story-cycle") return "study";
    if (kind === "festival-custom") return "social-visit";
    if (kind === "funerary-rite") return "worship";
    if (kind === "legal-custom") return "market-visit";
    return undefined;
}

function traditionCeremonyKind(kind: CulturalTraditionKind): CeremonyKind | undefined {
    if (kind === "festival-custom" || kind === "food-custom" || kind === "hospitality-code" || kind === "story-cycle") return "festival";
    if (kind === "funerary-rite") return "remembrance";
    if (kind === "legal-custom") return "court-session";
    if (kind === "training-drill") return "muster";
    if (kind === "craft-style") return "market-fair";
    return undefined;
}

function traditionKindForSlot(seed: number, settlement: Settlement, slot: number): CulturalTraditionKind {
    const kinds: CulturalTraditionKind[] = settlement.type === "capital"
        ? ["festival-custom", "legal-custom", "craft-style", "story-cycle", "food-custom", "funerary-rite", "hospitality-code", "training-drill"]
        : ["food-custom", "craft-style", "hospitality-code", "story-cycle", "festival-custom", "training-drill", "funerary-rite"];
    return kinds[Math.floor(hashFloat(seed, settlement.id, slot, 2663) * kinds.length)];
}

function traditionSubjectNameForKind(simulation: CivilizationSimulation, settlement: Settlement, kind: CulturalTraditionKind, belief?: Belief, organization?: Organization): string {
    if (belief && (kind === "funerary-rite" || kind === "festival-custom" || kind === "story-cycle")) return belief.name;
    if (organization && (kind === "craft-style" || kind === "training-drill" || kind === "legal-custom" || kind === "hospitality-code")) return organization.name;
    if (kind === "legal-custom") return "the bench";
    if (kind === "training-drill") return "the watch";
    if (kind === "food-custom") return "the hearth";
    if (kind === "hospitality-code") return "the guest door";
    if (kind === "funerary-rite") return "the remembered dead";
    if (kind === "craft-style") return "the workshops";
    if (kind === "story-cycle") return simulation.civilizations[settlement.civilizationId]?.name ?? settlement.name;
    return settlement.name;
}

function makeTraditionName(simulation: CivilizationSimulation, id: number, kind: CulturalTraditionKind, subjectName: string): string {
    const noun = TRADITION_NOUNS[kind][Math.floor(hashFloat(simulation.options.seed, id, simulation.year, 2671) * TRADITION_NOUNS[kind].length)];
    return `${noun} ${subjectName}`;
}

function chooseTraditionFounder(agents: Agent[], kind: CulturalTraditionKind): Agent | undefined {
    return agents
        .filter(agent => agent.alive && agent.age >= 16)
        .sort((a, b) => {
            const score = (agent: Agent) =>
                agent.reputation * 0.45
                + agent.skill * 0.35
                + (agent.profession === "elder" ? 0.28 : 0)
                + (kind === "craft-style" && (agent.profession === "artisan" || agent.profession === "miner") ? 0.32 : 0)
                + (kind === "legal-custom" && (agent.values.includes("law") || agent.profession === "scholar") ? 0.3 : 0)
                + (kind === "training-drill" && (agent.profession === "guard" || agent.specialties.includes("warfare")) ? 0.32 : 0)
                + (kind === "story-cycle" && (agent.specialties.includes("lore") || agent.values.includes("knowledge")) ? 0.28 : 0)
                + (kind === "funerary-rite" && (agent.values.includes("family") || agent.values.includes("faith")) ? 0.26 : 0)
                + (kind === "festival-custom" && agent.values.includes("community") ? 0.22 : 0);
            return score(b) - score(a) || b.age - a.age || a.id - b.id;
        })[0];
}

function matchingTraditionOrganization(simulation: CivilizationSimulation, settlement: Settlement, kind: CulturalTraditionKind): Organization | undefined {
    const preferredKinds: OrganizationKind[] = kind === "craft-style" ? ["guild", "college"]
        : kind === "training-drill" ? ["militia"]
        : kind === "legal-custom" ? ["college", "clan"]
        : kind === "hospitality-code" || kind === "food-custom" ? ["clan", "trade-house", "guild"]
        : kind === "festival-custom" || kind === "funerary-rite" ? ["temple", "clan"]
        : ["college", "clan", "temple"];
    return simulation.organizations
        .filter(organization => organization.settlementId === settlement.id && preferredKinds.includes(organization.kind))
        .sort((a, b) => b.memberIds.length - a.memberIds.length || a.id - b.id)[0];
}

function createCulturalTradition(
    simulation: CivilizationSimulation,
    settlement: Settlement,
    kind: CulturalTraditionKind,
    agents: Agent[],
): CulturalTradition | undefined {
    if (settlement.traditionIds.some(id => simulation.traditions[id]?.kind === kind)) return undefined;
    const id = simulation.traditions.length;
    const founder = chooseTraditionFounder(agents, kind);
    const belief = kind === "funerary-rite" || kind === "festival-custom" || kind === "story-cycle"
        ? dominantBeliefForCivilization(simulation, settlement.civilizationId)
        : undefined;
    const organization = matchingTraditionOrganization(simulation, settlement, kind);
    const subjectName = traditionSubjectNameForKind(simulation, settlement, kind, belief, organization);
    const strength = Math.round(clamp(0.34 + settlement.prosperity * 0.18 + (settlement.type === "capital" ? 0.08 : 0) + hashFloat(simulation.options.seed, id, settlement.id, 2677) * 0.32, 0.1, 1) * 1000) / 1000;
    const tradition: CulturalTradition = {
        id,
        name: makeTraditionName(simulation, id, kind, subjectName),
        kind,
        civilizationId: settlement.civilizationId,
        settlementId: settlement.id,
        originYear: simulation.year,
        founderAgentId: founder?.id,
        beliefId: belief?.id,
        organizationId: organization?.id,
        activityKind: traditionActivityKind(kind),
        ceremonyKind: traditionCeremonyKind(kind),
        strength,
        practiceCount: 0,
        adherentAgentIds: [],
        activityIds: [],
        ceremonyIds: [],
        writtenWorkIds: [],
        subjectRefs: [],
        description: `${settlement.name} kept ${traditionKindLabel(kind)} ${subjectName}.`,
        eventIds: [],
    };
    simulation.traditions.push(tradition);
    addTraditionIdToSettlement(settlement, id);
    addTraditionIdToCivilization(simulation.civilizations[settlement.civilizationId], id);
    tradition.subjectRefs = uniqueLegendRefs([
        traditionRef(simulation, id),
        settlementRef(simulation, settlement.id),
        civilizationRef(simulation, settlement.civilizationId),
        ...(founder ? [personRef(simulation, founder.id)] : []),
        ...(belief ? [beliefRef(simulation, belief.id)] : []),
        ...(organization ? [organizationRef(simulation, organization.id)] : []),
    ], 14);
    for (let agent of agents) {
        const affinity = agent.values.includes("community") || agent.values.includes("family") || agent.values.includes("faith") || agent.values.includes("knowledge") ? 0.18 : 0;
        if (agent.id === founder?.id || hashFloat(simulation.options.seed, id, agent.id, 2681) < clamp(0.32 + strength * 0.28 + affinity, 0.2, 0.82)) {
            addTraditionIdToAgent(agent, id);
            addAdherentToTradition(tradition, agent.id);
        }
    }
    recordLegendEvent(simulation, {
        year: simulation.year,
        type: "tradition-founded",
        headline: `${tradition.name} became a tradition in ${settlement.name}.`,
        description: `${tradition.name}, a ${traditionKindLabel(kind)}, took root in ${settlement.name}${founder ? ` through ${founder.name}` : ""}. Strength ${strength}.`,
        civilizationId: settlement.civilizationId,
        settlementId: settlement.id,
        personId: founder?.id,
        traditionId: id,
        beliefId: belief?.id,
        organizationId: organization?.id,
        entityRefs: tradition.subjectRefs,
    });
    return tradition;
}

function assignAgentTraditions(simulation: CivilizationSimulation, agent: Agent, settlement: Settlement) {
    const candidates = [...new Set([
        ...settlement.traditionIds,
        ...(simulation.civilizations[agent.civilizationId]?.traditionIds ?? []),
    ])]
        .map(id => simulation.traditions[id])
        .filter((tradition): tradition is CulturalTradition => !!tradition);
    if (candidates.length === 0) return;
    const limit = agent.age < 12 ? 1 : 2;
    const scored = candidates
        .sort((a, b) => {
            const score = (tradition: CulturalTradition) =>
                tradition.strength
                + (tradition.settlementId === settlement.id ? 0.18 : 0)
                + (tradition.kind === "craft-style" && (agent.profession === "artisan" || agent.profession === "miner") ? 0.2 : 0)
                + (tradition.kind === "legal-custom" && agent.values.includes("law") ? 0.18 : 0)
                + (tradition.kind === "training-drill" && (agent.profession === "guard" || agent.specialties.includes("warfare")) ? 0.2 : 0)
                + (tradition.kind === "funerary-rite" && (agent.values.includes("family") || agent.values.includes("faith")) ? 0.18 : 0)
                + (tradition.kind === "story-cycle" && (agent.values.includes("knowledge") || agent.specialties.includes("lore")) ? 0.18 : 0)
                + hashFloat(simulation.options.seed, agent.id, tradition.id, 2687) * 0.1;
            return score(b) - score(a) || a.id - b.id;
        })
        .slice(0, limit);
    for (let tradition of scored) {
        if (hashFloat(simulation.options.seed, agent.id, tradition.id, 2693) < clamp(0.42 + tradition.strength * 0.38, 0.3, 0.9)) {
            addTraditionIdToAgent(agent, tradition.id);
            addAdherentToTradition(tradition, agent.id);
        }
    }
}

function seedSettlementTraditions(simulation: CivilizationSimulation, settlement: Settlement, agents: Agent[]) {
    if (agents.length === 0) return;
    const target = settlement.type === "capital" ? 3 : 2;
    for (let slot = 0; slot < target; slot++) {
        createCulturalTradition(simulation, settlement, traditionKindForSlot(simulation.options.seed, settlement, slot), agents);
    }
    for (let agent of agents) assignAgentTraditions(simulation, agent, settlement);
}

function birthRecordKindForAgent(agent: Agent): BirthRecordKind {
    if (agent.parentIds.length > 0) return "lineage-childbirth";
    if (agent.bornYear < 0) return "founding-generation";
    return "recorded-birth";
}

function makeBirthRecordName(agent: Agent, kind: BirthRecordKind): string {
    if (kind === "founding-generation") return `${agent.name}'s founding-generation birth record`;
    if (kind === "lineage-childbirth") return `${agent.name}'s family birth`;
    return `${agent.name}'s birth`;
}

function createBirthRecord(
    simulation: CivilizationSimulation,
    agent: Agent,
    settlement: Settlement,
    birthEventId: number,
    household?: Household,
    union?: UnionRecord,
): BirthRecord {
    const id = simulation.births.length;
    const kind = birthRecordKindForAgent(agent);
    const parentNames = agent.parentIds.map(parentId => simulation.agents[parentId]?.name).filter(Boolean);
    const parentClause = parentNames.length === 0
        ? "No parents were recorded in the archive."
        : parentNames.length === 1
            ? `${parentNames[0]} was recorded as a parent.`
            : `${parentNames.slice(0, -1).join(", ")} and ${parentNames[parentNames.length - 1]} were recorded as parents.`;
    const birth: BirthRecord = {
        id,
        name: makeBirthRecordName(agent, kind),
        kind,
        year: agent.bornYear,
        personId: agent.id,
        parentAgentIds: [...agent.parentIds],
        civilizationId: agent.civilizationId,
        settlementId: settlement.id,
        householdId: household?.id,
        lineageId: agent.lineageId,
        structureId: household?.residenceStructureId,
        beliefId: agent.beliefId,
        unionId: union?.id,
        birthEventId,
        subjectRefs: [],
        description: `${agent.name} was born in ${settlement.name} of ${simulation.civilizations[agent.civilizationId]?.name ?? "an unknown civilization"}. ${parentClause}`,
        eventIds: [birthEventId],
    };
    simulation.births.push(birth);
    agent.birthId = id;
    birth.subjectRefs = uniqueLegendRefs([
        birthRef(simulation, id),
        personRef(simulation, agent.id),
        eventRef(simulation, birthEventId),
        settlementRef(simulation, settlement.id),
        civilizationRef(simulation, agent.civilizationId),
        ...birth.parentAgentIds.map(parentId => personRef(simulation, parentId)),
        ...(household ? [householdRef(simulation, household.id)] : []),
        ...(agent.lineageId === undefined ? [] : [lineageRef(simulation, agent.lineageId)]),
        ...(household?.residenceStructureId === undefined ? [] : [structureRef(simulation, household.residenceStructureId)]),
        ...(agent.beliefId === undefined ? [] : [beliefRef(simulation, agent.beliefId)]),
        ...(union === undefined ? [] : [unionRef(simulation, union.id)]),
    ], 32);

    const birthEvent = simulation.legendEvents[birthEventId];
    if (birthEvent) {
        birthEvent.birthId = id;
        if (!birthEvent.entityRefs.some(ref => ref.kind === "birth" && ref.id === id)) {
            birthEvent.entityRefs.unshift(internLegendRef(simulation, birthRef(simulation, id)));
        }
    }
    createBaselineAppearanceFeature(simulation, agent, birth);
    return birth;
}

function createAgent(
    simulation: CivilizationSimulation,
    civilizationId: number,
    settlementId: number,
    age: number,
    bornYear: number,
    profession?: AgentProfession,
    parentIds: number[] = [],
    initialDraft?: InitialAgentDraft,
): Agent {
    const id = simulation.agents.length;
    const settlement = simulation.settlements[settlementId];
    const familyName = inheritedFamilyName(simulation, parentIds);
    if (initialDraft && initialDraft.id !== id) {
        throw new Error(`Initial agent draft ${initialDraft.id} applied to agent ${id}`);
    }
    const draft = initialDraft;
    const assignedProfession = draft?.profession ?? profession
        ?? (age < 15 ? "child" : age >= 65 ? "elder" : chooseAdultProfession(simulation.options.seed, id, settlement, settlement.suitability));
    const traits = draft ? [...draft.traits] : initialAgentTraits(simulation.options.seed, id);
    const values = draft ? [...draft.values] : initialAgentValues(simulation.options.seed, id, assignedProfession);
    const morale = draft?.morale ?? clamp(0.58 + settlement.suitability * 0.25 + hashFloat(simulation.options.seed, id, 307, 2) * 0.17, 0, 1);
    const stress = draft?.stress ?? clamp(
        0.12
        + (traits.includes("melancholy") ? 0.08 : 0)
        + (traits.includes("restless") ? 0.04 : 0)
        - (traits.includes("patient") ? 0.03 : 0)
        - settlement.prosperity * 0.04
        + settlement.unrest * 0.08,
        0,
        1,
    );
    const resilience = draft?.resilience ?? initialAgentResilience(traits, values, simulation.options.seed, id);
    const agent: Agent = {
        id,
        name: uniqueAgentName(simulation, draft && familyName === undefined ? draft.name : makeAgentName(simulation.options.seed, id, familyName)),
        civilizationId,
        settlementId,
        bornYear,
        age,
        profession: assignedProfession,
        health: draft?.health ?? clamp(0.72 + hashFloat(simulation.options.seed, id, 307, 1) * 0.28, 0, 1),
        morale,
        stress,
        resilience,
        mentalState: draft?.mentalState ?? mentalStateFor(stress, morale),
        needStates: draft ? draft.needStates.map(need => ({...need})) : initialAgentNeeds(simulation.options.seed, id, assignedProfession, traits, values),
        needEpisodeIds: [],
        wealth: draft?.wealth ?? Math.round((6 + hashFloat(simulation.options.seed, id, 307, 3) * 16) * 100) / 100,
        skill: draft?.skill ?? clamp(0.2 + age / 90 + hashFloat(simulation.options.seed, id, 307, 4) * 0.25, 0, 1),
        traits,
        values,
        specialties: draft ? [...draft.specialties] : initialAgentSpecialties(simulation.options.seed, id, assignedProfession),
        epithets: [],
        epithetIds: [],
        reputationMilestoneIds: [],
        preferenceIds: [],
        writtenWorkIds: [],
        traditionIds: [],
        reputation: draft?.reputation ?? Math.round(clamp(0.03 + (age >= 18 ? age / 120 : 0) + hashFloat(simulation.options.seed, id, 307, 5) * 0.08, 0, 1) * 1000) / 1000,
        parentIds: [],
        childIds: [],
        organizationIds: [],
        membershipIds: [],
        socialBondIds: [],
        relationshipMilestoneIds: [],
        socialClaimIds: [],
        unionIds: [],
        beliefAdherenceIds: [],
        magicRoleIds: [],
        personAllegianceIds: [],
        officeIds: [],
        officeTermIds: [],
        caseIds: [],
        testimonyIds: [],
        battleIds: [],
        battleParticipationIds: [],
        journeyIds: [],
        structureIds: [],
        injuryIds: [],
        illnessIds: [],
        woundLegacyIds: [],
        memorialIds: [],
        burialIds: [],
        ageMilestoneIds: [],
        appearanceFeatureIds: [],
        ambitionIds: [],
        apprenticeshipIds: [],
        skillRecordIds: [],
        memoryIds: [],
        thoughtIds: [],
        personalityShiftIds: [],
        opinionIds: [],
        rumorIds: [],
        secretIds: [],
        schemeIds: [],
        feudIds: [],
        oathIds: [],
        ceremonyIds: [],
        ceremonyParticipationIds: [],
        activityIds: [],
        projectIds: [],
        projectParticipationIds: [],
        obligationIds: [],
        holdingIds: [],
        belongingIds: [],
        residenceIds: [],
        careerIds: [],
        alive: true,
        eventIds: [],
    };
    simulation.agents.push(agent);
    simulation.aliveAgentIds.push(agent.id);
    assignAgentLineage(simulation, agent, settlement);
    for (let parentId of parentIds) {
        const parent = simulation.agents[parentId];
        if (parent) linkParentChild(parent, agent);
    }
    const household = householdForParents(simulation, agent.parentIds);
    if (household) addAgentToHousehold(simulation, household, agent);
    const inheritedBelief = chooseBeliefForAgent(simulation, civilizationId, settlementId, agent.parentIds);
    if (inheritedBelief) adoptBelief(simulation, agent, inheritedBelief, settlement, false);

    const parentRefs = agent.parentIds.map(parentId => personRef(simulation, parentId));
    const parentNames = agent.parentIds.map(parentId => simulation.agents[parentId]?.name).filter(Boolean);
    const parentClause = parentNames.length === 0
        ? ""
        : parentNames.length === 1
            ? ` to ${parentNames[0]}`
            : ` to ${parentNames.slice(0, -1).join(", ")} and ${parentNames[parentNames.length - 1]}`;
    const birthEventId = recordLegendEvent(simulation, {
        year: bornYear,
        type: "person-born",
        headline: `${agent.name} was born.`,
        description: `${agent.name} was born${parentClause} in ${settlement.name} of ${simulation.civilizations[civilizationId].name}.`,
        civilizationId,
        settlementId,
        personId: id,
        householdId: household?.id,
        structureId: household?.residenceStructureId,
        lineageId: agent.lineageId,
        entityRefs: [
            personRef(simulation, id),
            ...(agent.lineageId !== undefined ? [lineageRef(simulation, agent.lineageId)] : []),
            ...parentRefs,
            ...(household ? [householdRef(simulation, household.id)] : []),
            ...(household?.residenceStructureId !== undefined ? [structureRef(simulation, household.residenceStructureId)] : []),
            settlementRef(simulation, settlementId),
            civilizationRef(simulation, civilizationId),
        ],
    });
    const parentUnion = registerUnionChildForParents(simulation, agent, agent.parentIds, birthEventId);
    createBirthRecord(simulation, agent, settlement, birthEventId, household, parentUnion);
    startPersonAllegiance(simulation, agent, civilizationId, settlement, parentIds.length > 0 ? "born" : "settled", {
        startEventId: birthEventId,
    });
    startResidence(simulation, agent, birthEventId, parentIds.length > 0 ? "born" : "settled", {settlement, household});
    startCareer(simulation, agent, birthEventId, assignedProfession === "child" ? "childhood" : "settled", {settlement, profession: assignedProfession});
    createInitialPreferencesForAgent(simulation, agent, settlement);
    assignAgentTraditions(simulation, agent, settlement);
    return agent;
}

function seedSettlementAgents(simulation: CivilizationSimulation, settlement: Settlement, seedPlan?: SettlementAgentSeedPlan): Agent[] {
    const targetPopulation = settlement.population;
    const createdAgents: Agent[] = [];
    withSuppressedLegendEventMemories(simulation, () => {
        const plan = seedPlan ?? timedPhase(simulation, "settlement-seed-agent-plan", () => buildSettlementAgentSeedPlan(simulation.options.seed, {
            settlementId: settlement.id,
            targetPopulation,
            firstAgentId: simulation.agents.length,
            civilizationId: settlement.civilizationId,
            type: settlement.type,
            suitability: settlement.suitability,
            prosperity: settlement.prosperity,
            unrest: settlement.unrest,
        }));
        if (plan.settlementId !== settlement.id) {
            throw new Error(`Seed plan for settlement ${plan.settlementId} applied to ${settlement.id}`);
        }
        if (plan.adultPlans.length + plan.childPlans.length !== targetPopulation) {
            throw new Error(`Seed plan for ${settlement.name} has ${plan.adultPlans.length + plan.childPlans.length} agents, expected ${targetPopulation}`);
        }

        timedPhase(simulation, "settlement-seed-adult-agents", () => {
            plan.adultPlans.forEach((agentPlan, index) => {
                createdAgents.push(createAgent(
                    simulation,
                    settlement.civilizationId,
                    settlement.id,
                    agentPlan.age,
                    simulation.year - agentPlan.age,
                    undefined,
                    [],
                    plan.adultDrafts[index],
                ));
            });
        });

        timedPhase(simulation, "settlement-seed-households", () => {
            arrangeInitialHouseholds(simulation, settlement, createdAgents);
        });

        timedPhase(simulation, "settlement-seed-child-agents", () => {
            plan.childPlans.forEach((agentPlan, index) => {
                const parentIds = chooseParentsForBirth(simulation, settlement, createdAgents, agentPlan.index);
                const child = createAgent(
                    simulation,
                    settlement.civilizationId,
                    settlement.id,
                    agentPlan.age,
                    simulation.year - agentPlan.age,
                    "child",
                    parentIds,
                    plan.childDrafts[index],
                );
                createdAgents.push(child);
            });
        });
    });

    if (createdAgents.length !== targetPopulation) {
        throw new Error(`Seeded ${createdAgents.length} agents for ${settlement.name}, expected ${targetPopulation}`);
    }
    settlement.population = createdAgents.length;
    return createdAgents;
}

function recordEvent(simulation: CivilizationSimulation, event: YearEvent) {
    simulation.events.push(event);
}

