function roadLegendName(simulation: CivilizationSimulation, id: number): string {
    const road = simulation.roads[id];
    if (!road) return `Road ${id}`;
    const from = simulation.settlements[road.fromSettlementId]?.name ?? `Settlement ${road.fromSettlementId}`;
    const to = simulation.settlements[road.toSettlementId]?.name ?? `Settlement ${road.toSettlementId}`;
    return `${from} to ${to} road`;
}

