const exportLegendEventFieldKinds: Array<[keyof LegendEvent, LegendEntityRef["kind"]]> = [
    ...compactedLegendEventFieldKinds,
    ["sourceEventId", "event"],
];

function addExportEventId(index: ExportEventIdIndex, kind: LegendEntityRef["kind"], id: number | undefined, eventId: number) {
    if (id === undefined || id < 0) return;
    let byId = index[kind];
    if (!byId) {
        byId = new Map<number, number[]>();
        index[kind] = byId;
    }
    let eventIds = byId.get(id);
    if (!eventIds) {
        eventIds = [];
        byId.set(id, eventIds);
    }
    if (eventIds[eventIds.length - 1] !== eventId) eventIds.push(eventId);
}

function roadMatchesJourney(road: Road, journey: Journey): boolean {
    return road.civilizationId === journey.civilizationId
        && journey.year >= road.openedYear
        && (
            road.fromSettlementId === journey.fromSettlementId && road.toSettlementId === journey.toSettlementId
            || road.fromSettlementId === journey.toSettlementId && road.toSettlementId === journey.fromSettlementId
        );
}

function exportRoadIdsForJourney(simulation: CivilizationSimulation, journey: Journey): number[] {
    return simulation.roads
        .filter(road => roadMatchesJourney(road, journey))
        .map(road => road.id);
}

function exportJourneyIdsForEvent(event: LegendEvent): number[] {
    const ids = event.entityRefs
        .filter(ref => ref.kind === "journey")
        .map(ref => ref.id);
    if (event.journeyId !== undefined) ids.unshift(event.journeyId);
    return uniqueNumberList(ids);
}

function exportRoadRefsForEvent(simulation: CivilizationSimulation, event: LegendEvent): LegendEntityRef[] {
    const roadIds: number[] = [];
    for (let journeyId of exportJourneyIdsForEvent(event)) {
        const journey = simulation.journeys[journeyId];
        if (journey) roadIds.push(...exportRoadIdsForJourney(simulation, journey));
    }
    return uniqueNumberList(roadIds).map(roadId => roadRef(simulation, roadId));
}

function eventFieldRefsForExport(simulation: CivilizationSimulation, event: LegendEvent): LegendEntityRef[] {
    const refs: LegendEntityRef[] = [];
    for (let [field, kind] of exportLegendEventFieldKinds) {
        const id = event[field];
        if (typeof id !== "number" || id < 0) continue;
        refs.push({kind, id, name: legendRefName(simulation, {kind, id})});
    }
    return refs;
}

function eventEntityRefsForExport(simulation: CivilizationSimulation, event: LegendEvent): LegendEntityRef[] {
    const refs = [...eventFieldRefsForExport(simulation, event), ...event.entityRefs, ...exportRoadRefsForEvent(simulation, event)];
    return uniqueLegendRefs(refs, refs.length);
}

function compactEventIds(ids: Array<number | undefined>, limit = 18): number[] {
    return uniqueNumberList(ids.filter((id): id is number => id !== undefined && id >= 0)).slice(0, limit);
}

function eventIdsForRecords(records: Array<{eventIds?: number[]; startEventId?: number; endEventId?: number; sourceEventId?: number; resolvedEventId?: number; revealedEventId?: number; transferredEventId?: number; onsetEventId?: number; casualtyEventId?: number; recordedEventId?: number; birthEventId?: number; swornEventId?: number; fulfilledEventId?: number; brokenEventId?: number}>, limit = 18): number[] {
    const ids: number[] = [];
    for (let record of records) {
        ids.push(record.startEventId, record.endEventId, record.sourceEventId, record.resolvedEventId, record.revealedEventId, record.transferredEventId, record.onsetEventId, record.casualtyEventId, record.recordedEventId, record.birthEventId, record.swornEventId, record.fulfilledEventId, record.brokenEventId);
        ids.push(...(record.eventIds ?? []));
    }
    return compactEventIds(ids, limit);
}

function minDefined(values: Array<number | undefined>, fallback: number): number {
    const numeric = values.filter((value): value is number => value !== undefined);
    return numeric.length ? Math.min(...numeric) : fallback;
}

function maxDefined(values: Array<number | undefined>): number | undefined {
    const numeric = values.filter((value): value is number => value !== undefined);
    return numeric.length ? Math.max(...numeric) : undefined;
}

function lifeChapter(
    simulation: CivilizationSimulation,
    agent: Agent,
    kind: LifeChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): LifeChapter {
    return {
        kind,
        title,
        startYear,
        endYear,
        status: endYear === undefined ? "active" : "ended",
        personId: agent.id,
        civilizationId: agent.civilizationId,
        settlementId: agent.settlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 16),
        subjectRefs: uniqueLegendRefs([
            personRef(simulation, agent.id),
            civilizationRef(simulation, agent.civilizationId),
            settlementRef(simulation, agent.settlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 24),
        description,
    };
}

function buildPersonLifeChapters(simulation: CivilizationSimulation, agent: Agent): LifeChapter[] {
    const chapters: LifeChapter[] = [];
    const birthEvents = agent.eventIds.filter(id => simulation.legendEvents[id]?.type === "person-born").slice(0, 1);
    const birth = agent.birthId === undefined ? undefined : simulation.births[agent.birthId];
    const parentRefs = agent.parentIds.slice(0, 2).map(id => personRef(simulation, id));
    const birthEnd = agent.age >= 15 || !agent.alive ? Math.min(agent.bornYear + 14, agent.diedYear ?? simulation.year) : undefined;
    chapters.push(lifeChapter(
        simulation,
        agent,
        "birth-family",
        `${agent.name}'s birth and family`,
        agent.bornYear,
        birthEnd,
        birthEvents,
        [
            ...(birth === undefined ? [] : [birthRef(simulation, birth.id)]),
            ...parentRefs,
            ...(agent.householdId === undefined ? [] : [householdRef(simulation, agent.householdId)]),
            ...(agent.lineageId === undefined ? [] : [lineageRef(simulation, agent.lineageId)]),
        ],
        `${agent.name} entered the records in ${simulation.settlements[agent.settlementId]?.name ?? "an unknown settlement"}${parentRefs.length ? " with parents recorded" : ""}${birth ? ` through ${birth.name}` : ""}.`,
    ));

    const residences = agent.residenceIds.map(id => simulation.residences[id]).filter(Boolean);
    if (residences.length) {
        const first = residences[0];
        const active = residences.find(residence => residence.status === "active") ?? residences[residences.length - 1];
        const refs = [
            residenceRef(simulation, first.id),
            ...(active.id === first.id ? [] : [residenceRef(simulation, active.id)]),
            ...(active.householdId === undefined ? [] : [householdRef(simulation, active.householdId)]),
            ...(active.structureId === undefined ? [] : [structureRef(simulation, active.structureId)]),
        ];
        chapters.push(lifeChapter(
            simulation,
            agent,
            "home",
            `${agent.name}'s homes`,
            first.startYear,
            active.status === "active" ? undefined : active.endYear,
            eventIdsForRecords(residences, 16),
            refs,
            `${agent.name}'s residence record spans ${residences.length} home ${residences.length === 1 ? "chapter" : "chapters"}, ending at ${simulation.settlements[active.settlementId]?.name ?? "an unknown settlement"}.`,
        ));
    }

    const careers = agent.careerIds.map(id => simulation.careers[id]).filter(Boolean);
    const ageMilestones = agent.ageMilestoneIds.map(id => simulation.ageMilestones[id]).filter(Boolean);
    if (careers.length) {
        const first = careers[0];
        const active = careers.find(career => career.status === "active") ?? careers[careers.length - 1];
        const namedCareers = careers.slice(-4).map(career => careerRef(simulation, career.id));
        chapters.push(lifeChapter(
            simulation,
            agent,
            "work",
            `${agent.name}'s work as ${agent.profession}`,
            first.startYear,
            active.status === "active" ? undefined : active.endYear,
            eventIdsForRecords([...careers, ...ageMilestones], 18),
            [
                ...ageMilestones.slice(-3).map(milestone => ageMilestoneRef(simulation, milestone.id)),
                ...namedCareers,
                ...(agent.skillRecordIds.slice(0, 4).map(id => skillRef(simulation, id))),
                ...(active.organizationId === undefined ? [] : [organizationRef(simulation, active.organizationId)]),
                ...(active.officeId === undefined ? [] : [officeRef(simulation, active.officeId)]),
            ],
            `${agent.name}'s working life moved through ${careers.length} career ${careers.length === 1 ? "record" : "records"} and ${ageMilestones.length} age milestone ${ageMilestones.length === 1 ? "record" : "records"}; the current profession is ${agent.profession}.`,
        ));
    }

    const activities = agent.activityIds.map(id => simulation.activities[id]).filter(Boolean);
    const thoughts = agent.thoughtIds.map(id => simulation.thoughts[id]).filter(Boolean);
    const needEpisodes = agent.needEpisodeIds.map(id => simulation.needEpisodes[id]).filter(Boolean);
    const preferences = agent.preferenceIds.map(id => simulation.preferences[id]).filter(Boolean);
    const conversations = simulation.conversations.filter(conversation => conversation.speakerAgentId === agent.id || conversation.listenerAgentId === agent.id);
    if (activities.length || thoughts.length || needEpisodes.length || preferences.length || conversations.length || agent.needStates.length) {
        const activeNeeds = agent.needStates
            .slice()
            .sort((a, b) => b.urgency - a.urgency || a.satisfaction - b.satisfaction || a.kind.localeCompare(b.kind))
            .slice(0, 3)
            .map(need => `${need.kind} (${Math.round(need.urgency * 100)}% urgency)`);
        const favored = preferences
            .slice()
            .sort((a, b) => b.strength - a.strength || a.recordedYear - b.recordedYear || a.id - b.id)
            .slice(0, 3)
            .map(preference => `${preference.sentiment} ${preference.targetName}`);
        chapters.push(lifeChapter(
            simulation,
            agent,
            "daily-life",
            `${agent.name}'s daily life`,
            minDefined([
                ...activities.map(activity => activity.year),
                ...thoughts.map(thought => thought.year),
                ...needEpisodes.map(episode => episode.startedYear),
                ...preferences.map(preference => preference.recordedYear),
                ...conversations.map(conversation => conversation.year),
            ], agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            eventIdsForRecords([...activities, ...thoughts, ...needEpisodes, ...preferences, ...conversations], 18),
            [
                ...activities.slice(-5).map(activity => activityRef(simulation, activity.id)),
                ...needEpisodes.slice(-5).map(episode => needEpisodeRef(simulation, episode.id)),
                ...thoughts.slice(-4).map(thought => thoughtRef(simulation, thought.id)),
                ...preferences.slice(0, 4).map(preference => preferenceRef(simulation, preference.id)),
                ...conversations.slice(-4).map(conversation => conversationRef(simulation, conversation.id)),
            ],
            `${agent.name}'s daily records include ${activities.length} activity ${activities.length === 1 ? "entry" : "entries"}, ${needEpisodes.length} need episode ${needEpisodes.length === 1 ? "record" : "records"}, ${thoughts.length} thought ${thoughts.length === 1 ? "record" : "records"}, ${preferences.length} preference ${preferences.length === 1 ? "record" : "records"}, and ${conversations.length} conversation ${conversations.length === 1 ? "record" : "records"}. ${activeNeeds.length ? `Current pressures: ${activeNeeds.join(", ")}.` : ""} ${favored.length ? `Recorded tastes: ${favored.join(", ")}.` : ""}`,
        ));
    }

    const bonds = agent.socialBondIds.map(id => simulation.socialBonds[id]).filter(Boolean);
    const unions = agent.unionIds.map(id => simulation.unions[id]).filter(Boolean);
    if (bonds.length || unions.length || agent.childIds.length || agent.spouseId !== undefined) {
        const bondYears = [
            ...bonds.map(bond => bond.startedYear),
            ...unions.map(union => union.startedYear),
            ...agent.childIds.map(childId => simulation.agents[childId]?.bornYear),
        ];
        chapters.push(lifeChapter(
            simulation,
            agent,
            "bonds",
            `${agent.name}'s bonds and kin`,
            minDefined(bondYears, agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            eventIdsForRecords([...bonds, ...unions], 16),
            [
                ...bonds.slice(0, 4).map(bond => relationshipRef(simulation, bond.id)),
                ...unions.slice(0, 2).map(union => unionRef(simulation, union.id)),
                ...(agent.spouseId === undefined ? [] : [personRef(simulation, agent.spouseId)]),
                ...agent.childIds.slice(0, 6).map(id => personRef(simulation, id)),
            ],
            `${agent.name}'s personal bonds include ${bonds.length} relationship ${bonds.length === 1 ? "record" : "records"} and ${agent.childIds.length} recorded ${agent.childIds.length === 1 ? "child" : "children"}.`,
        ));
    }

    const adherences = agent.beliefAdherenceIds.map(id => simulation.beliefAdherences[id]).filter(Boolean);
    if (agent.beliefId !== undefined || agent.traditionIds.length || agent.magicRoleIds.length || adherences.length) {
        const faithYears = [
            ...adherences.map(adherence => adherence.startedYear),
            ...agent.traditionIds.map(id => simulation.traditions[id]?.originYear),
            ...agent.magicRoleIds.map(id => simulation.magicRoles[id]?.startedYear),
        ];
        chapters.push(lifeChapter(
            simulation,
            agent,
            "faith-culture",
            `${agent.name}'s beliefs and customs`,
            minDefined(faithYears, agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            eventIdsForRecords(adherences, 14),
            [
                ...(agent.beliefId === undefined ? [] : [beliefRef(simulation, agent.beliefId)]),
                ...agent.beliefAdherenceIds.slice(0, 4).map(id => beliefAdherenceRef(simulation, id)),
                ...agent.traditionIds.slice(0, 4).map(id => traditionRef(simulation, id)),
                ...agent.magicRoleIds.slice(0, 3).map(id => magicRoleRef(simulation, id)),
            ],
            `${agent.name}'s cultural record connects them to ${agent.traditionIds.length} tradition ${agent.traditionIds.length === 1 ? "record" : "records"} and ${agent.magicRoleIds.length} magic role ${agent.magicRoleIds.length === 1 ? "record" : "records"}.`,
        ));
    }

    const memberships = agent.membershipIds.map(id => simulation.memberships[id]).filter(Boolean);
    const officeTerms = agent.officeTermIds.map(id => simulation.officeTerms[id]).filter(Boolean);
    if (memberships.length || officeTerms.length || agent.officeIds.length) {
        chapters.push(lifeChapter(
            simulation,
            agent,
            "public-life",
            `${agent.name}'s public life`,
            minDefined([...memberships.map(membership => membership.startedYear), ...officeTerms.map(term => term.startedYear)], agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            eventIdsForRecords([...memberships, ...officeTerms], 18),
            [
                ...memberships.slice(0, 4).map(membership => membershipRef(simulation, membership.id)),
                ...officeTerms.slice(0, 4).map(term => officeTermRef(simulation, term.id)),
                ...agent.officeIds.slice(0, 4).map(id => officeRef(simulation, id)),
            ],
            `${agent.name}'s public record includes ${memberships.length} membership ${memberships.length === 1 ? "term" : "terms"} and ${officeTerms.length} office ${officeTerms.length === 1 ? "term" : "terms"}.`,
        ));
    }

    const cases = agent.caseIds.map(id => simulation.cases[id]).filter(Boolean);
    const testimonies = agent.testimonyIds.map(id => simulation.testimonies[id]).filter(Boolean);
    const schemes = agent.schemeIds.map(id => simulation.schemes[id]).filter(Boolean);
    const feuds = agent.feudIds.map(id => simulation.feuds[id]).filter(Boolean);
    const oaths = agent.oathIds.map(id => simulation.oaths[id]).filter(Boolean);
    if (cases.length || testimonies.length || schemes.length || feuds.length || oaths.length) {
        chapters.push(lifeChapter(
            simulation,
            agent,
            "law-intrigue",
            `${agent.name}'s law, oaths, and intrigue`,
            minDefined([
                ...cases.map(legalCase => legalCase.openedYear),
                ...testimonies.map(testimony => testimony.year),
                ...schemes.map(scheme => scheme.startedYear),
                ...feuds.map(feud => feud.startedYear),
                ...oaths.map(oath => oath.swornYear),
            ], agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            eventIdsForRecords([...cases, ...testimonies, ...schemes, ...feuds, ...oaths], 18),
            [
                ...cases.slice(0, 4).map(legalCase => caseRef(simulation, legalCase.id)),
                ...testimonies.slice(0, 3).map(testimony => testimonyRef(simulation, testimony.id)),
                ...schemes.slice(0, 4).map(scheme => schemeRef(simulation, scheme.id)),
                ...feuds.slice(0, 3).map(feud => feudRef(simulation, feud.id)),
                ...oaths.slice(0, 3).map(oath => oathRef(simulation, oath.id)),
            ],
            `${agent.name}'s contested record includes ${cases.length} case ${cases.length === 1 ? "record" : "records"}, ${schemes.length} scheme ${schemes.length === 1 ? "record" : "records"}, and ${feuds.length} feud ${feuds.length === 1 ? "record" : "records"}.`,
        ));
    }

    const injuries = agent.injuryIds.map(id => simulation.injuries[id]).filter(Boolean);
    const illnesses = agent.illnessIds.map(id => simulation.illnesses[id]).filter(Boolean);
    const battleParticipations = agent.battleParticipationIds.map(id => simulation.battleParticipations[id]).filter(Boolean);
    if (injuries.length || illnesses.length || battleParticipations.length) {
        chapters.push(lifeChapter(
            simulation,
            agent,
            "hardship",
            `${agent.name}'s hardships`,
            minDefined([
                ...injuries.map(injury => injury.year),
                ...illnesses.map(illness => illness.onsetYear),
                ...battleParticipations.map(participation => simulation.battles[participation.battleId]?.year),
            ], agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            eventIdsForRecords([...injuries, ...illnesses, ...battleParticipations], 18),
            [
                ...injuries.slice(0, 4).map(injury => injuryRef(simulation, injury.id)),
                ...illnesses.slice(0, 4).map(illness => illnessRef(simulation, illness.id)),
                ...battleParticipations.slice(0, 4).map(participation => battleParticipationRef(simulation, participation.id)),
                ...agent.battleIds.slice(0, 4).map(id => battleRef(simulation, id)),
            ],
            `${agent.name}'s hardship record includes ${injuries.length} injur${injuries.length === 1 ? "y" : "ies"}, ${illnesses.length} illness ${illnesses.length === 1 ? "case" : "cases"}, and ${battleParticipations.length} battle role ${battleParticipations.length === 1 ? "record" : "records"}.`,
        ));
    }

    const artifacts = simulation.artifacts.filter(artifact => artifact.creatorAgentId === agent.id || artifact.ownerAgentId === agent.id);
    const holdings = agent.holdingIds.map(id => simulation.holdings[id]).filter(Boolean);
    const belongings = agent.belongingIds.map(id => simulation.belongings[id]).filter(Boolean);
    const projects = agent.projectIds.map(id => simulation.projects[id]).filter(Boolean);
    if (agent.writtenWorkIds.length || artifacts.length || holdings.length || belongings.length || projects.length || agent.epithets.length) {
        chapters.push(lifeChapter(
            simulation,
            agent,
            "works-legacy",
            `${agent.name}'s works and legacy`,
            minDefined([
                ...agent.writtenWorkIds.map(id => simulation.writtenWorks[id]?.year),
                ...artifacts.map(artifact => artifact.createdYear),
                ...holdings.map(holding => holding.foundedYear),
                ...belongings.map(belonging => belonging.acquiredYear),
                ...projects.map(project => project.year),
                ...agent.epithets.map(epithet => epithet.year),
            ], agent.bornYear),
            agent.alive ? undefined : agent.diedYear,
            compactEventIds([
                ...eventIdsForRecords([...holdings, ...belongings, ...projects], 12),
                ...agent.writtenWorkIds.flatMap(id => simulation.writtenWorks[id]?.eventIds ?? []),
                ...artifacts.flatMap(artifact => artifact.eventIds),
                ...agent.epithets.map(epithet => epithet.sourceEventId),
            ], 18),
            [
                ...agent.writtenWorkIds.slice(0, 4).map(id => writtenWorkRef(simulation, id)),
                ...artifacts.slice(0, 4).map(artifact => artifactRef(simulation, artifact.id)),
                ...holdings.slice(0, 4).map(holding => holdingRef(simulation, holding.id)),
                ...belongings.slice(0, 4).map(belonging => belongingRef(simulation, belonging.id)),
                ...projects.slice(0, 4).map(project => projectRef(simulation, project.id)),
            ],
            `${agent.name}'s lasting record includes ${agent.writtenWorkIds.length} written ${agent.writtenWorkIds.length === 1 ? "work" : "works"}, ${artifacts.length} artifact ${artifacts.length === 1 ? "link" : "links"}, and ${agent.epithets.length} epithet ${agent.epithets.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (!agent.alive && agent.diedYear !== undefined) {
        const memorials = agent.memorialIds.map(id => simulation.memorials[id]).filter(Boolean);
        const burials = agent.burialIds.map(id => simulation.burials[id]).filter(Boolean);
        const estates = simulation.estates.filter(estate => estate.decedentAgentId === agent.id);
        const deathEvents = agent.eventIds.filter(id => simulation.legendEvents[id]?.type === "person-died" || simulation.legendEvents[id]?.type === "battle-casualty");
        chapters.push(lifeChapter(
            simulation,
            agent,
            "death",
            `${agent.name}'s death and remembrance`,
            agent.diedYear,
            agent.diedYear,
            compactEventIds([...deathEvents, ...eventIdsForRecords([...memorials, ...burials, ...estates], 10)], 14),
            [
                ...memorials.slice(0, 4).map(memorial => memorialRef(simulation, memorial.id)),
                ...burials.slice(0, 4).map(burial => burialRef(simulation, burial.id)),
                ...estates.slice(0, 4).map(estate => estateRef(simulation, estate.id)),
                ...(agent.lineageId === undefined ? [] : [lineageRef(simulation, agent.lineageId)]),
                ...(agent.householdId === undefined ? [] : [householdRef(simulation, agent.householdId)]),
            ],
            `${agent.name} died in ${simulation.settlements[agent.settlementId]?.name ?? "an unknown settlement"} at age ${agent.age}; ${memorials.length} memorial ${memorials.length === 1 ? "record" : "records"}, ${burials.length} burial ${burials.length === 1 ? "record" : "records"}, and ${estates.length} estate ${estates.length === 1 ? "record" : "records"} preserve the death in the archive.`,
        ));
    }

    return chapters
        .sort((a, b) => a.startYear - b.startYear || a.kind.localeCompare(b.kind))
        .slice(0, 12);
}

function relationshipChapter(
    simulation: CivilizationSimulation,
    bond: SocialBond,
    kind: RelationshipChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): RelationshipChapter {
    return {
        kind,
        title,
        startYear,
        endYear,
        status: endYear === undefined ? "active" : "ended",
        relationshipId: bond.id,
        civilizationId: bond.civilizationId,
        settlementId: bond.settlementId,
        agentIds: [...bond.agentIds] as [number, number],
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            relationshipRef(simulation, bond.id),
            ...bond.agentIds.map(id => personRef(simulation, id)),
            settlementRef(simulation, bond.settlementId),
            civilizationRef(simulation, bond.civilizationId),
            ...(bond.organizationId === undefined ? [] : [organizationRef(simulation, bond.organizationId)]),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function relationshipRelatedRecords(simulation: CivilizationSimulation, bond: SocialBond) {
    return {
        milestones: bond.milestoneIds.map(id => simulation.relationshipMilestones[id]).filter(Boolean),
        socialClaims: simulation.socialClaims.filter(claim =>
            claim.relationshipId === bond.id
            || claim.subjectRefs.some(ref => ref.kind === "relationship" && ref.id === bond.id)
        ),
        conversations: simulation.conversations.filter(conversation => conversation.relationshipId === bond.id),
        obligations: simulation.obligations.filter(obligation =>
            obligation.relationshipId === bond.id
            || obligation.subjectRefs.some(ref => ref.kind === "relationship" && ref.id === bond.id)
        ),
        apprenticeships: simulation.apprenticeships.filter(apprenticeship => apprenticeship.relationshipId === bond.id),
        memories: simulation.memories.filter(memory => memory.subjectRefs.some(ref => ref.kind === "relationship" && ref.id === bond.id)),
        opinions: simulation.opinions.filter(opinion => opinion.subjectRefs.some(ref => ref.kind === "relationship" && ref.id === bond.id)),
    };
}

function buildRelationshipChapters(simulation: CivilizationSimulation, bond: SocialBond): RelationshipChapter[] {
    const chapters: RelationshipChapter[] = [];
    const related = relationshipRelatedRecords(simulation, bond);
    const first = simulation.agents[bond.agentIds[0]];
    const second = simulation.agents[bond.agentIds[1]];
    const firstName = first?.name ?? "one person";
    const secondName = second?.name ?? "another person";
    const relationshipName = `${relationshipKindLabel(bond.kind)} of ${firstName} and ${secondName}`;
    const formedMilestones = related.milestones.filter(milestone => milestone.kind === "formed");
    const firstMilestone = formedMilestones[0] ?? related.milestones[0];
    chapters.push(relationshipChapter(
        simulation,
        bond,
        "formation",
        `${relationshipName}'s formation`,
        bond.startedYear,
        firstMilestone?.year,
        compactEventIds([...bond.eventIds, ...formedMilestones.map(milestone => milestone.sourceEventId)], 14),
        [
            ...(firstMilestone ? [relationshipMilestoneRef(simulation, firstMilestone.id)] : []),
            ...(bond.organizationId === undefined ? [] : [organizationRef(simulation, bond.organizationId)]),
        ],
        `${relationshipName} began in ${simulation.settlements[bond.settlementId]?.name ?? "an unknown place"} as ${bond.kind}. Its current recorded state is ${socialBondStatus(bond)} with strength ${Math.round(bond.strength * 1000) / 1000}, trust ${Math.round(bond.trust * 1000) / 1000}, and tension ${Math.round(bond.tension * 1000) / 1000}.`,
    ));

    const turningMilestones = related.milestones.filter(milestone => milestone.kind !== "formed" && milestone.kind !== "ended");
    if (turningMilestones.length || related.memories.length || related.opinions.length) {
        chapters.push(relationshipChapter(
            simulation,
            bond,
            "turning-points",
            `${relationshipName}'s turning points`,
            minDefined([
                ...turningMilestones.map(milestone => milestone.year),
                ...related.memories.map(memory => memory.year),
                ...related.opinions.map(opinion => opinion.year),
            ], bond.startedYear),
            bond.active ? undefined : bond.endedYear,
            eventIdsForRecords([...turningMilestones, ...related.memories, ...related.opinions], 18),
            [
                ...turningMilestones.slice(-6).map(milestone => relationshipMilestoneRef(simulation, milestone.id)),
                ...related.memories.slice(-4).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-4).map(opinion => opinionRef(simulation, opinion.id)),
            ],
            `${relationshipName} has ${turningMilestones.length} turning milestone ${turningMilestones.length === 1 ? "record" : "records"}, ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}, and ${related.opinions.length} opinion ${related.opinions.length === 1 ? "record" : "records"}. The latest status is ${socialBondStatus(bond)}.`,
        ));
    }

    if (related.conversations.length) {
        chapters.push(relationshipChapter(
            simulation,
            bond,
            "conversations",
            `${relationshipName}'s conversations`,
            minDefined(related.conversations.map(conversation => conversation.year), bond.startedYear),
            undefined,
            eventIdsForRecords(related.conversations, 18),
            related.conversations.slice(-8).map(conversation => conversationRef(simulation, conversation.id)),
            `${relationshipName} is tied to ${related.conversations.length} conversation ${related.conversations.length === 1 ? "record" : "records"}, carrying the bond through talk, lessons, rumors, secrets, memories, faith, traditions, or artifacts.`,
        ));
    }

    if (related.socialClaims.length || related.obligations.length || related.apprenticeships.length) {
        chapters.push(relationshipChapter(
            simulation,
            bond,
            "claims-obligations",
            `${relationshipName}'s claims and duties`,
            minDefined([
                ...related.socialClaims.map(claim => claim.year),
                ...related.obligations.map(obligation => obligation.createdYear),
                ...related.apprenticeships.map(apprenticeship => apprenticeship.startedYear),
            ], bond.startedYear),
            undefined,
            eventIdsForRecords([...related.socialClaims, ...related.obligations, ...related.apprenticeships], 18),
            [
                ...related.socialClaims.slice(-6).map(claim => socialClaimRef(simulation, claim.id)),
                ...related.obligations.slice(-6).map(obligation => obligationRef(simulation, obligation.id)),
                ...related.apprenticeships.slice(-4).map(apprenticeship => apprenticeshipRef(simulation, apprenticeship.id)),
            ],
            `${relationshipName} carries ${related.socialClaims.length} favor or grudge ${related.socialClaims.length === 1 ? "claim" : "claims"}, ${related.obligations.length} obligation ${related.obligations.length === 1 ? "record" : "records"}, and ${related.apprenticeships.length} apprenticeship ${related.apprenticeships.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (!bond.active || bond.endedYear !== undefined) {
        const endedMilestones = related.milestones.filter(milestone => milestone.kind === "ended");
        chapters.push(relationshipChapter(
            simulation,
            bond,
            "ending",
            `${relationshipName}'s ending`,
            bond.endedYear ?? endedMilestones[0]?.year ?? bond.startedYear,
            bond.endedYear ?? endedMilestones[0]?.year,
            compactEventIds([...endedMilestones.map(milestone => milestone.sourceEventId), ...bond.eventIds], 14),
            endedMilestones.slice(-4).map(milestone => relationshipMilestoneRef(simulation, milestone.id)),
            `${relationshipName} is recorded as ended${bond.endedReason ? ` by ${bond.endedReason}` : ""}. Its final status was ${socialBondStatus(bond)}.`,
        ));
    }

    const order: Record<RelationshipChapterKind, number> = {
        formation: 0,
        "turning-points": 1,
        conversations: 2,
        "claims-obligations": 3,
        ending: 4,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || order[a.kind] - order[b.kind])
        .slice(0, 8);
}

function placeChapter(
    simulation: CivilizationSimulation,
    settlement: Settlement,
    kind: PlaceChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): PlaceChapter {
    const chapterStartYear = Math.max(settlement.foundedYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        settlementId: settlement.id,
        civilizationId: settlement.civilizationId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            settlementRef(simulation, settlement.id),
            civilizationRef(simulation, settlement.civilizationId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 28),
        description,
    };
}

function settlementConflictRecords(simulation: CivilizationSimulation, settlement: Settlement): Conflict[] {
    return simulation.conflicts.filter(conflict =>
        conflict.targetSettlementId === settlement.id
        || conflict.contestedSettlementIds.includes(settlement.id)
        || conflict.capturedSettlementIds.includes(settlement.id)
    );
}

function settlementRoadRecords(simulation: CivilizationSimulation, settlement: Settlement): Road[] {
    return simulation.roads.filter(road => road.fromSettlementId === settlement.id || road.toSettlementId === settlement.id);
}

function settlementJourneyRecords(simulation: CivilizationSimulation, settlement: Settlement): Journey[] {
    return simulation.journeys.filter(journey => journey.fromSettlementId === settlement.id || journey.toSettlementId === settlement.id);
}

function buildSettlementPlaceChapters(simulation: CivilizationSimulation, settlement: Settlement): PlaceChapter[] {
    const chapters: PlaceChapter[] = [];
    const controls = settlement.controlIds.map(id => simulation.settlementControls[id]).filter(Boolean);
    const activeControl = controls.find(control => control.status === "active") ?? controls[controls.length - 1];
    chapters.push(placeChapter(
        simulation,
        settlement,
        "founding-control",
        `${settlement.name}'s founding and rule`,
        settlement.foundedYear,
        activeControl?.status === "active" ? undefined : activeControl?.endedYear,
        eventIdsForRecords(controls, 18),
        controls.slice(0, 6).map(control => settlementControlRef(simulation, control.id)),
        `${settlement.name} was founded in year ${settlement.foundedYear} and has ${controls.length} recorded control ${controls.length === 1 ? "term" : "terms"}. It is currently held by ${simulation.civilizations[settlement.civilizationId]?.name ?? "an unknown civilization"}.`,
    ));

    const localAgents = simulation.agents.filter(agent => agent.settlementId === settlement.id);
    const households = simulation.households.filter(household => household.settlementId === settlement.id);
    const lineages = simulation.lineages.filter(lineage => lineage.originSettlementId === settlement.id || lineage.householdIds.some(id => simulation.households[id]?.settlementId === settlement.id));
    if (localAgents.length || households.length || lineages.length) {
        const notablePeople = localAgents
            .slice()
            .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
            .slice(0, 8);
        chapters.push(placeChapter(
            simulation,
            settlement,
            "people-families",
            `${settlement.name}'s people and families`,
            minDefined([
                ...localAgents.map(agent => agent.bornYear),
                ...households.map(household => household.foundedYear),
                ...lineages.map(lineage => lineage.foundedYear),
            ], settlement.foundedYear),
            undefined,
            compactEventIds([
                ...notablePeople.flatMap(agent => agent.eventIds.slice(0, 4)),
                ...eventIdsForRecords(households, 12),
                ...lineages.flatMap(lineage => lineage.eventIds),
            ], 18),
            [
                ...notablePeople.map(agent => personRef(simulation, agent.id)),
                ...households.slice(0, 6).map(household => householdRef(simulation, household.id)),
                ...lineages.slice(0, 6).map(lineage => lineageRef(simulation, lineage.id)),
            ],
            `${settlement.name} records ${localAgents.filter(agent => agent.alive).length} living residents, ${households.length} household ${households.length === 1 ? "record" : "records"}, and ${lineages.length} lineage ${lineages.length === 1 ? "link" : "links"}.`,
        ));
    }

    const structures = settlement.structureIds.map(id => simulation.structures[id]).filter(Boolean);
    const projects = simulation.projects.filter(project => project.settlementId === settlement.id);
    const holdings = simulation.holdings.filter(holding => holding.settlementId === settlement.id);
    const localArtifacts = simulation.artifacts.filter(artifact => artifact.settlementId === settlement.id || artifact.ownerSettlementId === settlement.id);
    if (structures.length || projects.length || holdings.length || localArtifacts.length) {
        const latestProjects = projects.slice().sort((a, b) => b.year - a.year || a.id - b.id).slice(0, 6);
        chapters.push(placeChapter(
            simulation,
            settlement,
            "building-work",
            `${settlement.name}'s buildings and work`,
            minDefined([
                ...structures.map(structure => structure.builtYear),
                ...projects.map(project => project.year),
                ...holdings.map(holding => holding.foundedYear),
                ...localArtifacts.map(artifact => artifact.createdYear),
            ], settlement.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...structures, ...latestProjects, ...holdings], 18),
                ...localArtifacts.flatMap(artifact => artifact.eventIds),
            ], 20),
            [
                ...structures.slice(0, 8).map(structure => structureRef(simulation, structure.id)),
                ...latestProjects.map(project => projectRef(simulation, project.id)),
                ...holdings.slice(0, 6).map(holding => holdingRef(simulation, holding.id)),
                ...localArtifacts.slice(0, 6).map(artifact => artifactRef(simulation, artifact.id)),
            ],
            `${settlement.name}'s built record includes ${structures.length} structure ${structures.length === 1 ? "entry" : "entries"}, ${projects.length} work project ${projects.length === 1 ? "record" : "records"}, ${holdings.length} holding ${holdings.length === 1 ? "record" : "records"}, and ${localArtifacts.length} artifact ${localArtifacts.length === 1 ? "link" : "links"}.`,
        ));
    }

    const roads = settlementRoadRecords(simulation, settlement);
    const journeys = settlementJourneyRecords(simulation, settlement);
    if (roads.length || journeys.length) {
        chapters.push(placeChapter(
            simulation,
            settlement,
            "roads-journeys",
            `${settlement.name}'s roads and journeys`,
            minDefined([
                ...roads.map(road => road.openedYear),
                ...journeys.map(journey => journey.year),
            ], settlement.foundedYear),
            undefined,
            eventIdsForRecords(journeys, 18),
            [
                ...roads.slice(0, 8).map(road => roadRef(simulation, road.id)),
                ...journeys.slice(-8).map(journey => journeyRef(simulation, journey.id)),
            ],
            `${settlement.name} is connected by ${roads.length} road ${roads.length === 1 ? "route" : "routes"} and appears in ${journeys.length} journey ${journeys.length === 1 ? "record" : "records"}.`,
        ));
    }

    const beliefs = simulation.beliefs.filter(belief => belief.originSettlementId === settlement.id);
    const sacredSites = simulation.sacredSites.filter(site => site.settlementId === settlement.id);
    const ceremonies = simulation.ceremonies.filter(ceremony => ceremony.settlementId === settlement.id);
    const magicRoles = simulation.magicRoles.filter(role => role.settlementId === settlement.id);
    const prophecies = simulation.prophecies.filter(prophecy => prophecy.settlementId === settlement.id || prophecy.targetSettlementId === settlement.id);
    const goals = simulation.civilizationGoals.filter(goal => goal.settlementId === settlement.id || goal.targetSettlementId === settlement.id);
    const traditions = settlement.traditionIds.map(id => simulation.traditions[id]).filter(Boolean);
    if (beliefs.length || sacredSites.length || ceremonies.length || traditions.length || magicRoles.length || prophecies.length || goals.length) {
        chapters.push(placeChapter(
            simulation,
            settlement,
            "faith-culture",
            `${settlement.name}'s faith and customs`,
            minDefined([
                ...beliefs.map(belief => belief.foundedYear),
                ...sacredSites.map(site => site.foundedYear),
                ...ceremonies.map(ceremony => ceremony.year),
                ...traditions.map(tradition => tradition.originYear),
                ...magicRoles.map(role => role.startedYear),
                ...prophecies.map(prophecy => prophecy.year),
                ...goals.map(goal => goal.startedYear),
            ], settlement.foundedYear),
            undefined,
            eventIdsForRecords([...beliefs, ...sacredSites, ...ceremonies, ...traditions, ...magicRoles, ...prophecies, ...goals], 20),
            [
                ...beliefs.slice(0, 5).map(belief => beliefRef(simulation, belief.id)),
                ...traditions.slice(0, 5).map(tradition => traditionRef(simulation, tradition.id)),
                ...sacredSites.slice(0, 5).map(site => sacredSiteRef(simulation, site.id)),
                ...magicRoles.slice(0, 4).map(role => magicRoleRef(simulation, role.id)),
                ...prophecies.slice(0, 4).map(prophecy => prophecyRef(simulation, prophecy.id)),
                ...goals.slice(0, 4).map(goal => civilizationGoalRef(simulation, goal.id)),
                ...ceremonies.slice(-4).map(ceremony => ceremonyRef(simulation, ceremony.id)),
            ],
            `${settlement.name}'s cultural life includes ${beliefs.length} founded belief ${beliefs.length === 1 ? "record" : "records"}, ${traditions.length} tradition ${traditions.length === 1 ? "record" : "records"}, ${sacredSites.length} sacred site ${sacredSites.length === 1 ? "record" : "records"}, and ${ceremonies.length} ceremony ${ceremonies.length === 1 ? "record" : "records"}.`,
        ));
    }

    const offices = simulation.offices.filter(office => office.settlementId === settlement.id);
    const officeTerms = simulation.officeTerms.filter(term => term.settlementId === settlement.id);
    const laws = simulation.laws.filter(law => law.settlementId === settlement.id);
    const cases = simulation.cases.filter(legalCase => legalCase.settlementId === settlement.id);
    const testimonies = simulation.testimonies.filter(testimony => testimony.settlementId === settlement.id);
    const schemes = simulation.schemes.filter(scheme => scheme.settlementId === settlement.id);
    const oaths = simulation.oaths.filter(oath => oath.settlementId === settlement.id || oath.targetSettlementId === settlement.id);
    const obligations = simulation.obligations.filter(obligation => obligation.settlementId === settlement.id);
    if (offices.length || officeTerms.length || laws.length || cases.length || testimonies.length || schemes.length || oaths.length || obligations.length) {
        chapters.push(placeChapter(
            simulation,
            settlement,
            "law-politics",
            `${settlement.name}'s law and politics`,
            minDefined([
                ...offices.map(office => office.createdYear),
                ...officeTerms.map(term => term.startedYear),
                ...laws.map(law => law.enactedYear),
                ...cases.map(legalCase => legalCase.openedYear),
                ...testimonies.map(testimony => testimony.year),
                ...schemes.map(scheme => scheme.startedYear),
                ...oaths.map(oath => oath.swornYear),
                ...obligations.map(obligation => obligation.createdYear),
            ], settlement.foundedYear),
            undefined,
            eventIdsForRecords([...offices, ...officeTerms, ...laws, ...cases, ...testimonies, ...schemes, ...oaths, ...obligations], 22),
            [
                ...offices.slice(0, 5).map(office => officeRef(simulation, office.id)),
                ...officeTerms.slice(-5).map(term => officeTermRef(simulation, term.id)),
                ...laws.slice(0, 5).map(law => lawRef(simulation, law.id)),
                ...cases.slice(-5).map(legalCase => caseRef(simulation, legalCase.id)),
                ...schemes.slice(-5).map(scheme => schemeRef(simulation, scheme.id)),
                ...oaths.slice(-5).map(oath => oathRef(simulation, oath.id)),
                ...obligations.slice(-5).map(obligation => obligationRef(simulation, obligation.id)),
            ],
            `${settlement.name}'s civic archive includes ${offices.length} office ${offices.length === 1 ? "record" : "records"}, ${laws.length} law ${laws.length === 1 ? "record" : "records"}, ${cases.length} legal case ${cases.length === 1 ? "record" : "records"}, ${schemes.length} scheme ${schemes.length === 1 ? "record" : "records"}, and ${oaths.length} oath ${oaths.length === 1 ? "record" : "records"}.`,
        ));
    }

    const conflicts = settlementConflictRecords(simulation, settlement);
    const battles = simulation.battles.filter(battle => battle.settlementId === settlement.id);
    const injuries = simulation.injuries.filter(injury => injury.settlementId === settlement.id);
    const illnesses = simulation.illnesses.filter(illness => illness.settlementId === settlement.id);
    const memorials = simulation.memorials.filter(memorial => memorial.settlementId === settlement.id);
    const feuds = simulation.feuds.filter(feud => feud.settlementId === settlement.id);
    const secrets = simulation.secrets.filter(secret => secret.settlementId === settlement.id);
    const rumors = simulation.rumors.filter(rumor => rumor.originSettlementId === settlement.id || rumor.spreadSettlementIds.includes(settlement.id));
    if (conflicts.length || battles.length || injuries.length || illnesses.length || memorials.length || feuds.length || secrets.length || rumors.length) {
        chapters.push(placeChapter(
            simulation,
            settlement,
            "conflict-hardship",
            `${settlement.name}'s conflict and hardship`,
            minDefined([
                ...conflicts.map(conflict => conflict.startedYear),
                ...battles.map(battle => battle.year),
                ...injuries.map(injury => injury.year),
                ...illnesses.map(illness => illness.onsetYear),
                ...memorials.map(memorial => memorial.year),
                ...feuds.map(feud => feud.startedYear),
                ...secrets.map(secret => secret.year),
                ...rumors.map(rumor => rumor.year),
            ], settlement.foundedYear),
            undefined,
            eventIdsForRecords([...conflicts, ...battles, ...injuries, ...illnesses, ...memorials, ...feuds, ...secrets, ...rumors], 22),
            [
                ...conflicts.slice(0, 5).map(conflict => conflictRef(simulation, conflict.id)),
                ...battles.slice(-5).map(battle => battleRef(simulation, battle.id)),
                ...injuries.slice(-4).map(injury => injuryRef(simulation, injury.id)),
                ...illnesses.slice(-4).map(illness => illnessRef(simulation, illness.id)),
                ...memorials.slice(-5).map(memorial => memorialRef(simulation, memorial.id)),
                ...feuds.slice(-4).map(feud => feudRef(simulation, feud.id)),
                ...secrets.slice(-4).map(secret => secretRef(simulation, secret.id)),
                ...rumors.slice(-4).map(rumor => rumorRef(simulation, rumor.id)),
            ],
            `${settlement.name}'s hardship record includes ${conflicts.length} conflict ${conflicts.length === 1 ? "record" : "records"}, ${battles.length} battle ${battles.length === 1 ? "record" : "records"}, ${injuries.length} injury ${injuries.length === 1 ? "record" : "records"}, ${illnesses.length} illness ${illnesses.length === 1 ? "case" : "cases"}, and ${memorials.length} memorial ${memorials.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chronicles = simulation.chronicles.filter(chronicle => chronicle.settlementId === settlement.id);
    const writtenWorks = simulation.writtenWorks.filter(work => work.settlementId === settlement.id);
    const memories = simulation.memories.filter(memory => memory.settlementId === settlement.id);
    const thoughts = simulation.thoughts.filter(thought => thought.settlementId === settlement.id);
    const opinions = simulation.opinions.filter(opinion => opinion.settlementId === settlement.id);
    const conversations = simulation.conversations.filter(conversation => conversation.settlementId === settlement.id);
    if (chronicles.length || writtenWorks.length || memories.length || thoughts.length || opinions.length || conversations.length || localArtifacts.length) {
        chapters.push(placeChapter(
            simulation,
            settlement,
            "memory-legacy",
            `${settlement.name}'s memory and legacy`,
            minDefined([
                ...chronicles.map(chronicle => chronicle.year),
                ...writtenWorks.map(work => work.year),
                ...memories.map(memory => memory.year),
                ...thoughts.map(thought => thought.year),
                ...opinions.map(opinion => opinion.year),
                ...conversations.map(conversation => conversation.year),
                ...localArtifacts.map(artifact => artifact.createdYear),
            ], settlement.foundedYear),
            undefined,
            eventIdsForRecords([...chronicles, ...writtenWorks, ...memories, ...thoughts, ...opinions, ...conversations], 22),
            [
                ...chronicles.slice(-6).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
                ...memories.slice(-6).map(memory => memoryRef(simulation, memory.id)),
                ...thoughts.slice(-5).map(thought => thoughtRef(simulation, thought.id)),
                ...opinions.slice(-5).map(opinion => opinionRef(simulation, opinion.id)),
                ...conversations.slice(-5).map(conversation => conversationRef(simulation, conversation.id)),
                ...localArtifacts.slice(0, 5).map(artifact => artifactRef(simulation, artifact.id)),
            ],
            `${settlement.name}'s memory layer includes ${chronicles.length} chronicle ${chronicles.length === 1 ? "record" : "records"}, ${writtenWorks.length} written ${writtenWorks.length === 1 ? "work" : "works"}, ${memories.length} memory ${memories.length === 1 ? "record" : "records"}, and ${conversations.length} conversation ${conversations.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<PlaceChapterKind, number> = {
        "founding-control": 0,
        "people-families": 1,
        "building-work": 2,
        "roads-journeys": 3,
        "faith-culture": 4,
        "law-politics": 5,
        "conflict-hardship": 6,
        "memory-legacy": 7,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 10);
}

function artifactChapter(
    simulation: CivilizationSimulation,
    artifact: Artifact,
    kind: ArtifactChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): ArtifactChapter {
    return {
        kind,
        title,
        startYear,
        endYear,
        status: endYear === undefined ? "active" : "ended",
        artifactId: artifact.id,
        civilizationId: artifact.civilizationId,
        settlementId: artifact.ownerSettlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            artifactRef(simulation, artifact.id),
            civilizationRef(simulation, artifact.civilizationId),
            settlementRef(simulation, artifact.ownerSettlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function provenanceRefs(simulation: CivilizationSimulation, entries: ArtifactProvenanceEntry[]): LegendEntityRef[] {
    const refs: LegendEntityRef[] = [];
    for (let entry of entries) {
        refs.push(civilizationRef(simulation, entry.civilizationId));
        refs.push(settlementRef(simulation, entry.settlementId));
        if (entry.previousCivilizationId !== undefined) refs.push(civilizationRef(simulation, entry.previousCivilizationId));
        if (entry.previousSettlementId !== undefined) refs.push(settlementRef(simulation, entry.previousSettlementId));
        if (entry.previousOwnerAgentId !== undefined) refs.push(personRef(simulation, entry.previousOwnerAgentId));
        if (entry.ownerAgentId !== undefined) refs.push(personRef(simulation, entry.ownerAgentId));
        if (entry.actorAgentId !== undefined) refs.push(personRef(simulation, entry.actorAgentId));
        if (entry.recipientAgentId !== undefined) refs.push(personRef(simulation, entry.recipientAgentId));
        if (entry.creatorAgentId !== undefined) refs.push(personRef(simulation, entry.creatorAgentId));
        if (entry.structureId !== undefined) refs.push(structureRef(simulation, entry.structureId));
        if (entry.previousStructureId !== undefined) refs.push(structureRef(simulation, entry.previousStructureId));
        if (entry.organizationId !== undefined) refs.push(organizationRef(simulation, entry.organizationId));
        if (entry.beliefId !== undefined) refs.push(beliefRef(simulation, entry.beliefId));
        if (entry.projectId !== undefined) refs.push(projectRef(simulation, entry.projectId));
        if (entry.journeyId !== undefined) refs.push(journeyRef(simulation, entry.journeyId));
        if (entry.sacredSiteId !== undefined) refs.push(sacredSiteRef(simulation, entry.sacredSiteId));
        if (entry.battleId !== undefined) refs.push(battleRef(simulation, entry.battleId));
        refs.push(eventRef(simulation, entry.eventId));
    }
    return uniqueLegendRefs(refs, 24);
}

function artifactRelatedRecords(simulation: CivilizationSimulation, artifact: Artifact) {
    return {
        journeys: simulation.journeys.filter(journey => journey.artifactIds.includes(artifact.id)),
        battles: simulation.battles.filter(battle => battle.capturedArtifactIds.includes(artifact.id)),
        ceremonies: simulation.ceremonies.filter(ceremony => ceremony.artifactIds.includes(artifact.id)),
        projects: simulation.projects.filter(project => project.artifactId === artifact.id),
        ambitions: simulation.ambitions.filter(ambition => ambition.artifactId === artifact.id),
        oaths: simulation.oaths.filter(oath => oath.targetArtifactId === artifact.id || oath.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        obligations: simulation.obligations.filter(obligation => obligation.artifactId === artifact.id || obligation.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        socialClaims: simulation.socialClaims.filter(claim => claim.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        chronicles: simulation.chronicles.filter(chronicle => chronicle.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        writtenWorks: simulation.writtenWorks.filter(work => work.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        memories: simulation.memories.filter(memory => memory.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        thoughts: simulation.thoughts.filter(thought => thought.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        opinions: simulation.opinions.filter(opinion => opinion.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        conversations: simulation.conversations.filter(conversation => conversation.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        rumors: simulation.rumors.filter(rumor => rumor.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
        secrets: simulation.secrets.filter(secret => secret.subjectRefs.some(ref => ref.kind === "artifact" && ref.id === artifact.id)),
    };
}

function buildArtifactChapters(simulation: CivilizationSimulation, artifact: Artifact): ArtifactChapter[] {
    const chapters: ArtifactChapter[] = [];
    const provenance = artifact.provenance.slice().sort((a, b) => a.year - b.year || a.eventId - b.eventId);
    const creationEntries = provenance.filter(entry => entry.kind === "created");
    const firstEntry = creationEntries[0] ?? provenance[0];
    chapters.push(artifactChapter(
        simulation,
        artifact,
        "creation",
        `${artifact.name}'s making`,
        artifact.createdYear,
        artifact.createdYear,
        compactEventIds([firstEntry?.eventId, ...artifact.eventIds], 12),
        [
            personRef(simulation, artifact.creatorAgentId),
            settlementRef(simulation, artifact.settlementId),
            ...(artifact.structureId === undefined ? [] : [structureRef(simulation, artifact.structureId)]),
            ...provenanceRefs(simulation, creationEntries).slice(0, 8),
        ],
        `${artifact.name} was made in year ${artifact.createdYear} by ${simulation.agents[artifact.creatorAgentId]?.name ?? "an unknown maker"} as a ${artifactScaleLabel(artifact.scale)} ${artifact.quality} ${artifact.material} ${artifactKindLabel(artifact.kind)}. ${artifact.detail}`,
    ));

    const custodyEntries = provenance.filter(entry => entry.kind === "created" || entry.kind === "moved" || entry.kind === "inherited" || entry.kind === "gifted" || entry.kind === "lost" || entry.kind === "recovered" || entry.kind === "reclaimed" || entry.kind === "stolen" || entry.kind === "contested");
    if (custodyEntries.length > 1 || artifact.ownerAgentId !== undefined || artifact.ownerSettlementId !== artifact.settlementId) {
        const latest = custodyEntries[custodyEntries.length - 1] ?? provenance[provenance.length - 1];
        const holder = artifact.ownerAgentId === undefined
            ? simulation.settlements[artifact.ownerSettlementId]?.name ?? "an unknown place"
            : simulation.agents[artifact.ownerAgentId]?.name ?? "an unknown holder";
        chapters.push(artifactChapter(
            simulation,
            artifact,
            "custody",
            `${artifact.name}'s keepers`,
            minDefined(custodyEntries.map(entry => entry.year), artifact.createdYear),
            undefined,
            custodyEntries.map(entry => entry.eventId),
            [
                ...provenanceRefs(simulation, custodyEntries).slice(0, 18),
                ...(artifact.ownerAgentId === undefined ? [] : [personRef(simulation, artifact.ownerAgentId)]),
                settlementRef(simulation, artifact.ownerSettlementId),
                ...(artifact.structureId === undefined ? [] : [structureRef(simulation, artifact.structureId)]),
            ],
            `${artifact.name} has ${custodyEntries.length} custody ${custodyEntries.length === 1 ? "entry" : "entries"}, including ${custodyEntries.filter(entry => entry.kind === "lost").length} loss ${custodyEntries.filter(entry => entry.kind === "lost").length === 1 ? "entry" : "entries"}, ${custodyEntries.filter(entry => entry.kind === "recovered").length} recovery ${custodyEntries.filter(entry => entry.kind === "recovered").length === 1 ? "entry" : "entries"}, ${custodyEntries.filter(entry => entry.kind === "stolen").length} theft ${custodyEntries.filter(entry => entry.kind === "stolen").length === 1 ? "entry" : "entries"}, and ${custodyEntries.filter(entry => entry.kind === "contested").length} contested claim ${custodyEntries.filter(entry => entry.kind === "contested").length === 1 ? "entry" : "entries"}, and is currently held by ${holder}.`,
        ));
        if (latest?.structureId !== undefined || artifact.structureId !== undefined) {
            chapters.push(artifactChapter(
                simulation,
                artifact,
                "current-resting-place",
                `${artifact.name}'s resting place`,
                latest?.year ?? artifact.createdYear,
                undefined,
                compactEventIds([latest?.eventId], 8),
                [
                    settlementRef(simulation, artifact.ownerSettlementId),
                    ...(artifact.structureId === undefined ? [] : [structureRef(simulation, artifact.structureId)]),
                    ...(artifact.ownerAgentId === undefined ? [] : [personRef(simulation, artifact.ownerAgentId)]),
                ],
                `${artifact.name} is recorded at ${simulation.settlements[artifact.ownerSettlementId]?.name ?? "an unknown settlement"}${artifact.structureId === undefined ? "" : ` in ${simulation.structures[artifact.structureId]?.name ?? "an unknown structure"}`}.`,
            ));
        }
    }

    const travelEntries = provenance.filter(entry => entry.kind === "moved" || entry.kind === "gifted" || entry.kind === "recovered" || entry.kind === "dedicated" && entry.journeyId !== undefined);
    const related = artifactRelatedRecords(simulation, artifact);
    if (travelEntries.length || related.journeys.length) {
        chapters.push(artifactChapter(
            simulation,
            artifact,
            "travel",
            `${artifact.name}'s journeys`,
            minDefined([
                ...travelEntries.map(entry => entry.year),
                ...related.journeys.map(journey => journey.year),
            ], artifact.createdYear),
            maxDefined([
                ...travelEntries.map(entry => entry.year),
                ...related.journeys.map(journey => journey.year),
            ]),
            compactEventIds([...travelEntries.map(entry => entry.eventId), ...eventIdsForRecords(related.journeys, 12)], 18),
            [
                ...provenanceRefs(simulation, travelEntries).slice(0, 12),
                ...related.journeys.slice(-6).map(journey => journeyRef(simulation, journey.id)),
            ],
            `${artifact.name} appears in ${related.journeys.length} journey ${related.journeys.length === 1 ? "record" : "records"} and ${travelEntries.length} travel-related provenance ${travelEntries.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    const captureEntries = provenance.filter(entry => entry.kind === "captured" || entry.kind === "stolen" || entry.kind === "contested" || entry.battleId !== undefined);
    if (captureEntries.length || related.battles.length) {
        chapters.push(artifactChapter(
            simulation,
            artifact,
            "conflict-capture",
            `${artifact.name}'s conflicts`,
            minDefined([
                ...captureEntries.map(entry => entry.year),
                ...related.battles.map(battle => battle.year),
            ], artifact.createdYear),
            maxDefined([
                ...captureEntries.map(entry => entry.year),
                ...related.battles.map(battle => battle.year),
            ]),
            compactEventIds([...captureEntries.map(entry => entry.eventId), ...eventIdsForRecords(related.battles, 12)], 18),
            [
                ...provenanceRefs(simulation, captureEntries).slice(0, 12),
                ...related.battles.slice(-6).map(battle => battleRef(simulation, battle.id)),
            ],
            `${artifact.name} is tied to ${captureEntries.length} conflict, theft, or claim ${captureEntries.length === 1 ? "entry" : "entries"} and ${related.battles.length} battle ${related.battles.length === 1 ? "record" : "records"}.`,
        ));
    }

    const dedicationEntries = provenance.filter(entry => entry.kind === "dedicated" || entry.sacredSiteId !== undefined || entry.beliefId !== undefined);
    if (dedicationEntries.length || related.ceremonies.length) {
        chapters.push(artifactChapter(
            simulation,
            artifact,
            "dedication-rites",
            `${artifact.name}'s rites and dedications`,
            minDefined([
                ...dedicationEntries.map(entry => entry.year),
                ...related.ceremonies.map(ceremony => ceremony.year),
            ], artifact.createdYear),
            undefined,
            compactEventIds([...dedicationEntries.map(entry => entry.eventId), ...eventIdsForRecords(related.ceremonies, 12)], 18),
            [
                ...provenanceRefs(simulation, dedicationEntries).slice(0, 16),
                ...related.ceremonies.slice(-6).map(ceremony => ceremonyRef(simulation, ceremony.id)),
            ],
            `${artifact.name} has ${dedicationEntries.length} sacred provenance ${dedicationEntries.length === 1 ? "entry" : "entries"} and was displayed or used in ${related.ceremonies.length} ceremony ${related.ceremonies.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.projects.length || related.ambitions.length || related.oaths.length || related.obligations.length || related.socialClaims.length) {
        chapters.push(artifactChapter(
            simulation,
            artifact,
            "work-use",
            `${artifact.name}'s work, vows, and claims`,
            minDefined([
                ...related.projects.map(project => project.year),
                ...related.ambitions.map(ambition => ambition.startedYear),
                ...related.oaths.map(oath => oath.swornYear),
                ...related.obligations.map(obligation => obligation.createdYear),
                ...related.socialClaims.map(claim => claim.year),
            ], artifact.createdYear),
            undefined,
            eventIdsForRecords([...related.projects, ...related.ambitions, ...related.oaths, ...related.obligations, ...related.socialClaims], 18),
            [
                ...related.projects.slice(-5).map(project => projectRef(simulation, project.id)),
                ...related.ambitions.slice(-5).map(ambition => ambitionRef(simulation, ambition.id)),
                ...related.oaths.slice(-5).map(oath => oathRef(simulation, oath.id)),
                ...related.obligations.slice(-5).map(obligation => obligationRef(simulation, obligation.id)),
                ...related.socialClaims.slice(-5).map(claim => socialClaimRef(simulation, claim.id)),
            ],
            `${artifact.name} is linked to ${related.projects.length} project ${related.projects.length === 1 ? "record" : "records"}, ${related.ambitions.length} ambition ${related.ambitions.length === 1 ? "record" : "records"}, ${related.oaths.length} oath ${related.oaths.length === 1 ? "record" : "records"}, ${related.obligations.length} obligation ${related.obligations.length === 1 ? "record" : "records"}, and ${related.socialClaims.length} social claim ${related.socialClaims.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.chronicles.length || related.writtenWorks.length || related.memories.length || related.thoughts.length || related.opinions.length || related.conversations.length || related.rumors.length || related.secrets.length) {
        chapters.push(artifactChapter(
            simulation,
            artifact,
            "records-memory",
            `${artifact.name}'s memory and record`,
            minDefined([
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.thoughts.map(thought => thought.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.conversations.map(conversation => conversation.year),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
            ], artifact.createdYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.thoughts, ...related.opinions, ...related.conversations, ...related.rumors, ...related.secrets], 16),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 20),
            [
                ...related.chronicles.slice(-5).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-5).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-5).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-5).map(opinion => opinionRef(simulation, opinion.id)),
                ...related.conversations.slice(-5).map(conversation => conversationRef(simulation, conversation.id)),
                ...related.rumors.slice(-5).map(rumor => rumorRef(simulation, rumor.id)),
                ...related.secrets.slice(-5).map(secret => secretRef(simulation, secret.id)),
            ],
            `${artifact.name}'s record layer includes ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, ${related.writtenWorks.length} written ${related.writtenWorks.length === 1 ? "work" : "works"}, ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}, and ${related.rumors.length} rumor ${related.rumors.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<ArtifactChapterKind, number> = {
        creation: 0,
        custody: 1,
        travel: 2,
        "conflict-capture": 3,
        "dedication-rites": 4,
        "work-use": 5,
        "records-memory": 6,
        "current-resting-place": 7,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 10);
}

function roadChapter(
    simulation: CivilizationSimulation,
    road: Road,
    kind: RoadChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): RoadChapter {
    const chapterStartYear = Math.max(road.openedYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        roadId: road.id,
        civilizationId: road.civilizationId,
        fromSettlementId: road.fromSettlementId,
        toSettlementId: road.toSettlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            roadRef(simulation, road.id),
            civilizationRef(simulation, road.civilizationId),
            settlementRef(simulation, road.fromSettlementId),
            settlementRef(simulation, road.toSettlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function roadRelatedRecords(simulation: CivilizationSimulation, road: Road) {
    const endpointIds = new Set([road.fromSettlementId, road.toSettlementId]);
    const roadSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "road" && ref.id === road.id);
    const endpointSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "settlement" && endpointIds.has(ref.id));
    return {
        journeys: simulation.journeys.filter(journey => roadMatchesJourney(road, journey)),
        roadLaws: simulation.laws.filter(law => law.civilizationId === road.civilizationId && law.domain === "roads"),
        tradeProjects: simulation.projects.filter(project =>
            project.civilizationId === road.civilizationId
            && (project.kind === "trade" || project.kind === "patrol")
            && endpointIds.has(project.settlementId)
        ),
        roadCeremonies: simulation.ceremonies.filter(ceremony =>
            ceremony.civilizationId === road.civilizationId
            && endpointIds.has(ceremony.settlementId)
            && (ceremony.kind === "market-fair" || ceremony.kind === "muster" || ceremony.kind === "festival")
        ),
        sacredSites: simulation.sacredSites.filter(site =>
            site.civilizationId === road.civilizationId
            && (site.kind === "road-shrine" || endpointIds.has(site.settlementId))
        ),
        conflicts: simulation.conflicts.filter(conflict =>
            conflict.attackerCivilizationId === road.civilizationId
            || conflict.defenderCivilizationId === road.civilizationId
        ).filter(conflict =>
            conflict.targetSettlementId !== undefined && endpointIds.has(conflict.targetSettlementId)
            || conflict.contestedSettlementIds.some(id => endpointIds.has(id))
            || conflict.capturedSettlementIds.some(id => endpointIds.has(id))
        ),
        battles: simulation.battles.filter(battle =>
            (battle.attackerCivilizationId === road.civilizationId || battle.defenderCivilizationId === road.civilizationId)
            && endpointIds.has(battle.settlementId)
        ),
        chronicles: simulation.chronicles.filter(chronicle => roadSubject(chronicle.subjectRefs) || endpointSubject(chronicle.subjectRefs) && chronicle.civilizationId === road.civilizationId),
        writtenWorks: simulation.writtenWorks.filter(work => roadSubject(work.subjectRefs) || endpointSubject(work.subjectRefs) && work.civilizationId === road.civilizationId),
        memories: simulation.memories.filter(memory => roadSubject(memory.subjectRefs)),
        thoughts: simulation.thoughts.filter(thought => roadSubject(thought.subjectRefs)),
        opinions: simulation.opinions.filter(opinion => roadSubject(opinion.subjectRefs)),
        conversations: simulation.conversations.filter(conversation => roadSubject(conversation.subjectRefs)),
        rumors: simulation.rumors.filter(rumor => roadSubject(rumor.subjectRefs)),
        secrets: simulation.secrets.filter(secret => roadSubject(secret.subjectRefs)),
    };
}

function journeyKindCount(journeys: Journey[], kind: JourneyKind): number {
    return journeys.filter(journey => journey.kind === kind).length;
}

function buildRoadChapters(simulation: CivilizationSimulation, road: Road): RoadChapter[] {
    const chapters: RoadChapter[] = [];
    const related = roadRelatedRecords(simulation, road);
    const from = simulation.settlements[road.fromSettlementId];
    const to = simulation.settlements[road.toSettlementId];
    const firstJourney = related.journeys.slice().sort((a, b) => a.year - b.year || a.id - b.id)[0];
    const latestJourney = related.journeys.slice().sort((a, b) => b.year - a.year || b.id - a.id)[0];

    chapters.push(roadChapter(
        simulation,
        road,
        "opening-route",
        `${roadLegendName(simulation, road.id)} opening`,
        road.openedYear,
        undefined,
        compactEventIds(firstJourney?.eventIds ?? [], 10),
        [
            settlementRef(simulation, road.fromSettlementId),
            settlementRef(simulation, road.toSettlementId),
            ...(firstJourney === undefined ? [] : [journeyRef(simulation, firstJourney.id)]),
        ],
        `${roadLegendName(simulation, road.id)} opened in year ${road.openedYear}, linking ${from?.name ?? "an unknown settlement"} and ${to?.name ?? "an unknown settlement"} across ${Math.round(road.length * 100) / 100} map units at strength ${Math.round(road.strength * 1000) / 1000}.`,
    ));

    if (related.journeys.length) {
        chapters.push(roadChapter(
            simulation,
            road,
            "traffic-journeys",
            `${roadLegendName(simulation, road.id)} traffic`,
            minDefined(related.journeys.map(journey => journey.year), road.openedYear),
            undefined,
            eventIdsForRecords(related.journeys, 20),
            related.journeys.slice(-8).map(journey => journeyRef(simulation, journey.id)),
            `${roadLegendName(simulation, road.id)} carries ${related.journeys.length} recorded journey ${related.journeys.length === 1 ? "entry" : "entries"}, ending with ${latestJourney?.name ?? "no named journey"} in year ${latestJourney?.year ?? road.openedYear}.`,
        ));
    }

    const tradeAndPilgrimage = related.journeys.filter(journey => journey.kind === "trade" || journey.kind === "pilgrimage" || journey.kind === "delegation");
    if (tradeAndPilgrimage.length || related.roadLaws.length || related.tradeProjects.length || related.roadCeremonies.length || related.sacredSites.length) {
        chapters.push(roadChapter(
            simulation,
            road,
            "trade-pilgrimage",
            `${roadLegendName(simulation, road.id)} trade and pilgrimage`,
            minDefined([
                ...tradeAndPilgrimage.map(journey => journey.year),
                ...related.roadLaws.map(law => law.enactedYear),
                ...related.tradeProjects.map(project => project.year),
                ...related.roadCeremonies.map(ceremony => ceremony.year),
                ...related.sacredSites.map(site => site.foundedYear),
            ], road.openedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...tradeAndPilgrimage, ...related.roadLaws, ...related.tradeProjects, ...related.roadCeremonies, ...related.sacredSites], 22),
            ], 22),
            [
                ...tradeAndPilgrimage.slice(-6).map(journey => journeyRef(simulation, journey.id)),
                ...related.roadLaws.slice(-5).map(law => lawRef(simulation, law.id)),
                ...related.tradeProjects.slice(-5).map(project => projectRef(simulation, project.id)),
                ...related.roadCeremonies.slice(-5).map(ceremony => ceremonyRef(simulation, ceremony.id)),
                ...related.sacredSites.slice(0, 5).map(site => sacredSiteRef(simulation, site.id)),
            ],
            `${roadLegendName(simulation, road.id)} is tied to ${journeyKindCount(related.journeys, "trade")} trade journey ${journeyKindCount(related.journeys, "trade") === 1 ? "entry" : "entries"}, ${journeyKindCount(related.journeys, "pilgrimage")} pilgrimage ${journeyKindCount(related.journeys, "pilgrimage") === 1 ? "entry" : "entries"}, ${related.roadLaws.length} road law ${related.roadLaws.length === 1 ? "entry" : "entries"}, and ${related.sacredSites.length} sacred site ${related.sacredSites.length === 1 ? "link" : "links"}.`,
        ));
    }

    if (related.conflicts.length || related.battles.length) {
        chapters.push(roadChapter(
            simulation,
            road,
            "conflict-danger",
            `${roadLegendName(simulation, road.id)} in conflict`,
            minDefined([
                ...related.conflicts.map(conflict => conflict.startedYear),
                ...related.battles.map(battle => battle.year),
            ], road.openedYear),
            related.conflicts.some(conflict => conflict.status !== "resolved") ? undefined : maxDefined([
                ...related.conflicts.map(conflict => conflict.endedYear),
                ...related.battles.map(battle => battle.year),
            ]),
            compactEventIds([
                ...eventIdsForRecords(related.conflicts, 18),
                ...eventIdsForRecords(related.battles, 18),
            ], 22),
            [
                ...related.conflicts.slice(-6).map(conflict => conflictRef(simulation, conflict.id)),
                ...related.battles.slice(-6).map(battle => battleRef(simulation, battle.id)),
            ],
            `${roadLegendName(simulation, road.id)} touches ${related.conflicts.length} conflict ${related.conflicts.length === 1 ? "arc" : "arcs"} and ${related.battles.length} battle ${related.battles.length === 1 ? "entry" : "entries"} around its endpoint settlements.`,
        ));
    }

    if (related.chronicles.length || related.writtenWorks.length || related.memories.length || related.thoughts.length || related.opinions.length || related.conversations.length || related.rumors.length || related.secrets.length) {
        chapters.push(roadChapter(
            simulation,
            road,
            "records-legacy",
            `${roadLegendName(simulation, road.id)} records and legacy`,
            minDefined([
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.thoughts.map(thought => thought.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.conversations.map(conversation => conversation.year),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
            ], road.openedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.thoughts, ...related.opinions, ...related.conversations, ...related.rumors, ...related.secrets], 22),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.chronicles.slice(-5).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-5).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-5).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-5).map(opinion => opinionRef(simulation, opinion.id)),
                ...related.conversations.slice(-5).map(conversation => conversationRef(simulation, conversation.id)),
                ...related.rumors.slice(-5).map(rumor => rumorRef(simulation, rumor.id)),
                ...related.secrets.slice(-5).map(secret => secretRef(simulation, secret.id)),
            ],
            `${roadLegendName(simulation, road.id)} is remembered through ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, ${related.writtenWorks.length} written ${related.writtenWorks.length === 1 ? "work" : "works"}, ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}, and ${related.rumors.length} rumor ${related.rumors.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<RoadChapterKind, number> = {
        "opening-route": 0,
        "traffic-journeys": 1,
        "trade-pilgrimage": 2,
        "conflict-danger": 3,
        "records-legacy": 4,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 8);
}

function structureChapter(
    simulation: CivilizationSimulation,
    structure: Structure,
    kind: StructureChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): StructureChapter {
    const chapterStartYear = Math.max(structure.builtYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        structureId: structure.id,
        civilizationId: structure.civilizationId,
        settlementId: structure.settlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            structureRef(simulation, structure.id),
            civilizationRef(simulation, structure.civilizationId),
            settlementRef(simulation, structure.settlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function structureRelatedRecords(simulation: CivilizationSimulation, structure: Structure) {
    const residentSet = new Set(structure.residentAgentIds);
    const workerSet = new Set(structure.workerAgentIds);
    const personSet = new Set([...structure.residentAgentIds, ...structure.workerAgentIds]);
    const structureSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "structure" && ref.id === structure.id);
    return {
        founder: structure.founderAgentId === undefined ? undefined : simulation.agents[structure.founderAgentId],
        organization: structure.organizationId === undefined ? undefined : simulation.organizations[structure.organizationId],
        belief: structure.beliefId === undefined ? undefined : simulation.beliefs[structure.beliefId],
        office: structure.officeId === undefined ? undefined : simulation.offices[structure.officeId],
        residents: structure.residentAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        workers: structure.workerAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        households: simulation.households.filter(household => household.residenceStructureId === structure.id),
        residences: simulation.residences.filter(residence => residence.structureId === structure.id),
        careers: simulation.careers.filter(career => career.structureId === structure.id),
        memberships: simulation.memberships.filter(membership => membership.structureId === structure.id),
        apprenticeships: simulation.apprenticeships.filter(apprenticeship => apprenticeship.structureId === structure.id),
        skills: simulation.skills.filter(skill => personSet.has(skill.agentId) && skill.subjectRefs.some(ref => ref.kind === "structure" && ref.id === structure.id)),
        teachings: simulation.teachings.filter(teaching => teaching.structureId === structure.id),
        projects: simulation.projects.filter(project => project.structureId === structure.id),
        projectParticipations: simulation.projectParticipations.filter(participation => participation.structureId === structure.id),
        ceremonies: simulation.ceremonies.filter(ceremony => ceremony.structureId === structure.id),
        ceremonyParticipations: simulation.ceremonyParticipations.filter(participation => participation.structureId === structure.id),
        activities: uniqueNumberList([
            ...structure.activityIds,
            ...simulation.activities.filter(activity => activity.structureId === structure.id).map(activity => activity.id),
        ]).map(id => simulation.activities[id]).filter(Boolean),
        officeTerms: simulation.officeTerms.filter(term => term.structureId === structure.id),
        laws: simulation.laws.filter(law => law.officeId === structure.officeId || law.settlementId === structure.settlementId && structure.kind === "court"),
        cases: simulation.cases.filter(legalCase => legalCase.structureId === structure.id),
        testimonies: simulation.testimonies.filter(testimony => testimony.structureId === structure.id),
        injuries: simulation.injuries.filter(injury => injury.structureId === structure.id),
        illnesses: simulation.illnesses.filter(illness => illness.structureId === structure.id),
        memorials: simulation.memorials.filter(memorial => memorial.structureId === structure.id),
        journeys: simulation.journeys.filter(journey => journey.originStructureId === structure.id || journey.destinationStructureId === structure.id),
        holdings: simulation.holdings.filter(holding => holding.structureId === structure.id),
        belongings: simulation.belongings.filter(belonging => belonging.structureId === structure.id),
        artifacts: simulation.artifacts.filter(artifact => artifact.structureId === structure.id || artifact.provenance.some(entry => entry.structureId === structure.id || entry.previousStructureId === structure.id)),
        chronicles: simulation.chronicles.filter(chronicle => chronicle.structureId === structure.id || structureSubject(chronicle.subjectRefs)),
        writtenWorks: simulation.writtenWorks.filter(work => work.structureId === structure.id || structureSubject(work.subjectRefs)),
        memories: simulation.memories.filter(memory => structureSubject(memory.subjectRefs)),
        thoughts: simulation.thoughts.filter(thought => structureSubject(thought.subjectRefs)),
        opinions: simulation.opinions.filter(opinion => structureSubject(opinion.subjectRefs)),
        conversations: simulation.conversations.filter(conversation => structureSubject(conversation.subjectRefs)),
        rumors: simulation.rumors.filter(rumor => structureSubject(rumor.subjectRefs)),
        secrets: simulation.secrets.filter(secret => structureSubject(secret.subjectRefs)),
        residentSet,
        workerSet,
    };
}

function buildStructureChapters(simulation: CivilizationSimulation, structure: Structure): StructureChapter[] {
    const chapters: StructureChapter[] = [];
    const related = structureRelatedRecords(simulation, structure);
    const notableResidents = related.residents
        .slice()
        .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
        .slice(0, 8);
    const notableWorkers = related.workers
        .slice()
        .sort((a, b) => b.reputation - a.reputation || b.skill - a.skill || a.id - b.id)
        .slice(0, 8);

    chapters.push(structureChapter(
        simulation,
        structure,
        "construction",
        `${structure.name}'s construction`,
        structure.builtYear,
        undefined,
        structure.eventIds,
        [
            ...(related.founder === undefined ? [] : [personRef(simulation, related.founder.id)]),
            ...(related.organization === undefined ? [] : [organizationRef(simulation, related.organization.id)]),
            ...(related.belief === undefined ? [] : [beliefRef(simulation, related.belief.id)]),
            ...(related.office === undefined ? [] : [officeRef(simulation, related.office.id)]),
        ],
        `${structure.name} was built in year ${structure.builtYear} as a ${structure.kind} in ${simulation.settlements[structure.settlementId]?.name ?? "an unknown settlement"}${related.founder === undefined ? "" : ` by ${related.founder.name}`}.`,
    ));

    if (related.organization || related.office || related.memberships.length || related.officeTerms.length || related.laws.length) {
        chapters.push(structureChapter(
            simulation,
            structure,
            "institution",
            `${structure.name}'s institution`,
            minDefined([
                related.organization?.foundedYear,
                related.office?.createdYear,
                ...related.memberships.map(membership => membership.startedYear),
                ...related.officeTerms.map(term => term.startedYear),
                ...related.laws.map(law => law.enactedYear),
            ], structure.builtYear),
            undefined,
            eventIdsForRecords([...related.memberships, ...related.officeTerms, ...related.laws], 20),
            [
                ...(related.organization === undefined ? [] : [organizationRef(simulation, related.organization.id)]),
                ...(related.office === undefined ? [] : [officeRef(simulation, related.office.id)]),
                ...related.memberships.slice(-6).map(membership => membershipRef(simulation, membership.id)),
                ...related.officeTerms.slice(-6).map(term => officeTermRef(simulation, term.id)),
                ...related.laws.slice(-5).map(law => lawRef(simulation, law.id)),
            ],
            `${structure.name}'s institutional record links ${related.memberships.length} membership ${related.memberships.length === 1 ? "entry" : "entries"}, ${related.officeTerms.length} office ${related.officeTerms.length === 1 ? "term" : "terms"}, and ${related.laws.length} law ${related.laws.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.residents.length || related.households.length || related.residences.length || notableResidents.length) {
        const activeResidences = related.residences.filter(residence => residence.status === "active");
        chapters.push(structureChapter(
            simulation,
            structure,
            "residents-households",
            `${structure.name}'s residents and households`,
            minDefined([
                ...related.residences.map(residence => residence.startYear),
                ...related.households.map(household => household.foundedYear),
                ...related.residents.map(resident => resident.bornYear),
            ], structure.builtYear),
            activeResidences.length ? undefined : maxDefined(related.residences.map(residence => residence.endYear)),
            compactEventIds([
                ...eventIdsForRecords([...related.residences, ...related.households], 18),
                ...notableResidents.flatMap(agent => agent.eventIds.slice(0, 3)),
            ], 22),
            [
                ...notableResidents.map(agent => personRef(simulation, agent.id)),
                ...related.households.slice(0, 8).map(household => householdRef(simulation, household.id)),
                ...related.residences.slice(-8).map(residence => residenceRef(simulation, residence.id)),
            ],
            `${structure.name} records ${related.residents.length} resident ${related.residents.length === 1 ? "person" : "people"}, ${related.households.length} household ${related.households.length === 1 ? "record" : "records"}, and ${related.residences.length} residence ${related.residences.length === 1 ? "term" : "terms"}.`,
        ));
    }

    if (related.workers.length || related.careers.length || related.apprenticeships.length || related.teachings.length || related.projects.length || related.projectParticipations.length || related.activities.length) {
        chapters.push(structureChapter(
            simulation,
            structure,
            "work-training",
            `${structure.name}'s work and training`,
            minDefined([
                ...related.careers.map(career => career.startYear),
                ...related.apprenticeships.map(apprenticeship => apprenticeship.startedYear),
                ...related.teachings.map(teaching => teaching.year),
                ...related.projects.map(project => project.year),
                ...related.projectParticipations.map(participation => participation.year),
                ...related.activities.map(activity => activity.year),
            ], structure.builtYear),
            undefined,
            eventIdsForRecords([...related.careers, ...related.apprenticeships, ...related.teachings, ...related.projects, ...related.projectParticipations, ...related.activities], 24),
            [
                ...notableWorkers.map(agent => personRef(simulation, agent.id)),
                ...related.careers.slice(-6).map(career => careerRef(simulation, career.id)),
                ...related.apprenticeships.slice(-6).map(apprenticeship => apprenticeshipRef(simulation, apprenticeship.id)),
                ...related.teachings.slice(-6).map(teaching => teachingRef(simulation, teaching.id)),
                ...related.projects.slice(-6).map(project => projectRef(simulation, project.id)),
                ...related.activities.slice(-6).map(activity => activityRef(simulation, activity.id)),
            ],
            `${structure.name}'s work record includes ${related.workers.length} worker ${related.workers.length === 1 ? "person" : "people"}, ${related.careers.length} career ${related.careers.length === 1 ? "link" : "links"}, ${related.apprenticeships.length} apprenticeship ${related.apprenticeships.length === 1 ? "record" : "records"}, ${related.teachings.length} teaching ${related.teachings.length === 1 ? "entry" : "entries"}, and ${related.projects.length} project ${related.projects.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.belief || related.ceremonies.length || related.ceremonyParticipations.length || related.journeys.length || structure.kind === "shrine" || structure.kind === "market" || structure.kind === "hall") {
        const relevantJourneys = related.journeys.filter(journey => journey.kind === "pilgrimage" || journey.kind === "trade" || journey.kind === "delegation");
        chapters.push(structureChapter(
            simulation,
            structure,
            "rites-culture",
            `${structure.name}'s rites and gatherings`,
            minDefined([
                related.belief?.foundedYear,
                ...related.ceremonies.map(ceremony => ceremony.year),
                ...related.ceremonyParticipations.map(participation => participation.year),
                ...relevantJourneys.map(journey => journey.year),
            ], structure.builtYear),
            undefined,
            compactEventIds([
                ...(related.belief?.eventIds ?? []),
                ...eventIdsForRecords([...related.ceremonies, ...related.ceremonyParticipations, ...relevantJourneys], 24),
            ], 24),
            [
                ...(related.belief === undefined ? [] : [beliefRef(simulation, related.belief.id)]),
                ...related.ceremonies.slice(-6).map(ceremony => ceremonyRef(simulation, ceremony.id)),
                ...related.ceremonyParticipations.slice(-6).map(participation => ceremonyParticipationRef(simulation, participation.id)),
                ...relevantJourneys.slice(-6).map(journey => journeyRef(simulation, journey.id)),
            ],
            `${structure.name}'s cultural record includes ${related.ceremonies.length} ceremony ${related.ceremonies.length === 1 ? "entry" : "entries"}, ${related.ceremonyParticipations.length} ceremony role ${related.ceremonyParticipations.length === 1 ? "record" : "records"}, and ${relevantJourneys.length} linked journey ${relevantJourneys.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.cases.length || related.testimonies.length || related.injuries.length || related.illnesses.length || related.memorials.length) {
        chapters.push(structureChapter(
            simulation,
            structure,
            "law-hardship",
            `${structure.name}'s law and hardship`,
            minDefined([
                ...related.cases.map(legalCase => legalCase.openedYear),
                ...related.testimonies.map(testimony => testimony.year),
                ...related.injuries.map(injury => injury.year),
                ...related.illnesses.map(illness => illness.onsetYear),
                ...related.memorials.map(memorial => memorial.year),
            ], structure.builtYear),
            undefined,
            eventIdsForRecords([...related.cases, ...related.testimonies, ...related.injuries, ...related.illnesses, ...related.memorials], 24),
            [
                ...related.cases.slice(-5).map(legalCase => caseRef(simulation, legalCase.id)),
                ...related.testimonies.slice(-5).map(testimony => testimonyRef(simulation, testimony.id)),
                ...related.injuries.slice(-5).map(injury => injuryRef(simulation, injury.id)),
                ...related.illnesses.slice(-5).map(illness => illnessRef(simulation, illness.id)),
                ...related.memorials.slice(-5).map(memorial => memorialRef(simulation, memorial.id)),
            ],
            `${structure.name}'s difficult record includes ${related.cases.length} legal case ${related.cases.length === 1 ? "record" : "records"}, ${related.testimonies.length} testimony ${related.testimonies.length === 1 ? "entry" : "entries"}, ${related.injuries.length} injur${related.injuries.length === 1 ? "y" : "ies"}, ${related.illnesses.length} illness ${related.illnesses.length === 1 ? "case" : "cases"}, and ${related.memorials.length} memorial ${related.memorials.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.holdings.length || related.belongings.length || related.artifacts.length || related.chronicles.length || related.writtenWorks.length || related.memories.length || related.opinions.length || related.rumors.length || related.secrets.length) {
        const renownedArtifacts = related.artifacts
            .slice()
            .sort((a, b) => b.renown - a.renown || a.createdYear - b.createdYear || a.id - b.id)
            .slice(0, 6);
        chapters.push(structureChapter(
            simulation,
            structure,
            "assets-records",
            `${structure.name}'s assets and records`,
            minDefined([
                ...related.holdings.map(holding => holding.foundedYear),
                ...related.belongings.map(belonging => belonging.acquiredYear),
                ...related.artifacts.map(artifact => artifact.createdYear),
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
            ], structure.builtYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.holdings, ...related.belongings, ...related.artifacts, ...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.opinions, ...related.rumors, ...related.secrets], 24),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.holdings.slice(-5).map(holding => holdingRef(simulation, holding.id)),
                ...related.belongings.slice(-5).map(belonging => belongingRef(simulation, belonging.id)),
                ...renownedArtifacts.map(artifact => artifactRef(simulation, artifact.id)),
                ...related.chronicles.slice(-5).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-5).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-5).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-5).map(opinion => opinionRef(simulation, opinion.id)),
            ],
            `${structure.name}'s material and written legacy includes ${related.holdings.length} holding ${related.holdings.length === 1 ? "entry" : "entries"}, ${related.belongings.length} belonging ${related.belongings.length === 1 ? "entry" : "entries"}, ${related.artifacts.length} artifact ${related.artifacts.length === 1 ? "link" : "links"}, ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, and ${related.writtenWorks.length} written ${related.writtenWorks.length === 1 ? "work" : "works"}.`,
        ));
    }

    const chapterOrder: Record<StructureChapterKind, number> = {
        construction: 0,
        institution: 1,
        "residents-households": 2,
        "work-training": 3,
        "rites-culture": 4,
        "law-hardship": 5,
        "assets-records": 6,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 9);
}

function conflictChapter(
    simulation: CivilizationSimulation,
    conflict: Conflict,
    kind: ConflictChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): ConflictChapter {
    const chapterStartYear = Math.max(conflict.startedYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        conflictId: conflict.id,
        attackerCivilizationId: conflict.attackerCivilizationId,
        defenderCivilizationId: conflict.defenderCivilizationId,
        sourceEventIds: compactEventIds(sourceEventIds, 20),
        subjectRefs: uniqueLegendRefs([
            conflictRef(simulation, conflict.id),
            civilizationRef(simulation, conflict.attackerCivilizationId),
            civilizationRef(simulation, conflict.defenderCivilizationId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 34),
        description,
    };
}

function conflictRelatedRecords(simulation: CivilizationSimulation, conflict: Conflict) {
    const battleIdSet = new Set(conflict.battleIds);
    const casualtySet = new Set(conflict.casualtyAgentIds);
    const conflictBattles = conflict.battleIds.map(id => simulation.battles[id]).filter(Boolean);
    const militaryUnitIds = uniqueNumberList(conflictBattles.flatMap(battle => [...battle.attackerUnitIds, ...battle.defenderUnitIds]));
    const spyOperationIds = uniqueNumberList([
        ...conflict.spyOperationIds,
        ...conflictBattles.flatMap(battle => battle.spyOperationIds),
    ]);
    const militaryUnits = militaryUnitIds.map(id => simulation.militaryUnits[id]).filter(Boolean);
    const contestedSettlementSet = new Set([
        ...conflict.contestedSettlementIds,
        ...conflict.capturedSettlementIds,
        ...(conflict.targetSettlementId === undefined ? [] : [conflict.targetSettlementId]),
    ]);
    const conflictSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "conflict" && ref.id === conflict.id);
    const battleSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "battle" && battleIdSet.has(ref.id));
    return {
        battles: conflictBattles,
        battleParticipations: simulation.battleParticipations.filter(participation => participation.conflictId === conflict.id || battleIdSet.has(participation.battleId)),
        militaryUnits,
        equipmentCaches: uniqueNumberList(militaryUnits.flatMap(unit => unit.equipmentCacheIds)).map(id => simulation.equipmentCaches[id]).filter(Boolean),
        spyOperations: spyOperationIds.map(id => simulation.spyOperations[id]).filter(Boolean),
        casualties: conflict.casualtyAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        capturedSettlements: conflict.capturedSettlementIds.map(id => simulation.settlements[id]).filter(Boolean),
        capturedArtifacts: conflict.capturedArtifactIds.map(id => simulation.artifacts[id]).filter(Boolean),
        settlementControls: simulation.settlementControls.filter(control => control.conflictId === conflict.id || (control.battleId !== undefined && battleIdSet.has(control.battleId))),
        personAllegiances: simulation.personAllegiances.filter(allegiance => allegiance.conflictId === conflict.id || (allegiance.battleId !== undefined && battleIdSet.has(allegiance.battleId))),
        injuries: simulation.injuries.filter(injury => (injury.battleId !== undefined && battleIdSet.has(injury.battleId)) || casualtySet.has(injury.personId)),
        memorials: simulation.memorials.filter(memorial => (memorial.battleId !== undefined && battleIdSet.has(memorial.battleId)) || casualtySet.has(memorial.personId)),
        oaths: simulation.oaths.filter(oath =>
            conflictSubject(oath.subjectRefs)
            || (oath.targetSettlementId !== undefined && contestedSettlementSet.has(oath.targetSettlementId))
            || (oath.targetArtifactId !== undefined && conflict.capturedArtifactIds.includes(oath.targetArtifactId))
        ),
        obligations: simulation.obligations.filter(obligation => conflictSubject(obligation.subjectRefs)),
        rumors: simulation.rumors.filter(rumor => conflictSubject(rumor.subjectRefs) || rumor.kind === "battle" && battleSubject(rumor.subjectRefs)),
        secrets: simulation.secrets.filter(secret => conflictSubject(secret.subjectRefs)),
        chronicles: simulation.chronicles.filter(chronicle => conflictSubject(chronicle.subjectRefs) || chronicle.kind === "battle-account" && battleSubject(chronicle.subjectRefs)),
        writtenWorks: simulation.writtenWorks.filter(work => conflictSubject(work.subjectRefs) || battleSubject(work.subjectRefs)),
        memories: simulation.memories.filter(memory => conflictSubject(memory.subjectRefs) || battleSubject(memory.subjectRefs)),
        thoughts: simulation.thoughts.filter(thought => conflictSubject(thought.subjectRefs) || battleSubject(thought.subjectRefs)),
        opinions: simulation.opinions.filter(opinion => conflictSubject(opinion.subjectRefs) || battleSubject(opinion.subjectRefs)),
        conversations: simulation.conversations.filter(conversation => conflictSubject(conversation.subjectRefs) || battleSubject(conversation.subjectRefs)),
        feuds: simulation.feuds.filter(feud => conflictSubject(feud.subjectRefs) || conflict.capturedSettlementIds.includes(feud.settlementId)),
    };
}

function buildConflictChapters(simulation: CivilizationSimulation, conflict: Conflict): ConflictChapter[] {
    const chapters: ConflictChapter[] = [];
    const related = conflictRelatedRecords(simulation, conflict);
    const attacker = simulation.civilizations[conflict.attackerCivilizationId];
    const defender = simulation.civilizations[conflict.defenderCivilizationId];
    const target = conflict.targetSettlementId === undefined ? undefined : simulation.settlements[conflict.targetSettlementId];
    const firstBattle = related.battles.slice().sort((a, b) => a.year - b.year || a.id - b.id)[0];
    const latestBattle = related.battles.slice().sort((a, b) => b.year - a.year || b.id - a.id)[0];

    chapters.push(conflictChapter(
        simulation,
        conflict,
        "outbreak",
        `${conflict.name}'s outbreak`,
        conflict.startedYear,
        conflict.battleIds.length || conflict.status !== "resolved" ? undefined : conflict.endedYear,
        compactEventIds([conflict.startedEventId, ...conflict.eventIds], 18),
        [
            civilizationRef(simulation, conflict.instigatorCivilizationId),
            ...(target === undefined ? [] : [settlementRef(simulation, target.id)]),
            ...conflict.contestedSettlementIds.slice(0, 6).map(id => settlementRef(simulation, id)),
        ],
        `${conflict.name} began in year ${conflict.startedYear} as a ${conflict.kind} between ${attacker?.name ?? "an unknown attacker"} and ${defender?.name ?? "an unknown defender"}${target === undefined ? "" : ` over ${target.name}`}.`,
    ));

    if (related.battles.length || related.battleParticipations.length) {
        chapters.push(conflictChapter(
            simulation,
            conflict,
            "campaigns-battles",
            `${conflict.name}'s campaigns and battles`,
            minDefined(related.battles.map(battle => battle.year), conflict.startedYear),
            conflict.status === "resolved" ? conflict.endedYear ?? latestBattle?.year : undefined,
            compactEventIds([
                ...eventIdsForRecords(related.battles, 20),
                ...eventIdsForRecords(related.battleParticipations, 20),
            ], 24),
            [
                ...related.battles.slice(-8).map(battle => battleRef(simulation, battle.id)),
                ...related.battleParticipations.slice(-8).map(participation => battleParticipationRef(simulation, participation.id)),
                ...related.militaryUnits.slice(-8).map(unit => militaryUnitRef(simulation, unit.id)),
                ...related.spyOperations.slice(-6).map(operation => spyOperationRef(simulation, operation.id)),
                ...(firstBattle?.attackerCommanderId === undefined ? [] : [personRef(simulation, firstBattle.attackerCommanderId)]),
                ...(firstBattle?.defenderCommanderId === undefined ? [] : [personRef(simulation, firstBattle.defenderCommanderId)]),
            ],
            `${conflict.name} records ${related.battles.length} battle ${related.battles.length === 1 ? "entry" : "entries"}, ${related.battleParticipations.length} battle role ${related.battleParticipations.length === 1 ? "record" : "records"}, ${related.militaryUnits.length} military unit ${related.militaryUnits.length === 1 ? "record" : "records"}, and ${related.spyOperations.length} spy operation ${related.spyOperations.length === 1 ? "record" : "records"}, ending most recently at ${latestBattle?.battlefieldName ?? latestBattle?.name ?? "no named battlefield"}.`,
        ));
    }

    if (related.casualties.length || related.injuries.length || related.memorials.length || related.capturedSettlements.length || related.capturedArtifacts.length) {
        const notableCasualties = related.casualties
            .slice()
            .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
            .slice(0, 8);
        chapters.push(conflictChapter(
            simulation,
            conflict,
            "casualties-captures",
            `${conflict.name}'s casualties and captures`,
            minDefined([
                ...related.battles.map(battle => battle.year),
                ...related.injuries.map(injury => injury.year),
                ...related.memorials.map(memorial => memorial.year),
                ...related.capturedArtifacts.map(artifact => artifact.createdYear),
            ], conflict.startedYear),
            conflict.status === "resolved" ? conflict.endedYear ?? latestBattle?.year : undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.battles, ...related.injuries, ...related.memorials], 22),
                ...related.capturedArtifacts.flatMap(artifact => artifact.eventIds),
            ], 24),
            [
                ...notableCasualties.map(agent => personRef(simulation, agent.id)),
                ...related.injuries.slice(-6).map(injury => injuryRef(simulation, injury.id)),
                ...related.memorials.slice(-6).map(memorial => memorialRef(simulation, memorial.id)),
                ...related.capturedSettlements.slice(0, 6).map(settlement => settlementRef(simulation, settlement.id)),
                ...related.capturedArtifacts.slice(0, 6).map(artifact => artifactRef(simulation, artifact.id)),
            ],
            `${conflict.name} caused ${related.casualties.length} recorded casualty ${related.casualties.length === 1 ? "person" : "people"}, ${related.injuries.length} injur${related.injuries.length === 1 ? "y" : "ies"}, ${related.capturedSettlements.length} captured settlement ${related.capturedSettlements.length === 1 ? "record" : "records"}, and ${related.capturedArtifacts.length} captured artifact ${related.capturedArtifacts.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.settlementControls.length || related.personAllegiances.length || conflict.endedEventId !== undefined) {
        chapters.push(conflictChapter(
            simulation,
            conflict,
            "control-aftermath",
            `${conflict.name}'s control and aftermath`,
            minDefined([
                ...related.settlementControls.map(control => control.startedYear),
                ...related.personAllegiances.map(allegiance => allegiance.startedYear),
                conflict.endedYear,
            ], conflict.startedYear),
            conflict.status === "resolved" ? conflict.endedYear : undefined,
            compactEventIds([
                conflict.endedEventId,
                ...eventIdsForRecords([...related.settlementControls, ...related.personAllegiances], 22),
            ], 24),
            [
                ...related.settlementControls.slice(-8).map(control => settlementControlRef(simulation, control.id)),
                ...related.personAllegiances.slice(-8).map(allegiance => personAllegianceRef(simulation, allegiance.id)),
                ...related.capturedSettlements.slice(0, 6).map(settlement => settlementRef(simulation, settlement.id)),
            ],
            `${conflict.name}'s aftermath changed ${related.settlementControls.length} settlement control ${related.settlementControls.length === 1 ? "term" : "terms"} and ${related.personAllegiances.length} person allegiance ${related.personAllegiances.length === 1 ? "record" : "records"}${conflict.status === "resolved" ? " before resolution" : " while remaining unresolved"}.`,
        ));
    }

    if (related.oaths.length || related.obligations.length || related.rumors.length || related.secrets.length || related.feuds.length) {
        chapters.push(conflictChapter(
            simulation,
            conflict,
            "oaths-rumors",
            `${conflict.name}'s vows and rumors`,
            minDefined([
                ...related.oaths.map(oath => oath.swornYear),
                ...related.obligations.map(obligation => obligation.createdYear),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
                ...related.feuds.map(feud => feud.startedYear),
            ], conflict.startedYear),
            undefined,
            eventIdsForRecords([...related.oaths, ...related.obligations, ...related.rumors, ...related.secrets, ...related.feuds], 24),
            [
                ...related.oaths.slice(-6).map(oath => oathRef(simulation, oath.id)),
                ...related.obligations.slice(-6).map(obligation => obligationRef(simulation, obligation.id)),
                ...related.rumors.slice(-6).map(rumor => rumorRef(simulation, rumor.id)),
                ...related.secrets.slice(-5).map(secret => secretRef(simulation, secret.id)),
                ...related.feuds.slice(-5).map(feud => feudRef(simulation, feud.id)),
            ],
            `${conflict.name} left ${related.oaths.length} oath ${related.oaths.length === 1 ? "record" : "records"}, ${related.rumors.length} rumor ${related.rumors.length === 1 ? "record" : "records"}, ${related.secrets.length} secret ${related.secrets.length === 1 ? "record" : "records"}, and ${related.feuds.length} feud ${related.feuds.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.chronicles.length || related.writtenWorks.length || related.memories.length || related.thoughts.length || related.opinions.length || related.conversations.length) {
        chapters.push(conflictChapter(
            simulation,
            conflict,
            "records-legacy",
            `${conflict.name}'s records and legacy`,
            minDefined([
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.thoughts.map(thought => thought.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.conversations.map(conversation => conversation.year),
            ], conflict.startedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.thoughts, ...related.opinions, ...related.conversations], 24),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.chronicles.slice(-6).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-6).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-6).map(opinion => opinionRef(simulation, opinion.id)),
                ...related.conversations.slice(-6).map(conversation => conversationRef(simulation, conversation.id)),
            ],
            `${conflict.name} is preserved by ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, ${related.writtenWorks.length} written ${related.writtenWorks.length === 1 ? "work" : "works"}, ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}, and ${related.opinions.length} opinion ${related.opinions.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<ConflictChapterKind, number> = {
        outbreak: 0,
        "campaigns-battles": 1,
        "casualties-captures": 2,
        "control-aftermath": 3,
        "oaths-rumors": 4,
        "records-legacy": 5,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 8);
}

function battleChapter(
    simulation: CivilizationSimulation,
    battle: Battle,
    kind: BattleChapterKind,
    title: string,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): BattleChapter {
    return {
        kind,
        title,
        startYear: battle.year,
        endYear: battle.year,
        status: "ended",
        battleId: battle.id,
        conflictId: battle.conflictId,
        settlementId: battle.settlementId,
        attackerCivilizationId: battle.attackerCivilizationId,
        defenderCivilizationId: battle.defenderCivilizationId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            battleRef(simulation, battle.id),
            ...(battle.conflictId === undefined ? [] : [conflictRef(simulation, battle.conflictId)]),
            settlementRef(simulation, battle.settlementId),
            civilizationRef(simulation, battle.attackerCivilizationId),
            civilizationRef(simulation, battle.defenderCivilizationId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 32),
        description,
    };
}

function battleRelatedRecords(simulation: CivilizationSimulation, battle: Battle) {
    const participantIds = new Set([...battle.attackerParticipantIds, ...battle.defenderParticipantIds]);
    const casualtyIds = new Set(battle.casualtyAgentIds);
    const militaryUnits = uniqueNumberList([...battle.attackerUnitIds, ...battle.defenderUnitIds])
        .map(id => simulation.militaryUnits[id])
        .filter(Boolean);
    const battleSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "battle" && ref.id === battle.id);
    const participantSubject = (refs: LegendEntityRef[] | undefined) => (refs ?? []).some(ref => ref.kind === "battle-participation" && battle.battleParticipationIds.includes(ref.id));
    return {
        conflict: battle.conflictId === undefined ? undefined : simulation.conflicts[battle.conflictId],
        participants: [...participantIds].map(id => simulation.agents[id]).filter(Boolean),
        casualties: battle.casualtyAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        capturedArtifacts: battle.capturedArtifactIds.map(id => simulation.artifacts[id]).filter(Boolean),
        militaryUnits,
        equipmentCaches: uniqueNumberList(militaryUnits.flatMap(unit => unit.equipmentCacheIds)).map(id => simulation.equipmentCaches[id]).filter(Boolean),
        spyOperations: battle.spyOperationIds.map(id => simulation.spyOperations[id]).filter(Boolean),
        participations: battle.battleParticipationIds.map(id => simulation.battleParticipations[id]).filter(Boolean),
        attackerParticipations: battle.battleParticipationIds
            .map(id => simulation.battleParticipations[id])
            .filter(participation => participation?.side === "attacker"),
        defenderParticipations: battle.battleParticipationIds
            .map(id => simulation.battleParticipations[id])
            .filter(participation => participation?.side === "defender"),
        injuries: simulation.injuries.filter(injury => injury.battleId === battle.id || casualtyIds.has(injury.personId)),
        memorials: simulation.memorials.filter(memorial => memorial.battleId === battle.id || casualtyIds.has(memorial.personId)),
        settlementControls: simulation.settlementControls.filter(control => control.battleId === battle.id),
        personAllegiances: simulation.personAllegiances.filter(allegiance => allegiance.battleId === battle.id),
        chronicles: simulation.chronicles.filter(chronicle => battleSubject(chronicle.subjectRefs) || chronicle.kind === "battle-account" && participantSubject(chronicle.subjectRefs)),
        writtenWorks: simulation.writtenWorks.filter(work => battleSubject(work.subjectRefs) || participantSubject(work.subjectRefs)),
        memories: simulation.memories.filter(memory => battleSubject(memory.subjectRefs) || participantSubject(memory.subjectRefs)),
        thoughts: simulation.thoughts.filter(thought => battleSubject(thought.subjectRefs) || participantSubject(thought.subjectRefs)),
        opinions: simulation.opinions.filter(opinion => battleSubject(opinion.subjectRefs) || participantSubject(opinion.subjectRefs)),
        conversations: simulation.conversations.filter(conversation => battleSubject(conversation.subjectRefs) || participantSubject(conversation.subjectRefs)),
        rumors: simulation.rumors.filter(rumor => battleSubject(rumor.subjectRefs) || participantSubject(rumor.subjectRefs)),
        secrets: simulation.secrets.filter(secret => battleSubject(secret.subjectRefs) || participantSubject(secret.subjectRefs)),
        obligations: simulation.obligations.filter(obligation => battleSubject(obligation.subjectRefs) || participantSubject(obligation.subjectRefs)),
    };
}

function buildBattleChapters(simulation: CivilizationSimulation, battle: Battle): BattleChapter[] {
    const chapters: BattleChapter[] = [];
    const related = battleRelatedRecords(simulation, battle);
    const attacker = simulation.civilizations[battle.attackerCivilizationId];
    const defender = simulation.civilizations[battle.defenderCivilizationId];
    const settlement = simulation.settlements[battle.settlementId];
    const attackerCommander = battle.attackerCommanderId === undefined ? undefined : simulation.agents[battle.attackerCommanderId];
    const defenderCommander = battle.defenderCommanderId === undefined ? undefined : simulation.agents[battle.defenderCommanderId];
    const notableCasualties = related.casualties
        .slice()
        .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
        .slice(0, 8);

    chapters.push(battleChapter(
        simulation,
        battle,
        "prelude",
        `${battle.name}'s prelude`,
        compactEventIds([...battle.eventIds, related.conflict?.startedEventId], 18),
        [
            ...(battle.conflictId === undefined ? [] : [conflictRef(simulation, battle.conflictId)]),
            settlementRef(simulation, battle.settlementId),
            civilizationRef(simulation, battle.attackerCivilizationId),
            civilizationRef(simulation, battle.defenderCivilizationId),
            ...related.militaryUnits.slice(0, 6).map(unit => militaryUnitRef(simulation, unit.id)),
            ...related.spyOperations.slice(0, 4).map(operation => spyOperationRef(simulation, operation.id)),
        ],
        `${battle.name} took place in year ${battle.year} at ${battle.battlefieldName} near ${settlement?.name ?? "an unknown place"} (${battlefieldTerrainLabel(battle.battlefieldTerrain)}, map ${battle.battlefieldX}, ${battle.battlefieldY}, triangle ${battle.battlefieldTriangle}) between ${attacker?.name ?? "an unknown attacker"} and ${defender?.name ?? "an unknown defender"}${related.conflict === undefined ? "" : ` as part of ${related.conflict.name}`}.`,
    ));

    if (attackerCommander || defenderCommander || related.participations.length) {
        chapters.push(battleChapter(
            simulation,
            battle,
            "commanders-sides",
            `${battle.name}'s commanders and sides`,
            eventIdsForRecords(related.participations, 18),
            [
                ...(attackerCommander === undefined ? [] : [personRef(simulation, attackerCommander.id)]),
                ...(defenderCommander === undefined ? [] : [personRef(simulation, defenderCommander.id)]),
                ...related.attackerParticipations.slice(0, 6).map(participation => battleParticipationRef(simulation, participation.id)),
                ...related.defenderParticipations.slice(0, 6).map(participation => battleParticipationRef(simulation, participation.id)),
                ...related.militaryUnits.slice(0, 8).map(unit => militaryUnitRef(simulation, unit.id)),
                ...related.equipmentCaches.slice(0, 6).map(cache => equipmentCacheRef(simulation, cache.id)),
            ],
            `${battle.name} records ${related.attackerParticipations.length} attacker role ${related.attackerParticipations.length === 1 ? "entry" : "entries"}, ${related.defenderParticipations.length} defender role ${related.defenderParticipations.length === 1 ? "entry" : "entries"}, ${related.militaryUnits.length} military unit ${related.militaryUnits.length === 1 ? "record" : "records"}, and ${related.equipmentCaches.length} equipment cache ${related.equipmentCaches.length === 1 ? "record" : "records"}${attackerCommander || defenderCommander ? `, led by ${attackerCommander?.name ?? "an unknown attacker commander"} and ${defenderCommander?.name ?? "an unknown defender commander"}` : ""}.`,
        ));
    }

    chapters.push(battleChapter(
        simulation,
        battle,
        "fighting-outcome",
        `${battle.name}'s fighting and outcome`,
        compactEventIds([
            ...battle.eventIds,
            ...eventIdsForRecords(related.participations, 18),
        ], 24),
        [
            ...related.participations.slice(-10).map(participation => battleParticipationRef(simulation, participation.id)),
            ...related.spyOperations.slice(-6).map(operation => spyOperationRef(simulation, operation.id)),
        ],
        `${battle.name} ended with a ${battle.outcome} outcome after involving ${related.participants.length} recorded participant ${related.participants.length === 1 ? "person" : "people"}, ${related.participations.length} battle role ${related.participations.length === 1 ? "record" : "records"}, attacker power ${battle.attackerPower}, defender power ${battle.defenderPower}, and intelligence advantage ${battle.intelligenceAdvantage.toFixed(2)}.`,
    ));

    if (related.casualties.length || related.injuries.length || related.memorials.length) {
        chapters.push(battleChapter(
            simulation,
            battle,
            "casualties-wounds",
            `${battle.name}'s casualties and wounds`,
            eventIdsForRecords([...related.participations, ...related.injuries, ...related.memorials], 24),
            [
                ...notableCasualties.map(agent => personRef(simulation, agent.id)),
                ...related.injuries.slice(-8).map(injury => injuryRef(simulation, injury.id)),
                ...related.memorials.slice(-8).map(memorial => memorialRef(simulation, memorial.id)),
            ],
            `${battle.name} left ${related.casualties.length} recorded casualty ${related.casualties.length === 1 ? "person" : "people"}, ${related.injuries.length} injury ${related.injuries.length === 1 ? "record" : "records"}, and ${related.memorials.length} memorial ${related.memorials.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.capturedArtifacts.length || related.settlementControls.length || related.personAllegiances.length) {
        chapters.push(battleChapter(
            simulation,
            battle,
            "spoils-control",
            `${battle.name}'s spoils and control`,
            compactEventIds([
                ...eventIdsForRecords([...related.settlementControls, ...related.personAllegiances], 22),
                ...related.capturedArtifacts.flatMap(artifact => artifact.eventIds),
            ], 24),
            [
                ...related.capturedArtifacts.slice(0, 8).map(artifact => artifactRef(simulation, artifact.id)),
                ...related.settlementControls.slice(-8).map(control => settlementControlRef(simulation, control.id)),
                ...related.personAllegiances.slice(-8).map(allegiance => personAllegianceRef(simulation, allegiance.id)),
            ],
            `${battle.name}'s aftermath included ${related.capturedArtifacts.length} captured artifact ${related.capturedArtifacts.length === 1 ? "record" : "records"}, ${related.settlementControls.length} settlement control change ${related.settlementControls.length === 1 ? "record" : "records"}, and ${related.personAllegiances.length} person allegiance change ${related.personAllegiances.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.chronicles.length || related.writtenWorks.length || related.memories.length || related.thoughts.length || related.opinions.length || related.conversations.length || related.rumors.length || related.secrets.length || related.obligations.length) {
        chapters.push(battleChapter(
            simulation,
            battle,
            "records-memory",
            `${battle.name}'s records and memory`,
            compactEventIds([
                ...eventIdsForRecords([...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.thoughts, ...related.opinions, ...related.conversations, ...related.rumors, ...related.secrets, ...related.obligations], 24),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.chronicles.slice(-6).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-6).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-6).map(opinion => opinionRef(simulation, opinion.id)),
                ...related.conversations.slice(-6).map(conversation => conversationRef(simulation, conversation.id)),
                ...related.rumors.slice(-6).map(rumor => rumorRef(simulation, rumor.id)),
                ...related.secrets.slice(-5).map(secret => secretRef(simulation, secret.id)),
                ...related.obligations.slice(-6).map(obligation => obligationRef(simulation, obligation.id)),
            ],
            `${battle.name} survives in ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}, ${related.opinions.length} opinion ${related.opinions.length === 1 ? "record" : "records"}, ${related.rumors.length} rumor ${related.rumors.length === 1 ? "record" : "records"}, and ${related.secrets.length} secret ${related.secrets.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<BattleChapterKind, number> = {
        prelude: 0,
        "commanders-sides": 1,
        "fighting-outcome": 2,
        "casualties-wounds": 3,
        "spoils-control": 4,
        "records-memory": 5,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 8);
}

function organizationChapter(
    simulation: CivilizationSimulation,
    organization: Organization,
    kind: OrganizationChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): OrganizationChapter {
    const chapterStartYear = Math.max(organization.foundedYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        organizationId: organization.id,
        civilizationId: organization.civilizationId,
        settlementId: organization.settlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            organizationRef(simulation, organization.id),
            civilizationRef(simulation, organization.civilizationId),
            settlementRef(simulation, organization.settlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function organizationRelatedRecords(simulation: CivilizationSimulation, organization: Organization) {
    const memberSet = new Set(organization.memberIds);
    const activityIds = uniqueNumberList([
        ...organization.activityIds,
        ...simulation.activities.filter(activity => activity.organizationId === organization.id).map(activity => activity.id),
    ]);
    return {
        memberships: organization.membershipIds.map(id => simulation.memberships[id]).filter(Boolean),
        members: organization.memberIds.map(id => simulation.agents[id]).filter(Boolean),
        activities: activityIds.map(id => simulation.activities[id]).filter(Boolean),
        careers: simulation.careers.filter(career => career.organizationId === organization.id),
        apprenticeships: simulation.apprenticeships.filter(apprenticeship => apprenticeship.organizationId === organization.id),
        teachings: simulation.teachings.filter(teaching => teaching.organizationId === organization.id),
        projects: simulation.projects.filter(project => project.organizationId === organization.id),
        traditions: simulation.traditions.filter(tradition => tradition.organizationId === organization.id),
        ceremonies: simulation.ceremonies.filter(ceremony => ceremony.organizationId === organization.id),
        ceremonyParticipations: simulation.ceremonyParticipations.filter(participation => participation.organizationId === organization.id),
        magicRoles: simulation.magicRoles.filter(role => role.organizationId === organization.id),
        holdings: simulation.holdings.filter(holding => holding.organizationId === organization.id),
        belongings: simulation.belongings.filter(belonging =>
            (belonging.ownerAgentId !== undefined && memberSet.has(belonging.ownerAgentId))
            || (belonging.structureId !== undefined && belonging.structureId === organization.structureId)
        ),
        artifacts: simulation.artifacts.filter(artifact =>
            artifact.structureId === organization.structureId
            || (artifact.ownerAgentId !== undefined && memberSet.has(artifact.ownerAgentId))
            || artifact.provenance.some(entry => entry.organizationId === organization.id)
        ),
        relationships: simulation.socialBonds.filter(bond => bond.organizationId === organization.id),
        chronicles: simulation.chronicles.filter(chronicle => chronicle.organizationId === organization.id || chronicle.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        writtenWorks: simulation.writtenWorks.filter(work => work.organizationId === organization.id || work.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        memories: simulation.memories.filter(memory => memory.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        thoughts: simulation.thoughts.filter(thought => thought.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        opinions: simulation.opinions.filter(opinion => opinion.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        conversations: simulation.conversations.filter(conversation => conversation.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        rumors: simulation.rumors.filter(rumor => rumor.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
        secrets: simulation.secrets.filter(secret => secret.subjectRefs.some(ref => ref.kind === "organization" && ref.id === organization.id)),
    };
}

function buildOrganizationChapters(simulation: CivilizationSimulation, organization: Organization): OrganizationChapter[] {
    const chapters: OrganizationChapter[] = [];
    const related = organizationRelatedRecords(simulation, organization);
    const founderMemberships = related.memberships.filter(membership => membership.role === "founder");
    const leaderMemberships = related.memberships.filter(membership => membership.role === "leader");
    const activeMemberships = related.memberships.filter(membership => membership.status === "active");
    const notableMembers = related.members
        .slice()
        .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
        .slice(0, 8);

    chapters.push(organizationChapter(
        simulation,
        organization,
        "founding",
        `${organization.name}'s founding`,
        organization.foundedYear,
        undefined,
        compactEventIds([
            ...organization.eventIds,
            ...eventIdsForRecords(founderMemberships, 10),
        ], 16),
        [
            ...(organization.leaderAgentId === undefined ? [] : [personRef(simulation, organization.leaderAgentId)]),
            ...founderMemberships.slice(0, 4).map(membership => membershipRef(simulation, membership.id)),
            ...(organization.structureId === undefined ? [] : [structureRef(simulation, organization.structureId)]),
            ...(organization.beliefId === undefined ? [] : [beliefRef(simulation, organization.beliefId)]),
        ],
        `${organization.name} was founded in ${simulation.settlements[organization.settlementId]?.name ?? "an unknown settlement"} as a ${organization.kind.replace("-", " ")}${organization.beliefId === undefined ? "" : " with a belief record"} and has ${related.memberships.length} membership ${related.memberships.length === 1 ? "entry" : "entries"}.`,
    ));

    if (related.memberships.length || related.relationships.length || notableMembers.length) {
        chapters.push(organizationChapter(
            simulation,
            organization,
            "leadership-membership",
            `${organization.name}'s leadership and members`,
            minDefined([
                ...related.memberships.map(membership => membership.startedYear),
                ...related.relationships.map(bond => bond.startedYear),
            ], organization.foundedYear),
            activeMemberships.length ? undefined : maxDefined(related.memberships.map(membership => membership.endedYear)),
            compactEventIds([
                ...eventIdsForRecords(related.memberships, 18),
                ...eventIdsForRecords(related.relationships, 12),
                ...notableMembers.flatMap(member => member.eventIds.slice(0, 3)),
            ], 20),
            [
                ...(organization.leaderAgentId === undefined ? [] : [personRef(simulation, organization.leaderAgentId)]),
                ...leaderMemberships.slice(-4).map(membership => membershipRef(simulation, membership.id)),
                ...related.memberships.slice(-8).map(membership => membershipRef(simulation, membership.id)),
                ...notableMembers.map(member => personRef(simulation, member.id)),
                ...related.relationships.slice(-4).map(bond => relationshipRef(simulation, bond.id)),
            ],
            `${organization.name}'s rolls list ${organization.memberIds.length} current member ${organization.memberIds.length === 1 ? "record" : "records"}, ${leaderMemberships.length} leadership ${leaderMemberships.length === 1 ? "term" : "terms"}, and ${related.relationships.length} internal relationship ${related.relationships.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.careers.length || related.apprenticeships.length || related.teachings.length || related.projects.length || related.activities.length) {
        chapters.push(organizationChapter(
            simulation,
            organization,
            "work-training",
            `${organization.name}'s work and training`,
            minDefined([
                ...related.careers.map(career => career.startYear),
                ...related.apprenticeships.map(apprenticeship => apprenticeship.startedYear),
                ...related.teachings.map(teaching => teaching.year),
                ...related.projects.map(project => project.year),
                ...related.activities.map(activity => activity.year),
            ], organization.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.careers, ...related.apprenticeships, ...related.teachings, ...related.projects, ...related.activities], 24),
            ], 24),
            [
                ...related.careers.slice(-6).map(career => careerRef(simulation, career.id)),
                ...related.apprenticeships.slice(-6).map(apprenticeship => apprenticeshipRef(simulation, apprenticeship.id)),
                ...related.teachings.slice(-6).map(teaching => teachingRef(simulation, teaching.id)),
                ...related.projects.slice(-6).map(project => projectRef(simulation, project.id)),
                ...related.activities.slice(-6).map(activity => activityRef(simulation, activity.id)),
            ],
            `${organization.name}'s practical record includes ${related.careers.length} career ${related.careers.length === 1 ? "link" : "links"}, ${related.apprenticeships.length} apprenticeship ${related.apprenticeships.length === 1 ? "record" : "records"}, ${related.teachings.length} teaching ${related.teachings.length === 1 ? "entry" : "entries"}, ${related.projects.length} project ${related.projects.length === 1 ? "entry" : "entries"}, and ${related.activities.length} activity ${related.activities.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (organization.beliefId !== undefined || related.traditions.length || related.ceremonies.length || related.ceremonyParticipations.length || related.magicRoles.length) {
        chapters.push(organizationChapter(
            simulation,
            organization,
            "rites-beliefs",
            `${organization.name}'s rites and beliefs`,
            minDefined([
                ...(organization.beliefId === undefined ? [] : [simulation.beliefs[organization.beliefId]?.foundedYear]),
                ...related.traditions.map(tradition => tradition.originYear),
                ...related.ceremonies.map(ceremony => ceremony.year),
                ...related.ceremonyParticipations.map(participation => participation.year),
                ...related.magicRoles.map(role => role.startedYear),
            ], organization.foundedYear),
            undefined,
            compactEventIds([
                ...(organization.beliefId === undefined ? [] : simulation.beliefs[organization.beliefId]?.eventIds ?? []),
                ...eventIdsForRecords([...related.traditions, ...related.ceremonies, ...related.ceremonyParticipations, ...related.magicRoles], 24),
            ], 24),
            [
                ...(organization.beliefId === undefined ? [] : [beliefRef(simulation, organization.beliefId)]),
                ...related.traditions.slice(0, 6).map(tradition => traditionRef(simulation, tradition.id)),
                ...related.ceremonies.slice(-6).map(ceremony => ceremonyRef(simulation, ceremony.id)),
                ...related.ceremonyParticipations.slice(-6).map(participation => ceremonyParticipationRef(simulation, participation.id)),
                ...related.magicRoles.slice(-6).map(role => magicRoleRef(simulation, role.id)),
            ],
            `${organization.name}'s ritual record includes ${related.traditions.length} tradition ${related.traditions.length === 1 ? "link" : "links"}, ${related.ceremonies.length} ceremony ${related.ceremonies.length === 1 ? "entry" : "entries"}, ${related.ceremonyParticipations.length} ceremony participation ${related.ceremonyParticipations.length === 1 ? "record" : "records"}, and ${related.magicRoles.length} magic role ${related.magicRoles.length === 1 ? "appointment" : "appointments"}.`,
        ));
    }

    if (organization.structureId !== undefined || related.holdings.length || related.belongings.length || related.artifacts.length || related.writtenWorks.length) {
        const renownedArtifacts = related.artifacts
            .slice()
            .sort((a, b) => b.renown - a.renown || a.createdYear - b.createdYear || a.id - b.id)
            .slice(0, 6);
        chapters.push(organizationChapter(
            simulation,
            organization,
            "assets-works",
            `${organization.name}'s assets and works`,
            minDefined([
                ...(organization.structureId === undefined ? [] : [simulation.structures[organization.structureId]?.builtYear]),
                ...related.holdings.map(holding => holding.foundedYear),
                ...related.belongings.map(belonging => belonging.acquiredYear),
                ...related.artifacts.map(artifact => artifact.createdYear),
                ...related.writtenWorks.map(work => work.year),
            ], organization.foundedYear),
            undefined,
            compactEventIds([
                ...(organization.structureId === undefined ? [] : simulation.structures[organization.structureId]?.eventIds ?? []),
                ...eventIdsForRecords([...related.holdings, ...related.belongings, ...related.artifacts, ...related.writtenWorks], 24),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...(organization.structureId === undefined ? [] : [structureRef(simulation, organization.structureId)]),
                ...related.holdings.slice(-6).map(holding => holdingRef(simulation, holding.id)),
                ...related.belongings.slice(-6).map(belonging => belongingRef(simulation, belonging.id)),
                ...renownedArtifacts.map(artifact => artifactRef(simulation, artifact.id)),
                ...related.writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
            ],
            `${organization.name}'s material record includes ${related.holdings.length} holding ${related.holdings.length === 1 ? "entry" : "entries"}, ${related.belongings.length} belonging ${related.belongings.length === 1 ? "entry" : "entries"}, ${related.artifacts.length} artifact ${related.artifacts.length === 1 ? "link" : "links"}, and ${related.writtenWorks.length} written ${related.writtenWorks.length === 1 ? "work" : "works"}.`,
        ));
    }

    if (related.chronicles.length || related.writtenWorks.length || related.memories.length || related.thoughts.length || related.opinions.length || related.conversations.length || related.rumors.length || related.secrets.length) {
        chapters.push(organizationChapter(
            simulation,
            organization,
            "records-legacy",
            `${organization.name}'s records and legacy`,
            minDefined([
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.thoughts.map(thought => thought.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.conversations.map(conversation => conversation.year),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
            ], organization.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.thoughts, ...related.opinions, ...related.conversations, ...related.rumors, ...related.secrets], 24),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.chronicles.slice(-6).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-6).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-6).map(opinion => opinionRef(simulation, opinion.id)),
                ...related.conversations.slice(-6).map(conversation => conversationRef(simulation, conversation.id)),
                ...related.rumors.slice(-6).map(rumor => rumorRef(simulation, rumor.id)),
                ...related.secrets.slice(-6).map(secret => secretRef(simulation, secret.id)),
            ],
            `${organization.name}'s legacy layer includes ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}, ${related.opinions.length} opinion ${related.opinions.length === 1 ? "record" : "records"}, ${related.rumors.length} rumor ${related.rumors.length === 1 ? "record" : "records"}, and ${related.secrets.length} secret ${related.secrets.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<OrganizationChapterKind, number> = {
        founding: 0,
        "leadership-membership": 1,
        "work-training": 2,
        "rites-beliefs": 3,
        "assets-works": 4,
        "records-legacy": 5,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 8);
}

function householdChapter(
    simulation: CivilizationSimulation,
    household: Household,
    kind: HouseholdChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): HouseholdChapter {
    const chapterStartYear = Math.max(household.foundedYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        householdId: household.id,
        civilizationId: household.civilizationId,
        settlementId: household.settlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            householdRef(simulation, household.id),
            civilizationRef(simulation, household.civilizationId),
            settlementRef(simulation, household.settlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function householdRelatedRecords(simulation: CivilizationSimulation, household: Household) {
    const memberSet = new Set(household.memberAgentIds);
    const residenceStructureId = household.residenceStructureId;
    const activityIds = uniqueNumberList([
        ...household.activityIds,
        ...simulation.activities.filter(activity => activity.householdId === household.id).map(activity => activity.id),
    ]);
    return {
        members: household.memberAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        founders: household.founderAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        lineages: household.lineageIds.map(id => simulation.lineages[id]).filter(Boolean),
        residences: simulation.residences.filter(residence => residence.householdId === household.id),
        careers: simulation.careers.filter(career => career.householdId === household.id),
        unions: simulation.unions.filter(union => union.householdId === household.id || union.partnerAgentIds.some(id => memberSet.has(id))),
        relationships: simulation.socialBonds.filter(bond => bond.agentIds.some(id => memberSet.has(id))),
        activities: activityIds.map(id => simulation.activities[id]).filter(Boolean),
        ceremonies: simulation.ceremonies.filter(ceremony => ceremony.hostAgentId !== undefined && memberSet.has(ceremony.hostAgentId) || ceremony.participantAgentIds.some(id => memberSet.has(id))),
        ceremonyParticipations: simulation.ceremonyParticipations.filter(participation => memberSet.has(participation.agentId)),
        obligations: simulation.obligations.filter(obligation =>
            memberSet.has(obligation.creditorAgentId)
            || memberSet.has(obligation.debtorAgentId)
            || obligation.witnessAgentIds.some(id => memberSet.has(id))
        ),
        holdings: simulation.holdings.filter(holding => holding.householdId === household.id || holding.ownerAgentId !== undefined && memberSet.has(holding.ownerAgentId)),
        belongings: simulation.belongings.filter(belonging =>
            belonging.householdId === household.id
            || belonging.ownerAgentId !== undefined && memberSet.has(belonging.ownerAgentId)
            || belonging.previousOwnerAgentId !== undefined && memberSet.has(belonging.previousOwnerAgentId)
            || residenceStructureId !== undefined && belonging.structureId === residenceStructureId
        ),
        artifacts: simulation.artifacts.filter(artifact =>
            memberSet.has(artifact.creatorAgentId)
            || artifact.ownerAgentId !== undefined && memberSet.has(artifact.ownerAgentId)
            || residenceStructureId !== undefined && artifact.structureId === residenceStructureId
        ),
        injuries: simulation.injuries.filter(injury => injury.householdId === household.id || memberSet.has(injury.personId)),
        illnesses: simulation.illnesses.filter(illness => illness.householdId === household.id || memberSet.has(illness.personId)),
        memorials: simulation.memorials.filter(memorial => memorial.householdId === household.id || memberSet.has(memorial.personId)),
        cases: simulation.cases.filter(legalCase =>
            memberSet.has(legalCase.accusedAgentId)
            || legalCase.victimAgentId !== undefined && memberSet.has(legalCase.victimAgentId)
            || legalCase.witnessAgentIds.some(id => memberSet.has(id))
        ),
        feuds: simulation.feuds.filter(feud => feud.householdIds.includes(household.id)),
        chronicles: simulation.chronicles.filter(chronicle => chronicle.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        writtenWorks: simulation.writtenWorks.filter(work => work.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        memories: simulation.memories.filter(memory => memory.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        thoughts: simulation.thoughts.filter(thought => thought.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        opinions: simulation.opinions.filter(opinion => opinion.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        conversations: simulation.conversations.filter(conversation => conversation.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        rumors: simulation.rumors.filter(rumor => rumor.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
        secrets: simulation.secrets.filter(secret => secret.subjectRefs.some(ref => ref.kind === "household" && ref.id === household.id)),
    };
}

function buildHouseholdChapters(simulation: CivilizationSimulation, household: Household): HouseholdChapter[] {
    const chapters: HouseholdChapter[] = [];
    const related = householdRelatedRecords(simulation, household);
    const notableMembers = related.members
        .slice()
        .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
        .slice(0, 8);
    const childIds = uniqueNumberList(related.unions.flatMap(union => union.childAgentIds)).filter(id => household.memberAgentIds.includes(id)).slice(0, 8);

    chapters.push(householdChapter(
        simulation,
        household,
        "founding-family",
        `${household.name}'s founding and family`,
        household.foundedYear,
        undefined,
        compactEventIds([
            ...household.eventIds,
            ...related.founders.flatMap(founder => founder.eventIds.slice(0, 3)),
        ], 18),
        [
            ...related.founders.slice(0, 4).map(founder => personRef(simulation, founder.id)),
            ...related.lineages.slice(0, 4).map(lineage => lineageRef(simulation, lineage.id)),
            ...(household.residenceStructureId === undefined ? [] : [structureRef(simulation, household.residenceStructureId)]),
        ],
        `${household.name} was founded in ${simulation.settlements[household.settlementId]?.name ?? "an unknown settlement"} by ${related.founders.length} recorded founder ${related.founders.length === 1 ? "person" : "people"} and is linked to ${related.lineages.length} lineage ${related.lineages.length === 1 ? "record" : "records"}.`,
    ));

    if (related.residences.length || related.members.length || household.residenceStructureId !== undefined) {
        const activeResidences = related.residences.filter(residence => residence.status === "active");
        chapters.push(householdChapter(
            simulation,
            household,
            "homes-members",
            `${household.name}'s homes and members`,
            minDefined([
                ...related.residences.map(residence => residence.startYear),
                ...related.members.map(member => member.bornYear),
                ...(household.residenceStructureId === undefined ? [] : [simulation.structures[household.residenceStructureId]?.builtYear]),
            ], household.foundedYear),
            activeResidences.length ? undefined : maxDefined(related.residences.map(residence => residence.endYear)),
            compactEventIds([
                ...eventIdsForRecords(related.residences, 18),
                ...notableMembers.flatMap(member => member.eventIds.slice(0, 3)),
            ], 20),
            [
                ...(household.residenceStructureId === undefined ? [] : [structureRef(simulation, household.residenceStructureId)]),
                ...related.residences.slice(-8).map(residence => residenceRef(simulation, residence.id)),
                ...notableMembers.map(member => personRef(simulation, member.id)),
            ],
            `${household.name}'s domestic record includes ${household.memberAgentIds.length} member ${household.memberAgentIds.length === 1 ? "entry" : "entries"} and ${related.residences.length} residence ${related.residences.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.careers.length || related.activities.length || related.ceremonies.length || related.ceremonyParticipations.length) {
        chapters.push(householdChapter(
            simulation,
            household,
            "work-daily-life",
            `${household.name}'s work and daily life`,
            minDefined([
                ...related.careers.map(career => career.startYear),
                ...related.activities.map(activity => activity.year),
                ...related.ceremonies.map(ceremony => ceremony.year),
                ...related.ceremonyParticipations.map(participation => participation.year),
            ], household.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.careers, ...related.activities, ...related.ceremonies, ...related.ceremonyParticipations], 22),
            ], 22),
            [
                ...related.careers.slice(-6).map(career => careerRef(simulation, career.id)),
                ...related.activities.slice(-6).map(activity => activityRef(simulation, activity.id)),
                ...related.ceremonies.slice(-5).map(ceremony => ceremonyRef(simulation, ceremony.id)),
                ...related.ceremonyParticipations.slice(-5).map(participation => ceremonyParticipationRef(simulation, participation.id)),
            ],
            `${household.name}'s ordinary life is recorded through ${related.careers.length} career ${related.careers.length === 1 ? "link" : "links"}, ${related.activities.length} activity ${related.activities.length === 1 ? "entry" : "entries"}, and ${related.ceremonies.length} ceremony ${related.ceremonies.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.unions.length || related.relationships.length || related.obligations.length || childIds.length) {
        chapters.push(householdChapter(
            simulation,
            household,
            "bonds-obligations",
            `${household.name}'s bonds and obligations`,
            minDefined([
                ...related.unions.map(union => union.startedYear),
                ...related.relationships.map(bond => bond.startedYear),
                ...related.obligations.map(obligation => obligation.createdYear),
                ...childIds.map(id => simulation.agents[id]?.bornYear),
            ], household.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.unions, ...related.relationships, ...related.obligations], 22),
                ...childIds.flatMap(id => simulation.agents[id]?.eventIds.slice(0, 2) ?? []),
            ], 22),
            [
                ...related.unions.slice(-6).map(union => unionRef(simulation, union.id)),
                ...related.relationships.slice(-6).map(bond => relationshipRef(simulation, bond.id)),
                ...related.obligations.slice(-6).map(obligation => obligationRef(simulation, obligation.id)),
                ...childIds.map(id => personRef(simulation, id)),
            ],
            `${household.name}'s social web includes ${related.unions.length} union ${related.unions.length === 1 ? "record" : "records"}, ${childIds.length} recorded ${childIds.length === 1 ? "child" : "children"}, ${related.relationships.length} relationship ${related.relationships.length === 1 ? "record" : "records"}, and ${related.obligations.length} obligation ${related.obligations.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.injuries.length || related.illnesses.length || related.memorials.length || related.cases.length || related.feuds.length) {
        chapters.push(householdChapter(
            simulation,
            household,
            "hardship-memory",
            `${household.name}'s hardships and memory`,
            minDefined([
                ...related.injuries.map(injury => injury.year),
                ...related.illnesses.map(illness => illness.onsetYear),
                ...related.memorials.map(memorial => memorial.year),
                ...related.cases.map(legalCase => legalCase.openedYear),
                ...related.feuds.map(feud => feud.startedYear),
            ], household.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.injuries, ...related.illnesses, ...related.memorials, ...related.cases, ...related.feuds], 22),
            ], 22),
            [
                ...related.injuries.slice(-5).map(injury => injuryRef(simulation, injury.id)),
                ...related.illnesses.slice(-5).map(illness => illnessRef(simulation, illness.id)),
                ...related.memorials.slice(-6).map(memorial => memorialRef(simulation, memorial.id)),
                ...related.cases.slice(-5).map(legalCase => caseRef(simulation, legalCase.id)),
                ...related.feuds.slice(-4).map(feud => feudRef(simulation, feud.id)),
            ],
            `${household.name}'s difficult record includes ${related.injuries.length} injur${related.injuries.length === 1 ? "y" : "ies"}, ${related.illnesses.length} illness ${related.illnesses.length === 1 ? "case" : "cases"}, ${related.memorials.length} memorial ${related.memorials.length === 1 ? "entry" : "entries"}, ${related.cases.length} legal case ${related.cases.length === 1 ? "record" : "records"}, and ${related.feuds.length} feud ${related.feuds.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.holdings.length || related.belongings.length || related.artifacts.length || related.chronicles.length || related.writtenWorks.length || related.memories.length || related.opinions.length || related.rumors.length || related.secrets.length) {
        const renownedArtifacts = related.artifacts
            .slice()
            .sort((a, b) => b.renown - a.renown || a.createdYear - b.createdYear || a.id - b.id)
            .slice(0, 6);
        chapters.push(householdChapter(
            simulation,
            household,
            "assets-legacy",
            `${household.name}'s assets and legacy`,
            minDefined([
                ...related.holdings.map(holding => holding.foundedYear),
                ...related.belongings.map(belonging => belonging.acquiredYear),
                ...related.artifacts.map(artifact => artifact.createdYear),
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
            ], household.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.holdings, ...related.belongings, ...related.artifacts, ...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.opinions, ...related.rumors, ...related.secrets], 22),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.holdings.slice(-6).map(holding => holdingRef(simulation, holding.id)),
                ...related.belongings.slice(-6).map(belonging => belongingRef(simulation, belonging.id)),
                ...renownedArtifacts.map(artifact => artifactRef(simulation, artifact.id)),
                ...related.chronicles.slice(-5).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-5).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-5).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-5).map(opinion => opinionRef(simulation, opinion.id)),
            ],
            `${household.name}'s legacy includes ${related.holdings.length} holding ${related.holdings.length === 1 ? "entry" : "entries"}, ${related.belongings.length} belonging ${related.belongings.length === 1 ? "entry" : "entries"}, ${related.artifacts.length} artifact ${related.artifacts.length === 1 ? "link" : "links"}, ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, and ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<HouseholdChapterKind, number> = {
        "founding-family": 0,
        "homes-members": 1,
        "work-daily-life": 2,
        "bonds-obligations": 3,
        "hardship-memory": 4,
        "assets-legacy": 5,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 8);
}

function lineageChapter(
    simulation: CivilizationSimulation,
    lineage: Lineage,
    kind: LineageChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): LineageChapter {
    const chapterStartYear = Math.max(lineage.foundedYear, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        lineageId: lineage.id,
        civilizationId: lineage.civilizationId,
        settlementId: lineage.originSettlementId,
        sourceEventIds: compactEventIds(sourceEventIds, 18),
        subjectRefs: uniqueLegendRefs([
            lineageRef(simulation, lineage.id),
            civilizationRef(simulation, lineage.civilizationId),
            settlementRef(simulation, lineage.originSettlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 30),
        description,
    };
}

function lineageRelatedRecords(simulation: CivilizationSimulation, lineage: Lineage) {
    const memberSet = new Set(lineage.memberAgentIds);
    const householdSet = new Set(lineage.householdIds);
    return {
        members: lineage.memberAgentIds.map(id => simulation.agents[id]).filter(Boolean),
        households: lineage.householdIds.map(id => simulation.households[id]).filter(Boolean),
        residences: simulation.residences.filter(residence => memberSet.has(residence.personId) || residence.householdId !== undefined && householdSet.has(residence.householdId)),
        unions: simulation.unions.filter(union => union.lineageIds.includes(lineage.id) || union.partnerAgentIds.some(id => memberSet.has(id)) || union.childAgentIds.some(id => memberSet.has(id))),
        careers: simulation.careers.filter(career => memberSet.has(career.personId)),
        apprenticeships: simulation.apprenticeships.filter(apprenticeship => apprenticeship.lineageId === lineage.id || memberSet.has(apprenticeship.mentorAgentId) || memberSet.has(apprenticeship.apprenticeAgentId)),
        skills: simulation.skills.filter(skill => memberSet.has(skill.agentId) || skill.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        projects: simulation.projects.filter(project => memberSet.has(project.leadAgentId) || project.workerAgentIds.some(id => memberSet.has(id)) || project.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        offices: simulation.offices.filter(office => office.holderAgentId !== undefined && memberSet.has(office.holderAgentId)),
        officeTerms: simulation.officeTerms.filter(term => memberSet.has(term.holderAgentId)),
        laws: simulation.laws.filter(law => law.authorAgentId !== undefined && memberSet.has(law.authorAgentId)),
        cases: simulation.cases.filter(legalCase =>
            memberSet.has(legalCase.accusedAgentId)
            || legalCase.victimAgentId !== undefined && memberSet.has(legalCase.victimAgentId)
            || legalCase.witnessAgentIds.some(id => memberSet.has(id))
        ),
        battleParticipations: simulation.battleParticipations.filter(participation => memberSet.has(participation.agentId)),
        injuries: simulation.injuries.filter(injury => memberSet.has(injury.personId)),
        illnesses: simulation.illnesses.filter(illness => memberSet.has(illness.personId)),
        memorials: simulation.memorials.filter(memorial => memberSet.has(memorial.personId)),
        feuds: simulation.feuds.filter(feud => feud.lineageIds.includes(lineage.id)),
        holdings: simulation.holdings.filter(holding => holding.householdId !== undefined && householdSet.has(holding.householdId) || holding.ownerAgentId !== undefined && memberSet.has(holding.ownerAgentId)),
        belongings: simulation.belongings.filter(belonging =>
            belonging.householdId !== undefined && householdSet.has(belonging.householdId)
            || belonging.ownerAgentId !== undefined && memberSet.has(belonging.ownerAgentId)
            || belonging.previousOwnerAgentId !== undefined && memberSet.has(belonging.previousOwnerAgentId)
        ),
        artifacts: simulation.artifacts.filter(artifact => memberSet.has(artifact.creatorAgentId) || artifact.ownerAgentId !== undefined && memberSet.has(artifact.ownerAgentId)),
        chronicles: simulation.chronicles.filter(chronicle => chronicle.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        writtenWorks: simulation.writtenWorks.filter(work => work.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        memories: simulation.memories.filter(memory => memory.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        thoughts: simulation.thoughts.filter(thought => thought.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        opinions: simulation.opinions.filter(opinion => opinion.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        conversations: simulation.conversations.filter(conversation => conversation.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        rumors: simulation.rumors.filter(rumor => rumor.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
        secrets: simulation.secrets.filter(secret => secret.subjectRefs.some(ref => ref.kind === "lineage" && ref.id === lineage.id)),
    };
}

function buildLineageChapters(simulation: CivilizationSimulation, lineage: Lineage): LineageChapter[] {
    const chapters: LineageChapter[] = [];
    const related = lineageRelatedRecords(simulation, lineage);
    const founder = simulation.agents[lineage.founderAgentId];
    const notableMembers = related.members
        .slice()
        .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
        .slice(0, 8);

    chapters.push(lineageChapter(
        simulation,
        lineage,
        "founding-ancestors",
        `${lineage.name}'s founding ancestors`,
        lineage.foundedYear,
        undefined,
        compactEventIds([
            ...lineage.eventIds,
            ...(founder?.eventIds.slice(0, 4) ?? []),
        ], 18),
        [
            personRef(simulation, lineage.founderAgentId),
            ...related.households.slice(0, 4).map(household => householdRef(simulation, household.id)),
        ],
        `${lineage.name} began in ${simulation.settlements[lineage.originSettlementId]?.name ?? "an unknown settlement"} with ${founder?.name ?? "an unknown founder"} as the recorded founder and ${related.households.length} household ${related.households.length === 1 ? "branch" : "branches"}.`,
    ));

    if (related.households.length || related.unions.length || related.residences.length) {
        chapters.push(lineageChapter(
            simulation,
            lineage,
            "households-branches",
            `${lineage.name}'s households and branches`,
            minDefined([
                ...related.households.map(household => household.foundedYear),
                ...related.unions.map(union => union.startedYear),
                ...related.residences.map(residence => residence.startYear),
            ], lineage.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.households, ...related.unions, ...related.residences], 22),
            ], 22),
            [
                ...related.households.slice(0, 10).map(household => householdRef(simulation, household.id)),
                ...related.unions.slice(-6).map(union => unionRef(simulation, union.id)),
                ...related.residences.slice(-6).map(residence => residenceRef(simulation, residence.id)),
            ],
            `${lineage.name}'s family branches include ${related.households.length} household ${related.households.length === 1 ? "record" : "records"}, ${related.unions.length} union ${related.unions.length === 1 ? "record" : "records"}, and ${related.residences.length} residence ${related.residences.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (related.members.length || related.offices.length || related.officeTerms.length || related.memorials.length) {
        chapters.push(lineageChapter(
            simulation,
            lineage,
            "members-standing",
            `${lineage.name}'s members and standing`,
            minDefined([
                ...related.members.map(member => member.bornYear),
                ...related.offices.map(office => office.createdYear),
                ...related.officeTerms.map(term => term.startedYear),
                ...related.memorials.map(memorial => memorial.year),
            ], lineage.foundedYear),
            undefined,
            compactEventIds([
                ...notableMembers.flatMap(member => member.eventIds.slice(0, 3)),
                ...eventIdsForRecords([...related.offices, ...related.officeTerms, ...related.memorials], 20),
            ], 22),
            [
                ...notableMembers.map(member => personRef(simulation, member.id)),
                ...related.offices.slice(-5).map(office => officeRef(simulation, office.id)),
                ...related.officeTerms.slice(-6).map(term => officeTermRef(simulation, term.id)),
                ...related.memorials.slice(-6).map(memorial => memorialRef(simulation, memorial.id)),
            ],
            `${lineage.name}'s standing is carried by ${related.members.length} member ${related.members.length === 1 ? "entry" : "entries"}, ${related.offices.length} office ${related.offices.length === 1 ? "seat" : "seats"}, ${related.officeTerms.length} office ${related.officeTerms.length === 1 ? "term" : "terms"}, and ${related.memorials.length} memorial ${related.memorials.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.careers.length || related.apprenticeships.length || related.skills.length || related.projects.length || related.laws.length) {
        chapters.push(lineageChapter(
            simulation,
            lineage,
            "work-training",
            `${lineage.name}'s work and training`,
            minDefined([
                ...related.careers.map(career => career.startYear),
                ...related.apprenticeships.map(apprenticeship => apprenticeship.startedYear),
                ...related.skills.map(skill => skill.startedYear),
                ...related.projects.map(project => project.year),
                ...related.laws.map(law => law.enactedYear),
            ], lineage.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.careers, ...related.apprenticeships, ...related.skills, ...related.projects, ...related.laws], 24),
                ...related.skills.flatMap(skill => skill.sourceEventIds),
            ], 24),
            [
                ...related.careers.slice(-6).map(career => careerRef(simulation, career.id)),
                ...related.apprenticeships.slice(-6).map(apprenticeship => apprenticeshipRef(simulation, apprenticeship.id)),
                ...related.skills.slice(-6).map(skill => skillRef(simulation, skill.id)),
                ...related.projects.slice(-6).map(project => projectRef(simulation, project.id)),
                ...related.laws.slice(-4).map(law => lawRef(simulation, law.id)),
            ],
            `${lineage.name}'s practical inheritance includes ${related.careers.length} career ${related.careers.length === 1 ? "link" : "links"}, ${related.apprenticeships.length} apprenticeship ${related.apprenticeships.length === 1 ? "record" : "records"}, ${related.skills.length} skill ${related.skills.length === 1 ? "record" : "records"}, ${related.projects.length} project ${related.projects.length === 1 ? "entry" : "entries"}, and ${related.laws.length} authored law ${related.laws.length === 1 ? "entry" : "entries"}.`,
        ));
    }

    if (related.feuds.length || related.cases.length || related.battleParticipations.length || related.injuries.length || related.illnesses.length) {
        chapters.push(lineageChapter(
            simulation,
            lineage,
            "conflict-hardship",
            `${lineage.name}'s conflicts and hardships`,
            minDefined([
                ...related.feuds.map(feud => feud.startedYear),
                ...related.cases.map(legalCase => legalCase.openedYear),
                ...related.battleParticipations.map(participation => participation.year),
                ...related.injuries.map(injury => injury.year),
                ...related.illnesses.map(illness => illness.onsetYear),
            ], lineage.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.feuds, ...related.cases, ...related.battleParticipations, ...related.injuries, ...related.illnesses], 24),
            ], 24),
            [
                ...related.feuds.slice(-5).map(feud => feudRef(simulation, feud.id)),
                ...related.cases.slice(-5).map(legalCase => caseRef(simulation, legalCase.id)),
                ...related.battleParticipations.slice(-6).map(participation => battleParticipationRef(simulation, participation.id)),
                ...related.injuries.slice(-5).map(injury => injuryRef(simulation, injury.id)),
                ...related.illnesses.slice(-5).map(illness => illnessRef(simulation, illness.id)),
            ],
            `${lineage.name}'s hardship record includes ${related.feuds.length} feud ${related.feuds.length === 1 ? "record" : "records"}, ${related.cases.length} legal case ${related.cases.length === 1 ? "record" : "records"}, ${related.battleParticipations.length} battle role ${related.battleParticipations.length === 1 ? "record" : "records"}, ${related.injuries.length} injur${related.injuries.length === 1 ? "y" : "ies"}, and ${related.illnesses.length} illness ${related.illnesses.length === 1 ? "case" : "cases"}.`,
        ));
    }

    if (related.holdings.length || related.belongings.length || related.artifacts.length || related.chronicles.length || related.writtenWorks.length || related.memories.length || related.opinions.length || related.rumors.length || related.secrets.length) {
        const renownedArtifacts = related.artifacts
            .slice()
            .sort((a, b) => b.renown - a.renown || a.createdYear - b.createdYear || a.id - b.id)
            .slice(0, 6);
        chapters.push(lineageChapter(
            simulation,
            lineage,
            "records-legacy",
            `${lineage.name}'s records and legacy`,
            minDefined([
                ...related.holdings.map(holding => holding.foundedYear),
                ...related.belongings.map(belonging => belonging.acquiredYear),
                ...related.artifacts.map(artifact => artifact.createdYear),
                ...related.chronicles.map(chronicle => chronicle.year),
                ...related.writtenWorks.map(work => work.year),
                ...related.memories.map(memory => memory.year),
                ...related.opinions.map(opinion => opinion.year),
                ...related.rumors.map(rumor => rumor.year),
                ...related.secrets.map(secret => secret.year),
            ], lineage.foundedYear),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...related.holdings, ...related.belongings, ...related.artifacts, ...related.chronicles, ...related.writtenWorks, ...related.memories, ...related.opinions, ...related.rumors, ...related.secrets], 24),
                ...related.chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...related.writtenWorks.flatMap(work => work.sourceEventIds),
            ], 24),
            [
                ...related.holdings.slice(-6).map(holding => holdingRef(simulation, holding.id)),
                ...related.belongings.slice(-6).map(belonging => belongingRef(simulation, belonging.id)),
                ...renownedArtifacts.map(artifact => artifactRef(simulation, artifact.id)),
                ...related.chronicles.slice(-6).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...related.writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
                ...related.memories.slice(-6).map(memory => memoryRef(simulation, memory.id)),
                ...related.opinions.slice(-6).map(opinion => opinionRef(simulation, opinion.id)),
            ],
            `${lineage.name}'s remembered legacy includes ${related.holdings.length} holding ${related.holdings.length === 1 ? "entry" : "entries"}, ${related.artifacts.length} artifact ${related.artifacts.length === 1 ? "link" : "links"}, ${related.chronicles.length} chronicle ${related.chronicles.length === 1 ? "entry" : "entries"}, ${related.writtenWorks.length} written ${related.writtenWorks.length === 1 ? "work" : "works"}, and ${related.memories.length} memory ${related.memories.length === 1 ? "record" : "records"}.`,
        ));
    }

    const chapterOrder: Record<LineageChapterKind, number> = {
        "founding-ancestors": 0,
        "households-branches": 1,
        "members-standing": 2,
        "work-training": 3,
        "conflict-hardship": 4,
        "records-legacy": 5,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 8);
}

function civilizationChapter(
    simulation: CivilizationSimulation,
    civilization: Civilization,
    kind: CivilizationChapterKind,
    title: string,
    startYear: number,
    endYear: number | undefined,
    sourceEventIds: number[],
    subjectRefs: LegendEntityRef[],
    description: string,
): CivilizationChapter {
    const chapterStartYear = Math.max(0, startYear);
    const chapterEndYear = endYear === undefined ? undefined : Math.max(chapterStartYear, endYear);
    return {
        kind,
        title,
        startYear: chapterStartYear,
        endYear: chapterEndYear,
        status: chapterEndYear === undefined ? "active" : "ended",
        civilizationId: civilization.id,
        sourceEventIds: compactEventIds(sourceEventIds, 20),
        subjectRefs: uniqueLegendRefs([
            civilizationRef(simulation, civilization.id),
            settlementRef(simulation, civilization.capitalSettlementId),
            ...subjectRefs,
            ...compactEventIds(sourceEventIds, 8).map(id => eventRef(simulation, id)),
        ], 32),
        description,
    };
}

function buildCivilizationChapters(simulation: CivilizationSimulation, civilization: Civilization): CivilizationChapter[] {
    const chapters: CivilizationChapter[] = [];
    const settlements = simulation.settlements.filter(settlement => settlement.civilizationId === civilization.id);
    const controls = simulation.settlementControls.filter(control => control.civilizationId === civilization.id || control.previousCivilizationId === civilization.id);
    const people = simulation.agents.filter(agent => agent.civilizationId === civilization.id);
    const households = simulation.households.filter(household => household.civilizationId === civilization.id);
    const lineages = simulation.lineages.filter(lineage => lineage.civilizationId === civilization.id);
    const structures = simulation.structures.filter(structure => structure.civilizationId === civilization.id);
    const roads = simulation.roads.filter(road => road.civilizationId === civilization.id);
    const journeys = simulation.journeys.filter(journey => journey.civilizationId === civilization.id);
    const beliefs = simulation.beliefs.filter(belief => belief.civilizationId === civilization.id);
    const myths = civilization.mythIds.map(id => simulation.myths[id]).filter(Boolean);
    const doctrines = civilization.doctrineIds.map(id => simulation.doctrines[id]).filter(Boolean);
    const magicRoles = civilization.magicRoleIds.map(id => simulation.magicRoles[id]).filter(Boolean);
    const prophecies = civilization.prophecyIds.map(id => simulation.prophecies[id]).filter(Boolean);
    const goals = civilization.civilizationGoalIds.map(id => simulation.civilizationGoals[id]).filter(Boolean);
    const sacredSites = simulation.sacredSites.filter(site => site.civilizationId === civilization.id);
    const offices = simulation.offices.filter(office => office.civilizationId === civilization.id);
    const officeTerms = simulation.officeTerms.filter(term => term.civilizationId === civilization.id);
    const laws = simulation.laws.filter(law => law.civilizationId === civilization.id);
    const cases = simulation.cases.filter(legalCase => legalCase.civilizationId === civilization.id);
    const conflicts = simulation.conflicts.filter(conflict =>
        conflict.attackerCivilizationId === civilization.id
        || conflict.defenderCivilizationId === civilization.id
        || conflict.instigatorCivilizationId === civilization.id
    );
    const battles = simulation.battles.filter(battle => battle.attackerCivilizationId === civilization.id || battle.defenderCivilizationId === civilization.id);
    const artifacts = simulation.artifacts.filter(artifact => artifact.civilizationId === civilization.id || artifact.provenance.some(entry => entry.civilizationId === civilization.id || entry.previousCivilizationId === civilization.id));
    const chronicles = simulation.chronicles.filter(chronicle => chronicle.civilizationId === civilization.id || chronicle.subjectRefs.some(ref => ref.kind === "civilization" && ref.id === civilization.id));
    const writtenWorks = simulation.writtenWorks.filter(work => work.civilizationId === civilization.id || work.subjectRefs.some(ref => ref.kind === "civilization" && ref.id === civilization.id));
    const projects = simulation.projects.filter(project => project.civilizationId === civilization.id);
    const ceremonies = simulation.ceremonies.filter(ceremony => ceremony.civilizationId === civilization.id);

    chapters.push(civilizationChapter(
        simulation,
        civilization,
        "founding-expansion",
        `${civilization.name}'s founding and expansion`,
        minDefined([...settlements.map(settlement => settlement.foundedYear), ...controls.map(control => control.startedYear)], 0),
        undefined,
        compactEventIds([
            ...civilization.eventIds,
            ...settlements.flatMap(settlement => settlement.eventIds),
            ...eventIdsForRecords(controls, 16),
        ], 24),
        [
            ...settlements.slice(0, 10).map(settlement => settlementRef(simulation, settlement.id)),
            ...controls.slice(0, 6).map(control => settlementControlRef(simulation, control.id)),
        ],
        `${civilization.name} began from ${simulation.settlements[civilization.capitalSettlementId]?.name ?? "an unknown capital"} and now records ${settlements.length} settlement ${settlements.length === 1 ? "holding" : "holdings"} with ${controls.length} control ${controls.length === 1 ? "term" : "terms"}.`,
    ));

    if (offices.length || officeTerms.length || laws.length || cases.length) {
        chapters.push(civilizationChapter(
            simulation,
            civilization,
            "rule-law",
            `${civilization.name}'s rule and law`,
            minDefined([
                ...offices.map(office => office.createdYear),
                ...officeTerms.map(term => term.startedYear),
                ...laws.map(law => law.enactedYear),
                ...cases.map(legalCase => legalCase.openedYear),
            ], minDefined(settlements.map(settlement => settlement.foundedYear), 0)),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...offices, ...officeTerms, ...laws, ...cases], 20),
            ], 24),
            [
                ...offices.slice(0, 8).map(office => officeRef(simulation, office.id)),
                ...officeTerms.slice(-6).map(term => officeTermRef(simulation, term.id)),
                ...laws.slice(-6).map(law => lawRef(simulation, law.id)),
                ...cases.slice(-6).map(legalCase => caseRef(simulation, legalCase.id)),
            ],
            `${civilization.name}'s political record contains ${offices.length} office ${offices.length === 1 ? "seat" : "seats"}, ${officeTerms.length} office ${officeTerms.length === 1 ? "term" : "terms"}, ${laws.length} law ${laws.length === 1 ? "entry" : "entries"}, and ${cases.length} legal case ${cases.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (beliefs.length || myths.length || doctrines.length || magicRoles.length || prophecies.length || goals.length || sacredSites.length) {
        const activeGoals = goals.filter(goal => goal.status === "active");
        const openProphecies = prophecies.filter(prophecy => prophecy.status === "open");
        chapters.push(civilizationChapter(
            simulation,
            civilization,
            "beliefs-goals",
            `${civilization.name}'s beliefs, magic, and aims`,
            minDefined([
                ...beliefs.map(belief => belief.foundedYear),
                ...myths.map(myth => myth.year),
                ...doctrines.map(doctrine => doctrine.foundedYear),
                ...magicRoles.map(role => role.startedYear),
                ...prophecies.map(prophecy => prophecy.year),
                ...goals.map(goal => goal.startedYear),
                ...sacredSites.map(site => site.foundedYear),
            ], minDefined(settlements.map(settlement => settlement.foundedYear), 0)),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...beliefs, ...myths, ...doctrines, ...magicRoles, ...prophecies, ...goals, ...sacredSites], 24),
            ], 24),
            [
                ...beliefs.slice(0, 6).map(belief => beliefRef(simulation, belief.id)),
                ...myths.slice(0, 6).map(myth => mythRef(simulation, myth.id)),
                ...doctrines.slice(0, 6).map(doctrine => doctrineRef(simulation, doctrine.id)),
                ...magicRoles.slice(-6).map(role => magicRoleRef(simulation, role.id)),
                ...prophecies.slice(-6).map(prophecy => prophecyRef(simulation, prophecy.id)),
                ...goals.slice(-6).map(goal => civilizationGoalRef(simulation, goal.id)),
                ...sacredSites.slice(0, 6).map(site => sacredSiteRef(simulation, site.id)),
            ],
            `${civilization.name}'s culture links ${beliefs.length} belief ${beliefs.length === 1 ? "root" : "roots"}, ${myths.length} myth ${myths.length === 1 ? "cycle" : "cycles"}, ${magicRoles.length} magic role ${magicRoles.length === 1 ? "appointment" : "appointments"}, ${openProphecies.length} open ${openProphecies.length === 1 ? "prophecy" : "prophecies"}, and ${activeGoals.length} active kingdom ${activeGoals.length === 1 ? "goal" : "goals"}.`,
        ));
    }

    if (conflicts.length || battles.length) {
        const activeConflicts = conflicts.filter(conflict => conflict.status === "active" || conflict.status === "dormant");
        chapters.push(civilizationChapter(
            simulation,
            civilization,
            "war-captures",
            `${civilization.name}'s wars and captures`,
            minDefined([
                ...conflicts.map(conflict => conflict.startedYear),
                ...battles.map(battle => battle.year),
            ], minDefined(settlements.map(settlement => settlement.foundedYear), 0)),
            activeConflicts.length ? undefined : maxDefined([
                ...conflicts.map(conflict => conflict.endedYear),
                ...battles.map(battle => battle.year),
            ]),
            compactEventIds([
                ...eventIdsForRecords(conflicts, 16),
                ...eventIdsForRecords(battles, 18),
            ], 24),
            [
                ...conflicts.slice(-6).map(conflict => conflictRef(simulation, conflict.id)),
                ...battles.slice(-8).map(battle => battleRef(simulation, battle.id)),
            ],
            `${civilization.name}'s military record names ${conflicts.length} conflict ${conflicts.length === 1 ? "arc" : "arcs"}, ${battles.length} battle ${battles.length === 1 ? "entry" : "entries"}, ${activeConflicts.length} unresolved ${activeConflicts.length === 1 ? "conflict" : "conflicts"}, and ${conflicts.reduce((sum, conflict) => sum + conflict.capturedSettlementIds.length, 0)} captured settlement ${conflicts.reduce((sum, conflict) => sum + conflict.capturedSettlementIds.length, 0) === 1 ? "record" : "records"}.`,
        ));
    }

    if (roads.length || journeys.length) {
        chapters.push(civilizationChapter(
            simulation,
            civilization,
            "roads-journeys",
            `${civilization.name}'s roads and journeys`,
            minDefined([
                ...roads.map(road => road.openedYear),
                ...journeys.map(journey => journey.year),
            ], minDefined(settlements.map(settlement => settlement.foundedYear), 0)),
            undefined,
            compactEventIds([
                ...eventIdsForRecords(journeys, 20),
            ], 24),
            [
                ...roads.slice(0, 10).map(road => roadRef(simulation, road.id)),
                ...journeys.slice(-8).map(journey => journeyRef(simulation, journey.id)),
            ],
            `${civilization.name}'s movement record includes ${roads.length} internal road ${roads.length === 1 ? "link" : "links"} and ${journeys.length} journey ${journeys.length === 1 ? "entry" : "entries"} across migration, trade, pilgrimage, delegation, and expedition traffic.`,
        ));
    }

    if (people.length || households.length || lineages.length) {
        const notablePeople = people
            .slice()
            .sort((a, b) => b.reputation - a.reputation || b.age - a.age || a.id - b.id)
            .slice(0, 10);
        chapters.push(civilizationChapter(
            simulation,
            civilization,
            "people-families",
            `${civilization.name}'s people and families`,
            minDefined([
                ...people.map(agent => agent.bornYear),
                ...households.map(household => household.foundedYear),
                ...lineages.map(lineage => lineage.foundedYear),
            ], minDefined(settlements.map(settlement => settlement.foundedYear), 0)),
            undefined,
            compactEventIds([
                ...notablePeople.flatMap(agent => agent.eventIds.slice(0, 4)),
                ...eventIdsForRecords([...households, ...lineages], 18),
            ], 24),
            [
                ...notablePeople.map(agent => personRef(simulation, agent.id)),
                ...households.slice(0, 8).map(household => householdRef(simulation, household.id)),
                ...lineages.slice(0, 8).map(lineage => lineageRef(simulation, lineage.id)),
            ],
            `${civilization.name}'s social archive contains ${people.filter(agent => agent.alive).length} living people, ${households.length} household ${households.length === 1 ? "record" : "records"}, and ${lineages.length} lineage ${lineages.length === 1 ? "record" : "records"}.`,
        ));
    }

    if (structures.length || projects.length || artifacts.length || chronicles.length || writtenWorks.length || ceremonies.length) {
        const renownedArtifacts = artifacts
            .slice()
            .sort((a, b) => b.renown - a.renown || a.createdYear - b.createdYear || a.id - b.id)
            .slice(0, 8);
        chapters.push(civilizationChapter(
            simulation,
            civilization,
            "works-records",
            `${civilization.name}'s works and records`,
            minDefined([
                ...structures.map(structure => structure.builtYear),
                ...projects.map(project => project.year),
                ...artifacts.map(artifact => artifact.createdYear),
                ...chronicles.map(chronicle => chronicle.year),
                ...writtenWorks.map(work => work.year),
                ...ceremonies.map(ceremony => ceremony.year),
            ], minDefined(settlements.map(settlement => settlement.foundedYear), 0)),
            undefined,
            compactEventIds([
                ...eventIdsForRecords([...structures, ...projects, ...artifacts, ...ceremonies], 20),
                ...chronicles.flatMap(chronicle => chronicle.sourceEventIds),
                ...writtenWorks.flatMap(work => work.sourceEventIds),
                ...eventIdsForRecords([...chronicles, ...writtenWorks], 12),
            ], 24),
            [
                ...structures.slice(0, 8).map(structure => structureRef(simulation, structure.id)),
                ...projects.slice(-6).map(project => projectRef(simulation, project.id)),
                ...renownedArtifacts.map(artifact => artifactRef(simulation, artifact.id)),
                ...chronicles.slice(-6).map(chronicle => chronicleRef(simulation, chronicle.id)),
                ...writtenWorks.slice(-6).map(work => writtenWorkRef(simulation, work.id)),
                ...ceremonies.slice(-6).map(ceremony => ceremonyRef(simulation, ceremony.id)),
            ],
            `${civilization.name}'s material and written legacy includes ${structures.length} structure ${structures.length === 1 ? "record" : "records"}, ${projects.length} project ${projects.length === 1 ? "entry" : "entries"}, ${artifacts.length} artifact ${artifacts.length === 1 ? "link" : "links"}, ${chronicles.length} chronicle ${chronicles.length === 1 ? "entry" : "entries"}, and ${writtenWorks.length} written ${writtenWorks.length === 1 ? "work" : "works"}.`,
        ));
    }

    const recentEvents = civilization.eventIds
        .map(id => simulation.legendEvents[id])
        .filter(Boolean)
        .sort((a, b) => b.year - a.year || b.id - a.id)
        .slice(0, 8);
    chapters.push(civilizationChapter(
        simulation,
        civilization,
        "current-legacy",
        `${civilization.name}'s present legacy`,
        simulation.year,
        undefined,
        recentEvents.map(event => event.id),
        [
            ...goals.filter(goal => goal.status === "active").slice(0, 6).map(goal => civilizationGoalRef(simulation, goal.id)),
            ...prophecies.filter(prophecy => prophecy.status === "open").slice(0, 4).map(prophecy => prophecyRef(simulation, prophecy.id)),
            ...settlements
                .slice()
                .sort((a, b) => b.population - a.population || a.id - b.id)
                .slice(0, 6)
                .map(settlement => settlementRef(simulation, settlement.id)),
            ...recentEvents.map(event => eventRef(simulation, event.id)),
        ],
        `By year ${simulation.year}, ${civilization.name} records ${civilization.population} people across ${settlements.length} settlement ${settlements.length === 1 ? "holding" : "holdings"}, with ${goals.filter(goal => goal.status === "active").length} active kingdom ${goals.filter(goal => goal.status === "active").length === 1 ? "goal" : "goals"} and ${prophecies.filter(prophecy => prophecy.status === "open").length} open ${prophecies.filter(prophecy => prophecy.status === "open").length === 1 ? "prophecy" : "prophecies"}.`,
    ));

    const chapterOrder: Record<CivilizationChapterKind, number> = {
        "founding-expansion": 0,
        "rule-law": 1,
        "beliefs-goals": 2,
        "war-captures": 3,
        "roads-journeys": 4,
        "people-families": 5,
        "works-records": 6,
        "current-legacy": 7,
    };
    return chapters
        .sort((a, b) => a.startYear - b.startYear || chapterOrder[a.kind] - chapterOrder[b.kind])
        .slice(0, 10);
}

function buildExportEventIdIndex(simulation: CivilizationSimulation): ExportEventIdIndex {
    const index: ExportEventIdIndex = {};
    for (let event of simulation.legendEvents) {
        for (let [field, kind] of exportLegendEventFieldKinds) {
            const value = event[field];
            if (typeof value === "number") addExportEventId(index, kind, value, event.id);
        }
        for (let ref of eventEntityRefsForExport(simulation, event)) {
            addExportEventId(index, ref.kind, ref.id, event.id);
        }
    }
    return index;
}

function exportEventIds(index: ExportEventIdIndex, kind: LegendEntityRef["kind"], id: number, fallback: number[]): number[] {
    return [...(index[kind]?.get(id) ?? fallback)];
}

function roadTimelineEventIds(index: ExportEventIdIndex, simulation: CivilizationSimulation, road: Road): number[] {
    const ids: number[] = [];
    for (let journey of simulation.journeys) {
        if (!roadMatchesJourney(road, journey)) continue;
        ids.push(...exportEventIds(index, "journey", journey.id, journey.eventIds));
    }
    return uniqueNumberList(ids);
}

function mythicRecordsForCivilization(simulation: CivilizationSimulation, civilization: Civilization): MythsAndMagicRecord {
    const beliefs = simulation.beliefs.filter(belief => belief.civilizationId === civilization.id);
    const gods = civilization.godIds.map(id => simulation.gods[id]).filter((god): god is God => !!god);
    const commandments = civilization.commandmentIds.map(id => simulation.commandments[id]).filter((commandment): commandment is Commandment => !!commandment);
    const destinies = civilization.destinyIds.map(id => simulation.destinies[id]).filter((destiny): destiny is Destiny => !!destiny);
    const miracles = civilization.miracleIds.map(id => simulation.miracles[id]).filter((miracle): miracle is Miracle => !!miracle);
    const myths = civilization.mythIds.map(id => simulation.myths[id]).filter((myth): myth is Myth => !!myth);
    const doctrines = civilization.doctrineIds.map(id => simulation.doctrines[id]).filter((doctrine): doctrine is Doctrine => !!doctrine);
    const magicRoles = civilization.magicRoleIds.map(id => simulation.magicRoles[id]).filter((role): role is MagicRole => !!role);
    const prophecies = civilization.prophecyIds.map(id => simulation.prophecies[id]).filter((prophecy): prophecy is Prophecy => !!prophecy);
    const goals = civilization.civilizationGoalIds.map(id => simulation.civilizationGoals[id]).filter((goal): goal is CivilizationGoal => !!goal);
    const sacredSites = simulation.sacredSites.filter(site => site.civilizationId === civilization.id);
    const capital = simulation.settlements[civilization.capitalSettlementId];
    const openProphecies = prophecies.filter(prophecy => prophecy.status === "open");
    const activeGoals = goals.filter(goal => goal.status === "active");
    const activeDestinies = destinies.filter(destiny => destiny.status === "active");
    const activeRoles = magicRoles.filter(role => role.status === "active");
    const domains = uniqueNumberList(beliefs.map(belief => BELIEF_DOMAINS.indexOf(belief.domain)).filter(index => index >= 0))
        .map(index => BELIEF_DOMAINS[index]);
    const eventIds = eventIdsForRecords([...beliefs, ...gods, ...commandments, ...destinies, ...miracles, ...myths, ...doctrines, ...magicRoles, ...prophecies, ...goals, ...sacredSites], 64);
    const subjectRefs = uniqueLegendRefs([
        civilizationRef(simulation, civilization.id),
        ...(capital ? [settlementRef(simulation, capital.id)] : []),
        ...beliefs.slice(0, 8).map(belief => beliefRef(simulation, belief.id)),
        ...gods.slice(0, 8).map(god => godRef(simulation, god.id)),
        ...commandments.slice(0, 6).map(commandment => commandmentRef(simulation, commandment.id)),
        ...activeDestinies.slice(0, 6).map(destiny => destinyRef(simulation, destiny.id)),
        ...miracles.slice(-6).map(miracle => miracleRef(simulation, miracle.id)),
        ...myths.slice(0, 8).map(myth => mythRef(simulation, myth.id)),
        ...doctrines.slice(0, 8).map(doctrine => doctrineRef(simulation, doctrine.id)),
        ...activeRoles.slice(0, 8).map(role => magicRoleRef(simulation, role.id)),
        ...openProphecies.slice(0, 8).map(prophecy => prophecyRef(simulation, prophecy.id)),
        ...activeGoals.slice(0, 8).map(goal => civilizationGoalRef(simulation, goal.id)),
        ...sacredSites.slice(0, 8).map(site => sacredSiteRef(simulation, site.id)),
        ...activeRoles.slice(0, 6).map(role => personRef(simulation, role.agentId)),
        ...eventIds.slice(0, 8).map(id => eventRef(simulation, id)),
    ], 48);
    const domainText = domains.length ? ` Its religious domains emphasize ${domains.map(beliefDomainLabel).join(", ")}.` : "";
    return {
        id: civilization.id,
        name: `${civilization.name} Myths & Magic`,
        civilizationId: civilization.id,
        capitalSettlementId: civilization.capitalSettlementId,
        beliefIds: beliefs.map(belief => belief.id),
        godIds: gods.map(god => god.id),
        commandmentIds: commandments.map(commandment => commandment.id),
        destinyIds: destinies.map(destiny => destiny.id),
        activeDestinyIds: activeDestinies.map(destiny => destiny.id),
        miracleIds: miracles.map(miracle => miracle.id),
        mythIds: myths.map(myth => myth.id),
        doctrineIds: doctrines.map(doctrine => doctrine.id),
        magicRoleIds: magicRoles.map(role => role.id),
        magicRoleHolderIds: uniqueNumberList(magicRoles.map(role => role.agentId)),
        prophecyIds: prophecies.map(prophecy => prophecy.id),
        openProphecyIds: openProphecies.map(prophecy => prophecy.id),
        civilizationGoalIds: goals.map(goal => goal.id),
        activeCivilizationGoalIds: activeGoals.map(goal => goal.id),
        sacredSiteIds: sacredSites.map(site => site.id),
        sourceEventIds: eventIds.slice(0, 36),
        subjectRefs,
        description: `${civilization.name}'s Myths & Magic layer ties ${beliefs.length} belief ${beliefs.length === 1 ? "root" : "roots"} to ${gods.length} god ${gods.length === 1 ? "power" : "powers"}, ${commandments.length} commandment ${commandments.length === 1 ? "rule" : "rules"}, ${activeDestinies.length} active ${activeDestinies.length === 1 ? "destiny" : "destinies"}, ${miracles.length} miracle ${miracles.length === 1 ? "witness" : "witnesses"}, ${myths.length} myth ${myths.length === 1 ? "cycle" : "cycles"}, ${magicRoles.length} magic role ${magicRoles.length === 1 ? "appointment" : "appointments"}, ${openProphecies.length} open ${openProphecies.length === 1 ? "prophecy" : "prophecies"}, ${activeGoals.length} active kingdom ${activeGoals.length === 1 ? "goal" : "goals"}, and ${sacredSites.length} sacred ${sacredSites.length === 1 ? "place" : "places"}.${domainText}`,
        eventIds,
    };
}

function buildMythsAndMagicRecords(simulation: CivilizationSimulation): MythsAndMagicRecord[] {
    return simulation.civilizations.map(civilization => mythicRecordsForCivilization(simulation, civilization));
}

function exportStoryHook(hook: StoryHook): LegendsStoryHookExport {
    return {
        id: hook.id,
        name: hook.name,
        kind: hook.kind,
        tone: hook.tone,
        year: hook.year,
        score: hook.score,
        rawScore: hook.rawScore,
        urgency: hook.urgency,
        civilizationId: hook.civilizationId,
        settlementId: hook.settlementId,
        personId: hook.personId,
        artifactId: hook.artifactId,
        battleId: hook.battleId,
        conflictId: hook.conflictId,
        beliefId: hook.beliefId,
        godId: hook.godId,
        prophecyId: hook.prophecyId,
        relationshipId: hook.relationshipId,
        secretId: hook.secretId,
        feudId: hook.feudId,
        oathId: hook.oathId,
        eventId: hook.eventId,
        seedRefs: hook.seedRefs.map(ref => ({...ref})),
        // subjectRefs intentionally mirrors seedRefs: the viewer's subject lists and
        // the mentions/backlink indexer only read subjectRefs, while the story tools
        // read seedRefs. Keep both populated.
        subjectRefs: hook.seedRefs.map(ref => ({...ref})),
        prompt: hook.prompt,
        stakes: hook.stakes,
        complication: hook.complication,
        suggestedFocus: hook.suggestedFocus,
        description: `${hook.prompt} ${hook.stakes} ${hook.complication}`,
        eventIds: hook.eventIds,
    };
}

